library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;
--use axi_mcdma_v1_2_2.axi_msg_afifo_autord.all;

-------------------------------------------------------------------------------
entity  axi_msg_bmg_ctrl is
    generic (
       C_START_ADDR            : integer := 0;
       C_DEPTH                 : integer := 10;
       C_FIELD                 : integer := 5
    );
      
    port (
       m_axi_msg_aclk : in std_logic;
       sinit         : in std_logic;
       data_in       : in std_logic;
       wren          : out std_logic;
       rden          : in std_logic;
       bmg_empty         : out std_logic;
       bmg_full          : out std_logic;
       bmg_pause         : out std_logic;
       desc_avail        : out std_logic;
       data_valid        : out std_logic;
       wraddr           : out std_logic_vector (8 downto 0);
       rdaddr           : out std_logic_vector (8 downto 0)
 --      dcount         : out std_logic_vector (FETCH_QUEUE_CNT_WIDTH-1 downto 0)
     );
  
end axi_msg_bmg_ctrl;

 
architecture implementation of axi_msg_bmg_ctrl is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";


constant START_ADDR_POINT  : std_logic_vector(8 downto 0) := std_logic_vector(to_unsigned(C_START_ADDR,9));
constant END_ADDR_POINT  : std_logic_vector(8 downto 0) := std_logic_vector(to_unsigned(C_START_ADDR+C_DEPTH-1,9));

constant MAX_LIMIT : std_logic_vector(4 downto 0) := std_logic_vector(to_unsigned(C_DEPTH,5));
constant MAX_MINUS_ONE : std_logic_vector(4 downto 0) := std_logic_vector(to_unsigned(C_DEPTH-C_FIELD,5));
constant ONE_LIMIT : std_logic_vector(4 downto 0) := std_logic_vector(to_unsigned(C_FIELD,5));
constant ZERO_LIMIT : std_logic_vector(4 downto 0) := std_logic_vector(to_unsigned(0,5));

signal bmg_count : std_logic_vector (4 downto 0);
signal wrbram : std_logic_vector (0 downto 0);

signal wraddr_int : std_logic_vector (8 downto 0);
signal rdaddr_int : std_logic_vector (8 downto 0);

signal valid, valid1 : std_logic;
signal count_shift : std_logic_vector (C_DEPTH downto 0);

signal tmp_full, tmp_empty, tmp_pause, tmp_avail : std_logic;

----------------------------------------------------------------------------
-- Bitwise OR of a std_logic_vector.
----------------------------------------------------------------------------
function or_reduce(slv : std_logic_vector) return std_logic is
    variable r : std_logic := '0';
begin
    for i in slv'range loop
        r := r or slv(i);
    end loop;
    return r;
end or_reduce;


begin

wrbram(0) <= data_in;
wren <= data_in;

wraddr <= wraddr_int;
rdaddr <= rdaddr_int;

process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (sinit = '1') then
           wraddr_int<= START_ADDR_POINT;
        elsif (wrbram(0) = '1' and wraddr_int= END_ADDR_POINT) then
           wraddr_int<= START_ADDR_POINT;
        elsif (wrbram(0) = '1') then
           wraddr_int<= std_logic_vector(unsigned(wraddr_int(8 downto 0)) +1);
        end if;
     end if;
end process;

process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (sinit = '1') then
           valid1 <= '0';
        else
           valid1 <= valid;
        end if;
     end if;
end process;

data_valid <= valid1;

process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (sinit = '1') then
           rdaddr_int<= START_ADDR_POINT;
           valid <= '0';
        elsif (rden = '1' and rdaddr_int= END_ADDR_POINT) then
           rdaddr_int<= START_ADDR_POINT;
           valid <= '1';
        elsif (rden = '1') then
           rdaddr_int<= std_logic_vector(unsigned(rdaddr_int(8 downto 0)) +1);
           valid <= '1';
        else
           valid <= '0';
        end if;
     end if;
end process;

bmg_full <= '1' when (bmg_count = MAX_LIMIT) else '0';
bmg_empty <= '1' when (bmg_count = ZERO_LIMIT) else '0';
bmg_pause <= '1' when (bmg_count > MAX_MINUS_ONE and bmg_count <= MAX_LIMIT) else '0';
desc_avail <= '1' when (bmg_count >= ONE_LIMIT) else '0';


process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (sinit = '1') then
           bmg_count <= (others => '0');
        elsif (wrbram(0) = '1' and rden = '1') then
           bmg_count <= bmg_count;
        elsif (wrbram(0) = '1') then
           bmg_count <= std_logic_vector(unsigned(bmg_count(4 downto 0)) + 1);
        elsif (rden = '1') then
           bmg_count <= std_logic_vector(unsigned(bmg_count(4 downto 0)) - 1);
        end if;
     end if;
end process;


--process (m_axi_msg_aclk)
--begin
--     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
--        if (sinit = '1') then
--           count_shift (0) <= '1';
--           count_shift (C_DEPTH downto 1) <= (others => '0');
--        elsif (wrbram(0) = '1' and rden = '1') then
--           count_shift <= count_shift;
--        elsif (wrbram(0) = '1') then
--           count_shift (0) <= '0';
--           count_shift (C_DEPTH downto 1) <= count_shift (C_DEPTH-1 downto 0);
--        elsif (rden = '1') then
--           count_shift (C_DEPTH) <= count_shift(0);
--           count_shift (C_DEPTH-1 downto 0) <= count_shift (C_DEPTH downto 1);
--        end if;
--     end if;
--end process;

-- bmg_full <= count_shift (C_DEPTH);
-- bmg_empty <= count_shift (0);
-- bmg_pause <= or_reduce (count_shift (C_DEPTH downto ((C_DEPTH/2)+1)));
-- desc_avail <= or_reduce (count_shift (C_DEPTH downto C_DEPTH/2));



end implementation;


