--   );
end generate USE_BMG;
 
USE_XPM : if C_USE_XPM = 1 generate
begin
 
xpm_memory_sdpram_inst : xpm_memory_sdpram
  generic map (

  -- Common module generics
    MEMORY_SIZE        => 16896,        --positive integer
    MEMORY_PRIMITIVE   => "block",      --string; "auto", "distributed", "block" or "ultra" ;
    CLOCKING_MODE      => "common_clock",--string; "common_clock", "independent_clock" 
    MEMORY_INIT_FILE   => "none",      --string; "none" or "<filename>.mem" 
    MEMORY_INIT_PARAM  => "",          --string;
    USE_MEM_INIT       => 1,           --integer; 0,1
    WAKEUP_TIME        => "disable_sleep",--string; "disable_sleep" or "use_sleep_pin" 
    MESSAGE_CONTROL    => 0,           --integer; 0,1
    ECC_MODE           => "no_ecc",    --string; "no_ecc", "encode_only", "decode_only" or "both_encode_and_decode" 
    AUTO_SLEEP_TIME    => 0,           --Do not Change

  -- Port A module generics
    WRITE_DATA_WIDTH_A => 33,          --positive integer
    BYTE_WRITE_WIDTH_A => 33,          --integer; 8, 9, or WRITE_DATA_WIDTH_A value
    ADDR_WIDTH_A       => 9,           --positive integer

  -- Port B module generics
    READ_DATA_WIDTH_B  => 33,          --positive integer
    ADDR_WIDTH_B       => 9,           --positive integer
    READ_RESET_VALUE_B => "0",         --string
    READ_LATENCY_B     => 2,           --non-negative integer
    WRITE_MODE_B       => "no_change"  --string; "write_first", "read_first", "no_change" 
  )
  port map (

  -- Common module ports
    sleep          => '0',

  -- Port A module ports
    clka           => clka,
    ena            => '1', --ena,
    wea            => wea,
    addra          => addra,
    dina           => dina,
    injectsbiterra => '0',
    injectdbiterra => '0',

  -- Port B module ports
    clkb           => clkb,
    rstb           => '0',
    enb            => enb,
    regceb         => regceb,
    addrb          => addrb,
    doutb          => doutb,
    sbiterrb       => open,
    dbiterrb       => open
  );



end generate USE_XPM;

END blk_mem_gen_0_arch;



