-------------------------------------------------------------------------------
-- Filename:          axi_msg_ftch_sm.vhd
-- Description: This entity manages fetching of descriptors.
--
-- VHDL-Standard:   VHDL'93
-------------------------------------------------------------------------------
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library unisim;
use unisim.vcomponents.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;

-------------------------------------------------------------------------------
entity  axi_msg_ftch_sm is
    generic (
        C_M_AXI_SG_ADDR_WIDTH       : integer range 32 to 64    := 32;
            -- Master AXI Memory Map Address Width for Scatter Gather R/W Port
        C_ENABLE_MULTI_CHANNEL             : integer range 0 to 1      := 0;
        C_NUM_S2MM_CHANNELS                : integer range 1 to 16 := 1;
        C_NUM_MM2S_CHANNELS                : integer range 1 to 16 := 1;
        C_MAX_CHANNELS                     : integer range 1 to 16 := 8;

        C_INCLUDE_CH1               : integer range 0 to 1      := 1;
            -- Include or Exclude channel 1 scatter gather engine
            -- 0 = Exclude Channel 1 SG Engine
            -- 1 = Include Channel 1 SG Engine

        C_INCLUDE_CH2               : integer range 0 to 1       := 1;
            -- Include or Exclude channel 2 scatter gather engine
            -- 0 = Exclude Channel 2 SG Engine
            -- 1 = Include Channel 2 SG Engine

        C_SG_CH1_WORDS_TO_FETCH     : integer range 4 to 16      := 8;
            -- Number of words to fetch

        C_SG_CH2_WORDS_TO_FETCH     : integer range 4 to 16      := 8;
            -- Number of words to fetch

        C_SG_FTCH_DESC2QUEUE     : integer range 0 to 8          := 0;
            -- Number of descriptors to fetch and queue for each channel.
            -- A value of zero excludes the fetch queues.


        C_SG_CH1_ENBL_STALE_ERROR   : integer range 0 to 1      := 1;
            -- Enable or disable stale descriptor check
            -- 0 = Disable stale descriptor error check
            -- 1 = Enable stale descriptor error check

        C_SG_CH2_ENBL_STALE_ERROR   : integer range 0 to 1      := 1;
            -- Enable or disable stale descriptor check
            -- 0 = Disable stale descriptor error check
            -- 1 = Enable stale descriptor error check
        C_ENABLE_MULTI_CH_RESET     : integer range 0 to 1      := 0

    );
    port (
        -----------------------------------------------------------------------
        -- AXI Scatter Gather Interface
        -----------------------------------------------------------------------
        m_axi_msg_aclk               : in  std_logic                         ;                   --
        m_axi_msg_aresetn            : in  std_logic                         ;                   --
        soft_rst_mm2s                : in std_logic                          ;
        soft_rst_s2mm                : in std_logic                          ;   
                                                                                                --
        updt_error                  : in  std_logic                         ;                   --
        ch_ftch_active_error        : out std_logic_vector (C_MAX_CHANNELS-1 downto 0);

        -- S2MM Channel 1 Control and Status                                                         --
        ch_mm2s_run_stop                : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_desc_flush              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_updt_done               : in  std_logic                         ;                   --
        ch_mm2s_sg_idle                 : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_tailpntr_enabled        : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_queue_full         : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_queue_empty        : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_pause              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_fetch_address           : in std_logic_vector                                       --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                   --
        ch_mm2s_ftch_active             : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_idle               : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --

        mm2s_ftch_interr_set         : out std_logic                         ;                   --
        mm2s_ftch_slverr_set         : out std_logic                         ;                   --
        mm2s_ftch_decerr_set         : out std_logic                         ;                   --
        mm2s_ftch_err_early          : out std_logic                         ;                   --
        mm2s_ftch_stale_desc         : out std_logic                         ;                   --
        mm2s_ftch_active             : out std_logic                         ;
        mm2s_channel_ftch            : out std_logic_vector (C_MAX_CHANNELS-1 downto 0);
        mm2s_updt_done               : in std_logic                          ;


                                                                                                --
        -- S2MM Channel 1 Control and Status                                                         --
        ch_s2mm_run_stop                : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_desc_flush              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_updt_done               : in  std_logic                         ;                   --
        ch_s2mm_sg_idle                 : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_tailpntr_enabled        : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_queue_full         : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_queue_empty        : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_pause              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_fetch_address           : in std_logic_vector                                       --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                   --
        ch_s2mm_ftch_active             : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_idle               : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --

        s2mm_ftch_interr_set         : out std_logic                         ;                   --
        s2mm_ftch_slverr_set         : out std_logic                         ;                   --
        s2mm_ftch_decerr_set         : out std_logic                         ;                   --
        s2mm_ftch_err_early          : out std_logic                         ;                   --
        s2mm_ftch_stale_desc         : out std_logic                         ;                   --
        s2mm_ftch_active             : out std_logic                         ;
        s2mm_channel_ftch            : out std_logic_vector (C_MAX_CHANNELS-1 downto 0);
        s2mm_updt_done               : in std_logic                          ;
                                                                                                --
        -- DataMover Command                                                                    --
        ftch_cmnd_wr                : out std_logic                         ;                   --
        ftch_cmnd_data              : out std_logic_vector                                      --
                                        ((C_M_AXI_SG_ADDR_WIDTH+MSG_CMD_BASE_WIDTH)-1 downto 0);    --
        -- DataMover Status                                                                     --
        ftch_done                   : in  std_logic                         ;                   --
        ftch_error                  : in  std_logic                         ;                   --
        ftch_interr                 : in  std_logic                         ;                   --
        ftch_slverr                 : in  std_logic                         ;                   --
        ftch_decerr                 : in  std_logic                         ;                   --
        ftch_stale_desc             : in  std_logic                         ;                   --
        ftch_error_early            : in  std_logic                         ;                   --
        ftch_error_addr             : out std_logic_vector                                      --
                                        (C_M_AXI_SG_ADDR_WIDTH-1 downto 0)                      --


    );

end axi_msg_ftch_sm;

