--signal ch1_desc_ftched_count    : std_logic_vector
--                                    (SG_FTCH_DESC2QUEUE_WIDTH-1 downto 0) := (others => '0');
--signal ch2_desc_ftched_count    : std_logic_vector
--                                    (SG_FTCH_DESC2QUEUE_WIDTH-1 downto 0) := (others => '0');

function r16(sl : std_logic) return std_logic_vector is
    variable slv : std_logic_vector(0 to 15) := (others => sl);
begin
    return slv;
end r16;
----------------------------------------------------------------------------
-- Bitwise OR of a std_logic_vector.
----------------------------------------------------------------------------
function or_reduce(slv : std_logic_vector) return std_logic is
    variable r : std_logic := '0';
begin
    for i in slv'range loop
        r := r or slv(i);
    end loop;
    return r;
end or_reduce;


function func_ret_int (slv : std_logic_vector (15 downto 0)) return integer is

 Variable number : Integer range 0 to 16 := 0;

begin

  case slv is
     when "0000000000000001" =>
        number := 0;
     when "0000000000000010" =>
        number := 1;
     when "0000000000000100" =>
        number := 2;
     when "0000000000001000" =>
        number := 3;
     when "0000000000010000" =>
        number := 4;
     when "0000000000100000" =>
        number := 5;
     when "0000000001000000" =>
        number := 6;
     when "0000000010000000" =>
        number := 7;
     when "0000000100000000" =>
        number := 8;
     when "0000001000000000" =>
        number := 9;
     when "0000010000000000" =>
        number := 10;
     when "0000100000000000" =>
        number := 11;
     when "0001000000000000" =>
        number := 12;
     when "0010000000000000" =>
        number := 13;
     when "0100000000000000" =>
        number := 14;
     when "1000000000000000" =>
        number := 15;
     when others =>
        number := 0;

  end case;

  Return (number);

end function func_ret_int;


