s2mm_active_tmp <= r16(s2mm_active);
s2mm_active_all <= s2mm_active_tmp (C_MAX_CHANNELS-1 downto 0);


mm2s_active_tmp <= r16(mm2s_active);
mm2s_active_all <= mm2s_active_tmp (C_MAX_CHANNELS-1 downto 0);

any_s2mm_update <= s2mm_updt_done;
any_mm2s_update <= mm2s_updt_done; 

--any_s2mm_update <= ch1_s2mm_updt_done or ch2_s2mm_updt_done or ch3_s2mm_updt_done or 
--                   ch4_s2mm_updt_done or ch5_s2mm_updt_done or ch6_s2mm_updt_done or 
--                   ch7_s2mm_updt_done or ch8_s2mm_updt_done;

--any_mm2s_update <= ch1_mm2s_updt_done or ch2_mm2s_updt_done or ch3_mm2s_updt_done or 
--                   ch4_mm2s_updt_done or ch5_mm2s_updt_done or ch6_mm2s_updt_done or 
