-------------------------------------------------------------------------------
-- Scatter Gather Fetch State Machine
-- it first serves MM2S, will fetch one BD
-- then switches to S2MM, will fetch one BD and then to MM2S..
-- at the Init time, it will take time for all channels to fetch BDs and fill the queue
-- subsequently (normally) there will be only one channel active
-------------------------------------------------------------------------------A


SG_FTCH_PATH : process (ftch_what_cs,
                        service_any_mm2s,
                        service_any_s2mm,
                        ftch_error,
                        mm2s_done,
                        s2mm_done,
			soft_rst_mm2s)
     begin

                     ftch_what_ns <= ftch_what_cs;
                     s2mm_active_i <= '0';
                     mm2s_active_i <= '0';
                       shift_mm2s <= '0';
                     shift_s2mm <= '0';

         case ftch_what_cs is

             when IDLE =>
                 if (ftch_error = '1') then
                     ftch_what_ns <= IDLE;
                 elsif (service_any_mm2s = '1') then
                     ftch_what_ns <=  FTCH_MM2S;
                     mm2s_active_i <= '1';
                 elsif (service_any_s2mm = '1') then
                     ftch_what_ns <= FTCH_S2MM;
                     s2mm_active_i <= '1';
                 else
                     ftch_what_ns <= IDLE;
                     shift_mm2s <= '1';
                     shift_s2mm <= '1';
                 end if;

              when FTCH_MM2S =>
                 if (ftch_error = '1') then
                     ftch_what_ns <= IDLE;
                 elsif (mm2s_done = '1') then
                        shift_mm2s <= '1';  -- move the token
                     if (service_any_s2mm = '1') then
                        ftch_what_ns <= FTCH_S2MM;
                        s2mm_active_i <= '1';
                     else
                        ftch_what_ns <= IDLE;
                     end if;
                 elsif (service_any_s2mm = '0') then
                        shift_s2mm <= '1';  -- move the token till some ch is servicable
                        mm2s_active_i <= '1';
                 else
                        mm2s_active_i <= '1';
                 end if;
              when FTCH_S2MM =>
                 if (ftch_error = '1') then
                     ftch_what_ns <= IDLE;
                 elsif (s2mm_done = '1') then
                        shift_s2mm <= '1'; -- move the token
                     if (service_any_mm2s = '1') then
                        ftch_what_ns <= FTCH_MM2S;
                        mm2s_active_i <= '1';
                     else
                        ftch_what_ns <= IDLE;
                     end if;
                 elsif (service_any_mm2s = '0') then
                        shift_mm2s <= '1'; -- move the token till some ch is servicable
                        s2mm_active_i <= '1';
                 else
                        s2mm_active_i <= '1';
                 end if;
-- coverage off
              when others =>
                     ftch_what_ns <= IDLE;
-- coverage on
         end case;

end process SG_FTCH_PATH;

REGISTER_FTCH_WHAT_STATE : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                ftch_what_cs     <= IDLE;
            else
                ftch_what_cs     <= ftch_what_ns;
            end if;
        end if;
    end process REGISTER_FTCH_WHAT_STATE;

-- mm2s_active and s2mm_active can never be '1' at the same time


REGISTER_MM2S_ACTIVE : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0') then -- or s2mm_active_i = '1')then
                mm2s_active <= '0';
            elsif (C_INCLUDE_CH1 = 1) then  --if (mm2s_active_i = '1') then
                mm2s_active <= mm2s_active_i; --'1';
            else
                mm2s_active <= '0';
            end if;
        end if;
    end process REGISTER_MM2S_ACTIVE;

REGISTER_S2MM_ACTIVE : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0') then -- or mm2s_active_i = '1')then
                s2mm_active <= '0';
            elsif (C_INCLUDE_CH2 = 1) then --e --if (s2mm_active_i = '1') then
                s2mm_active <= s2mm_active_i; --'1';
            else
                s2mm_active <= '0';
            end if;
        end if;
    end process REGISTER_S2MM_ACTIVE;


ch_token <= s2mm_ch_token when (s2mm_active = '1') else mm2s_ch_token;

-------------------------------------------------------------------------------
-- Scatter Gather Fetch State Machine
-------------------------------------------------------------------------------
SG_FTCH_MACHINE : process(ftch_cs,
                            mm2s_active,
                            s2mm_active,
                            ch_active_i,
                            s2mm_active_all,
                            mm2s_active_all,
                    --        service_ch,
--                            service_ch1, -- mux of mm2s and s2mm
--                            service_ch2,
--                            service_ch3,
--                            service_ch4,
--                            service_ch5,
--                            service_ch6,
--                            service_ch7,
--                            service_ch8,
--                            ch_token, 
                            service_ch_s2mm,
                            service_ch_mm2s,
                            ftch_error,
                            ftch_done, soft_rst_mm2s)

    begin
        -- Default signal assignment
        ch_active_set          <= (others => '0');
        active <= '0';
--        ch1_active_set          <= '0';
--        ch2_active_set          <= '0';
--        ch3_active_set          <= '0';
--        ch4_active_set          <= '0';
--        ch5_active_set          <= '0';
--        ch6_active_set          <= '0';
--        ch7_active_set          <= '0';
--        ch8_active_set          <= '0';
        write_cmnd_cmb          <= '0';
        ch_s2mm_ftch_sm_idle   <= (others => '0');
        ch_mm2s_ftch_sm_idle   <= (others => '0');
        ftch_ns                 <= ftch_cs;
                         s2mm_done_i <= '0';
                         mm2s_done_i <= '0';

        case ftch_cs is

            -------------------------------------------------------------------
            when IDLE =>

                ch_s2mm_ftch_sm_idle       <=  not service_ch_s2mm;
                ch_mm2s_ftch_sm_idle       <=  not service_ch_mm2s;

                if (s2mm_active = '1' or mm2s_active = '1') then
                    ftch_ns     <= FETCH_INIT;
                else
                    ftch_ns     <= IDLE;
                end if; 


            when FETCH_INIT =>
                ch_s2mm_ftch_sm_idle       <=  not service_ch_s2mm;
                ch_mm2s_ftch_sm_idle       <=  not service_ch_mm2s;

                -- sg error during fetch - shut down
                if(ftch_error = '1')then
                    ftch_ns     <= FETCH_ERROR;
                else --if (service_ch /= ALL_ZERO) then
                    ftch_ns <= FETCH_DESCRIPTOR;
                    active <= '1';

--                elsif(service_ch(0) = '1' and ch_token(0) = '1')then -- this is a mux input
--                    ch_active_set(0)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(1) = '1' and ch_token(1) = '1')then
--                    ch_active_set(1)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(2) = '1' and ch_token(2) = '1')then
--                    ch_active_set(2)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(3) = '1' and ch_token(3) = '1')then
--                    ch_active_set(3)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(4) = '1' and ch_token(4) = '1')then
--                    ch_active_set(4)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(5) = '1' and ch_token(5) = '1')then
--                    ch_active_set(5)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(6) = '1' and ch_token(6) = '1')then
--                    ch_active_set(6)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                elsif(service_ch(7) = '1' and ch_token(7) = '1')then
--                    ch_active_set(7)  <= '1';
--                    ftch_ns <= FETCH_DESCRIPTOR;
--                    active <= '1';
--                else
--                    ftch_ns                <= IDLE;
--                   -- shift <= '1';
--                    shift_mm2s <= '1';
--                    shift_s2mm <= '1';
                end if;

            -------------------------------------------------------------------
            when FETCH_DESCRIPTOR =>
                -- sg error during fetch - shut down
             --   shift <= '1';
                if(ftch_error = '1')then
                    ftch_ns     <= FETCH_ERROR;
                else
                    ch_s2mm_ftch_sm_idle    <= not (ch_active_i and s2mm_active_all) and not service_ch_s2mm;
                    ch_mm2s_ftch_sm_idle    <= not (ch_active_i and mm2s_active_all) and not service_ch_mm2s;                
                    write_cmnd_cmb      <= '1';
                    ftch_ns             <= FETCH_STATUS;
                end if;

            -------------------------------------------------------------------
            when FETCH_STATUS =>
                    ch_s2mm_ftch_sm_idle    <= not (ch_active_i and s2mm_active_all) and not service_ch_s2mm;
                    ch_mm2s_ftch_sm_idle    <= not (ch_active_i and mm2s_active_all) and not service_ch_mm2s;
                -- sg error during fetch - shut down
                if(ftch_error = '1')then
                    ftch_ns     <= FETCH_ERROR;

                elsif(ftch_done = '1')then
                    -- if finished S2MM then change to MM2S
                    if (s2mm_active = '1') then
                         s2mm_done_i <= '1';
                         ftch_ns <= IDLE2;
                    elsif (mm2s_active = '1') then
                         mm2s_done_i <= '1';
                         ftch_ns <= IDLE2;
                    else
                         ftch_ns <= IDLE2;
                    end if;
                else
                    ftch_ns <= FETCH_STATUS;
                end if;

            when IDLE2 =>
                    ch_s2mm_ftch_sm_idle    <= not (ch_active_i and s2mm_active_all) and not service_ch_s2mm;
                    ch_mm2s_ftch_sm_idle    <= not (ch_active_i and mm2s_active_all) and not service_ch_mm2s;                    
                ftch_ns <= IDLE;

            -------------------------------------------------------------------
            when FETCH_ERROR =>

             if ( C_ENABLE_MULTI_CH_RESET = 1) then
                    --ch_s2mm_ftch_sm_idle    <= (others => '1');
                    --ch_mm2s_ftch_sm_idle    <= (others => '1');    --Sravya
                    ch_s2mm_ftch_sm_idle    <= not (ch_active_i and s2mm_active_all) and not service_ch_s2mm;
                    ch_mm2s_ftch_sm_idle    <= not (ch_active_i and mm2s_active_all) and not service_ch_mm2s;                    
                 ftch_ns             <= FETCH_ERROR;
		if(ftch_error = '0') then --Sravya TODO for S2MM
			ftch_ns <= IDLE2;
			mm2s_done_i <= '1';
                        s2mm_done_i <= '1';
		end if;
             end if;

           if ( C_ENABLE_MULTI_CH_RESET = 0) then
                 ch_s2mm_ftch_sm_idle    <= (others => '1');
                 ch_mm2s_ftch_sm_idle    <= (others => '1');
                 ftch_ns             <= FETCH_ERROR;
           end if;   
            -------------------------------------------------------------------
            -- coverage off
            when others =>
                ftch_ns <= IDLE;

            -- coverage on
        end case;
    end process SG_FTCH_MACHINE;

