-------------------------------------------------------------------------------
REGISTER_STATE : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                ftch_cs     <= IDLE;
            else
                ftch_cs     <= ftch_ns;
            end if;
        end if;
    end process REGISTER_STATE;

REGISTER_STATE_DONE : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                s2mm_done     <= '0';
                mm2s_done     <= '0';
            else
                s2mm_done     <= s2mm_done_i;
                mm2s_done     <= mm2s_done_i;
            end if;
        end if;
    end process REGISTER_STATE_DONE;

