    GEN_CH1_NO_FETCH_PAUSE : if C_SG_FTCH_DESC2QUEUE /= 0 generate
            mm2s_pause_fetch <= or_reduce (ch_mm2s_ftch_pause);
    end generate GEN_CH1_NO_FETCH_PAUSE;

-------------------------------------------------------------------------------
-- based on MM2S or MM2S, the respective service_ch1 is chosen
-------------------------------------------------------------------------------

TOKEN_ID_MM2S : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                mm2s_ch_token(0) <= '1';
                mm2s_ch_token(C_MAX_CHANNELS-1 downto 1) <= (others => '0');
            elsif (shift_mm2s = '1' and C_NUM_MM2S_CHANNELS > 1) then
                mm2s_ch_token (C_NUM_MM2S_CHANNELS-1 downto 1) <= mm2s_ch_token (C_NUM_MM2S_CHANNELS-2 downto 0);
                mm2s_ch_token (0) <= mm2s_ch_token (C_NUM_MM2S_CHANNELS-1);
            elsif (shift_mm2s = '1' and C_NUM_MM2S_CHANNELS = 1) then
                mm2s_ch_token(0) <= '1';
                mm2s_ch_token(C_MAX_CHANNELS-1 downto 1) <= (others => '0');
            end if;
        end if;
    end process TOKEN_ID_MM2S;


 -- use or_reduce
service_any_mm2s <= or_reduce (service_ch_mm2s);
mm2s_ftch_active <= mm2s_active;


