 begin
  mm2s_channel_ftch  <= ch_active_i_r;
  service_ch_mm2s <= service_ch_mm2s_i and mm2s_ch_token;
 end generate CHN_FTCH_MULTI_RST;

CHN_FTCH_SINGLE_RST: if (C_ENABLE_MULTI_CH_RESET = 0) generate
