   mm2s_channel_ftch  <= ch_active_i;
   service_ch_mm2s <= service_ch_mm2s_i2 and mm2s_ch_token;
 end generate CHN_FTCH_SINGLE_RST;


MM2S_GEN: for I in 0 to C_NUM_MM2S_CHANNELS-1 generate
begin
    service_ch_mm2s_i(I) <= '1' when ch_mm2s_run_stop(I) = '1'          -- Channel running
                        and ch_mm2s_sg_idle(I) = '0'           -- SG Engine running
                        and ch_mm2s_ftch_queue_full(I) = '0'   -- Queue not full
                        and updt_error = '0'            -- No SG Update error
                        and mm2s_stale_descriptor = '0'  -- No Stale Descriptors
                        and ch_mm2s_desc_flush(I) = '0'        -- Not flushing desc
                        and ch_mm2s_ftch_pause(I) = '0'       -- No fetch pause
              else '0';


    process (m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                      service_ch_mm2s_i2(I) <= '0';
                else
                      service_ch_mm2s_i2(I) <= service_ch_mm2s_i(I);
                end if;
            end if;
     end process;


    ch_mm2s_ftch_active(I) <= ch_active_i(I) and mm2s_active;
    ch_mm2s_ftch_active_i(I) <= ch_active_i(I) and mm2s_active;

 
CH_MM2S_IDLE_PROCESS_MULTI_RST: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
    CH_MM2S_IDLE_PROCESS : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    ch_mm2s_ftch_idle(I)   <= '1';

--                elsif(updt_error = '1' or ftch_error = '1'
                elsif((ftch_error = '1'
                or (mm2s_ftch_interr_set_i = '1')) and ch_active_i(I) = '1') then -- and ch_active_i(I) = '1')) then --ch1_mm2s_ftch_interr_set_i = '1')then

                    ch_mm2s_ftch_idle(I)   <= '1';

                -- When SG Fetch no longer idle then clear fetch idle
                elsif(ch_mm2s_sg_idle(I) = '0')then
                    ch_mm2s_ftch_idle(I)   <= '0';

                -- If tail = cur and fetch queue is empty then
                elsif(ch_mm2s_sg_idle(I) = '1' and ch_mm2s_ftch_queue_empty(I) = '1' and ch_mm2s_ftch_sm_idle(I) = '1')then
                    ch_mm2s_ftch_idle(I)   <= '1';
                end if;
            end if;
        end process CH_MM2S_IDLE_PROCESS;
end generate CH_MM2S_IDLE_PROCESS_MULTI_RST;

CH_MM2S_IDLE_PROCESS_SINGLE_RST: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
   CH_MM2S_IDLE_PROCESS : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    ch_mm2s_ftch_idle(I)   <= '1';

--                elsif(updt_error = '1' or ftch_error = '1'
                elsif(ftch_error = '1'
                or (mm2s_ftch_interr_set_i = '1')) then -- and ch_active_i(I) = '1')) then --ch1_mm2s_ftch_interr_set_i = '1')then

                    ch_mm2s_ftch_idle(I)   <= '1';

                -- When SG Fetch no longer idle then clear fetch idle
                elsif(ch_mm2s_sg_idle(I) = '0')then
                    ch_mm2s_ftch_idle(I)   <= '0';

                -- If tail = cur and fetch queue is empty then
                elsif(ch_mm2s_sg_idle(I) = '1' and ch_mm2s_ftch_queue_empty(I) = '1' and ch_mm2s_ftch_sm_idle(I) = '1')then
                    ch_mm2s_ftch_idle(I)   <= '1';
                end if;
            end if;
        end process CH_MM2S_IDLE_PROCESS;

end generate CH_MM2S_IDLE_PROCESS_SINGLE_RST; 
 
end generate MM2S_GEN;


UNUSED_CHANNELS : if (C_MAX_CHANNELS > C_NUM_MM2S_CHANNELS) generate
begin

MM2S_GEN: for I in C_NUM_MM2S_CHANNELS to C_MAX_CHANNELS-1 generate
begin

    service_ch_mm2s_i(I) <= '0';
    service_ch_mm2s_i2(I) <= '0';
    ch_mm2s_ftch_active(I) <= '0';
    ch_mm2s_ftch_active_i(I) <= '0';
    ch_mm2s_ftch_idle(I) <= '1';

end generate MM2S_GEN;

end generate UNUSED_CHANNELS;



    -------------------------------------------------------------------------------
    -- Log Fetch Errors
    -- Common for MM2S, if one channel has stale, the whole engine comes down
    -------------------------------------------------------------------------------

  RST_PER_CH_ENABLE_GEN: if C_ENABLE_MULTI_CH_RESET = 1 generate 
  begin
    INT_ERROR_PROCESS_MM2S : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0' or soft_rst_mm2s = '1')then
                    mm2s_ftch_interr_set_i  <= '0';
                -- Channel active and datamover int error or fetch done and descriptor stale
                --elsif((mm2s_active = '1' and ftch_interr = '1') -- and any_channel = '1')
                --   or ((ftch_done = '1' or ftch_error = '1') and mm2s_stale_descriptor = '1'))then
                --    mm2s_ftch_interr_set_i  <= '1';
                elsif (mm2s_active = '1' and (ftch_interr = '1' or ftch_stale_desc = '1')) then
                      mm2s_ftch_interr_set_i <= '1';
		else 
			mm2s_ftch_interr_set_i <= '0';
                end if;
            end if;
        end process INT_ERROR_PROCESS_MM2S;

   SLV_ERROR_PROCESS_MM2S : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0' or soft_rst_mm2s = '1')then
                    mm2s_ftch_slverr_set_i  <= '0';
                elsif(mm2s_active = '1' and ftch_slverr = '1')then
                    mm2s_ftch_slverr_set_i  <= '1';
		else 
			mm2s_ftch_slverr_set_i <= '0';
                end if;
            end if;
        end process SLV_ERROR_PROCESS_MM2S;

    DEC_ERROR_PROCESS_MM2S : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0' or soft_rst_mm2s = '1')then
                    mm2s_ftch_decerr_set_i  <= '0';
                elsif(mm2s_active = '1'and ftch_decerr = '1')then
                    mm2s_ftch_decerr_set_i  <= '1';
		else 
			mm2s_ftch_decerr_set_i <= '0';
                end if;
            end if;
        end process DEC_ERROR_PROCESS_MM2S;

  end generate RST_PER_CH_ENABLE_GEN;

 RST_PER_CH_DISABLE_GEN: if C_ENABLE_MULTI_CH_RESET = 0 generate 
  begin
    INT_ERROR_PROCESS_MM2S : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    mm2s_ftch_interr_set_i  <= '0';
                -- Channel active and datamover int error or fetch done and descriptor stale
                --elsif((mm2s_active = '1' and ftch_interr = '1') -- and any_channel = '1')
                --   or ((ftch_done = '1' or ftch_error = '1') and mm2s_stale_descriptor = '1'))then
                --    mm2s_ftch_interr_set_i  <= '1';
                elsif (mm2s_active = '1') then
                   if (ftch_interr = '1' or ftch_stale_desc = '1') then
                      mm2s_ftch_interr_set_i <= '1';
                   end if;
                end if;
            end if;
        end process INT_ERROR_PROCESS_MM2S;
   
   SLV_ERROR_PROCESS_MM2S : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    mm2s_ftch_slverr_set_i  <= '0';
                elsif(mm2s_active = '1' and ftch_slverr = '1')then
                    mm2s_ftch_slverr_set_i  <= '1';
                end if;
            end if;
        end process SLV_ERROR_PROCESS_MM2S;

   DEC_ERROR_PROCESS_MM2S : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    mm2s_ftch_decerr_set_i  <= '0';
                elsif(mm2s_active = '1'and ftch_decerr = '1')then
                    mm2s_ftch_decerr_set_i  <= '1';
                end if;
            end if;
        end process DEC_ERROR_PROCESS_MM2S;


 end generate RST_PER_CH_DISABLE_GEN;

    mm2s_ftch_interr_set <= mm2s_ftch_interr_set_i;
    mm2s_ftch_slverr_set <= mm2s_ftch_slverr_set_i;
    mm2s_ftch_decerr_set <= mm2s_ftch_decerr_set_i;

    -- Early detection of SlvErr or DecErr, used to prevent error'ed descriptor
    -- from being used by dma controller
    mm2s_ftch_err_early_i  <= '1' when (ftch_error_early = '1' and mm2s_active = '1')
                            else '0';

    mm2s_ftch_err_early <= mm2s_ftch_err_early_i;

    -- Enable stale descriptor check
    GEN_CH1_STALE_CHECK : if C_SG_CH1_ENBL_STALE_ERROR = 1 generate
    begin
        -----------------------------------------------------------------------
        -- Stale Descriptor Error
        -----------------------------------------------------------------------
     CH1_STALE_DESC_MULTI_RST: if C_ENABLE_MULTI_CH_RESET = 1 generate
     begin
        CH1_STALE_DESC : process(m_axi_msg_aclk)
            begin
                if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                    -- If reset then clear flag
                    if(m_axi_msg_aresetn = '0' or soft_rst_mm2s = '1')then
                        mm2s_stale_descriptor <= '0';
                    elsif(ftch_stale_desc = '1' and mm2s_active='1')then
                        mm2s_stale_descriptor <= '1';
		    else
			mm2s_stale_descriptor <= '0';
                    end if;
                end if;
            end process CH1_STALE_DESC;
     end generate CH1_STALE_DESC_MULTI_RST;

    CH1_STALE_DESC_SINGLE_RST: if C_ENABLE_MULTI_CH_RESET = 0 generate
     begin
       CH1_STALE_DESC : process(m_axi_msg_aclk)
            begin
                if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                    -- If reset then clear flag
                    if(m_axi_msg_aresetn = '0')then
                        mm2s_stale_descriptor <= '0';
                    elsif(ftch_stale_desc = '1' and mm2s_active='1')then
                        mm2s_stale_descriptor <= '1';
                    end if;
                end if;
            end process CH1_STALE_DESC;
    end generate CH1_STALE_DESC_SINGLE_RST;

    end generate GEN_CH1_STALE_CHECK;

    -- Disable stale descriptor check
    GEN_CH1_NO_STALE_CHECK : if C_SG_CH1_ENBL_STALE_ERROR = 0 generate
    begin
        mm2s_stale_descriptor <= '0';
    end generate GEN_CH1_NO_STALE_CHECK;

    -- Early detection of Stale Descriptor (valid only in tailpntr mode) used
    -- to prevent error'ed descriptor from being used.
    mm2s_ftch_stale_desc <= mm2s_stale_descriptor;

               mm2s_fetch_address <= ch_mm2s_fetch_address((func_ret_int(ch_active_i)+1)*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*func_ret_int(ch_active_i));

