--           when "00000010" =>
--               mm2s_fetch_address <= ch_mm2s_fetch_address(2*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*1);
--           when "00000100" =>
--               mm2s_fetch_address <= ch_mm2s_fetch_address(3*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*2);
--           when "00001000" =>
--               mm2s_fetch_address <= ch_mm2s_fetch_address(4*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*3);
--           when "00010000" =>
