--           when "01000000" =>
--               mm2s_fetch_address <= ch_mm2s_fetch_address(7*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*6);
--           when "10000000" =>
--               mm2s_fetch_address <= ch_mm2s_fetch_address(8*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*7);
--           when others =>
--               mm2s_fetch_address <= ch_mm2s_fetch_address(C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
      
