--end process;

end generate GEN_CH1_FETCH;

-------------------------------------------------------------------------------
-- Channel excluded therefore do not generate fetch logic
-------------------------------------------------------------------------------
GEN_NO_CH1_FETCH : if C_INCLUDE_CH1 = 0 generate
begin
    mm2s_ftch_interr_set	<= '0';
    ch_mm2s_ftch_idle       <= (others => '1');
    mm2s_ftch_slverr_set <= '0';
    mm2s_ftch_decerr_set <= '0';
    mm2s_ftch_err_early  <= '0';
    mm2s_ftch_stale_desc <= '0';
    mm2s_ch_token <= (others => '0');
    mm2s_fetch_address <= (others => '0');
    ch_mm2s_ftch_active <= (others => '0');
    service_any_mm2s <= '0';

mm2s_ftch_active <= '0';
mm2s_channel_ftch  <= (others => '0');

end generate GEN_NO_CH1_FETCH;


-------------------------------------------------------------------------------
-- S2MM Channel included therefore generate fetch logic
-------------------------------------------------------------------------------
GEN_CH2_FETCH : if C_INCLUDE_CH2 = 1 generate
begin

TOKEN_ID_S2MM : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                s2mm_ch_token(0) <= '1';
                s2mm_ch_token(C_MAX_CHANNELS-1 downto 1) <= (others => '0');
            elsif (shift_s2mm = '1' and C_NUM_S2MM_CHANNELS > 1) then
                s2mm_ch_token (C_NUM_S2MM_CHANNELS-1 downto 1) <= s2mm_ch_token (C_NUM_S2MM_CHANNELS-2 downto 0);
                s2mm_ch_token (0) <= s2mm_ch_token (C_NUM_S2MM_CHANNELS-1);
            elsif (shift_s2mm = '1' and C_NUM_S2MM_CHANNELS = 1) then
                s2mm_ch_token(0) <= '1';
                s2mm_ch_token(C_MAX_CHANNELS-1 downto 1) <= (others => '0');
            end if;
        end if;
    end process TOKEN_ID_S2MM;


    -- Fetch queues so do not need to pause
    GEN_CH2_NO_FETCH_PAUSE : if C_SG_FTCH_DESC2QUEUE /= 0 generate
            s2mm_pause_fetch <= or_reduce (ch_s2mm_ftch_pause);
    end generate GEN_CH2_NO_FETCH_PAUSE;

-------------------------------------------------------------------------------
-- based on MM2S or S2MM, the respective service_ch1 is chosen
-------------------------------------------------------------------------------


 -- use or_reduce
service_any_s2mm <= or_reduce (service_ch_s2mm);
s2mm_ftch_active <= s2mm_active;

CHN_FTCH_S2MM_MULTI: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
s2mm_channel_ftch  <= ch_active_i_r;
service_ch_s2mm <= service_ch_s2mm_i and s2mm_ch_token;
end generate CHN_FTCH_S2MM_MULTI;

CHN_FTCH_S2MM_SINGLE: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
s2mm_channel_ftch  <= ch_active_i;
service_ch_s2mm <= service_ch_s2mm_i2 and s2mm_ch_token;
end generate CHN_FTCH_S2MM_SINGLE;

-- service_ch_s2mm <= service_ch_s2mm_i2 and s2mm_ch_token;


S2MM_GEN: for I in 0 to C_NUM_S2MM_CHANNELS-1 generate
begin
    service_ch_s2mm_i(I) <= '1' when ch_s2mm_run_stop(I) = '1'          -- Channel running
                        and ch_s2mm_sg_idle(I) = '0'           -- SG Engine running
                        and ch_s2mm_ftch_queue_full(I) = '0'   -- Queue not full
                        and updt_error = '0'            -- No SG Update error
                        and s2mm_stale_descriptor = '0'  -- No Stale Descriptors
                        and ch_s2mm_desc_flush(I) = '0'        -- Not flushing desc
                        and ch_s2mm_ftch_pause(I) = '0'       -- No fetch pause
              else '0';


    process (m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                      service_ch_s2mm_i2(I) <= '0';
                else
                      service_ch_s2mm_i2(I) <= service_ch_s2mm_i(I);
                end if;
            end if;
     end process;


    ch_s2mm_ftch_active(I) <= ch_active_i(I) and s2mm_active;
    ch_s2mm_ftch_active_i(I) <= ch_active_i(I) and s2mm_active;

CH_S2MM_IDLE_PROCESS_MULTI_RST :  if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
   CH_S2MM_IDLE_PROCESS : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    ch_s2mm_ftch_idle(I)   <= '1';

--                elsif(updt_error = '1' or ftch_error = '1'
                elsif((ftch_error = '1'
                or (s2mm_ftch_interr_set_i = '1')) and ch_active_i (I) = '1') then -- and ch_active_i(I) = '1')) then --ch1_s2mm_ftch_interr_set_i = '1')then

                    ch_s2mm_ftch_idle(I)   <= '1';

                -- When SG Fetch no longer idle then clear fetch idle
                elsif(ch_s2mm_sg_idle(I) = '0')then
                    ch_s2mm_ftch_idle(I)   <= '0';

                -- If tail = cur and fetch queue is empty then
                elsif(ch_s2mm_sg_idle(I) = '1' and ch_s2mm_ftch_queue_empty(I) = '1' and ch_s2mm_ftch_sm_idle(I) = '1')then
                    ch_s2mm_ftch_idle(I)   <= '1';
                end if;
            end if;
        end process CH_S2MM_IDLE_PROCESS;


end generate CH_S2MM_IDLE_PROCESS_MULTI_RST;
 
CH_S2MM_IDLE_PROCESS_SINGLE_RST :  if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
    CH_S2MM_IDLE_PROCESS : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    ch_s2mm_ftch_idle(I)   <= '1';

--                elsif(updt_error = '1' or ftch_error = '1'
                elsif(ftch_error = '1'
                or (s2mm_ftch_interr_set_i = '1')) then -- and ch_active_i(I) = '1')) then --ch1_s2mm_ftch_interr_set_i = '1')then

                    ch_s2mm_ftch_idle(I)   <= '1';

                -- When SG Fetch no longer idle then clear fetch idle
                elsif(ch_s2mm_sg_idle(I) = '0')then
                    ch_s2mm_ftch_idle(I)   <= '0';

                -- If tail = cur and fetch queue is empty then
                elsif(ch_s2mm_sg_idle(I) = '1' and ch_s2mm_ftch_queue_empty(I) = '1' and ch_s2mm_ftch_sm_idle(I) = '1')then
                    ch_s2mm_ftch_idle(I)   <= '1';
                end if;
            end if;
        end process CH_S2MM_IDLE_PROCESS;
end generate CH_S2MM_IDLE_PROCESS_SINGLE_RST;

end generate S2MM_GEN;


UNUSED_CHANNELS : if (C_MAX_CHANNELS > C_NUM_S2MM_CHANNELS) generate
begin

S2MM_GEN: for I in C_NUM_S2MM_CHANNELS to C_MAX_CHANNELS-1 generate
begin

    service_ch_s2mm_i(I) <= '0';
    service_ch_s2mm_i2(I) <= '0';
    ch_s2mm_ftch_active(I) <= '0';
    ch_s2mm_ftch_active_i(I) <= '0';
    ch_s2mm_ftch_idle(I) <= '1';

end generate S2MM_GEN;

end generate UNUSED_CHANNELS;


