    -------------------------------------------------------------------------------
    -- Log Fetch Errors
    -- Common for S2MM, if one channel has stale, the whole engine comes down
    -------------------------------------------------------------------------------
RST_PER_CH_ENABLE_GEN2: if C_ENABLE_MULTI_CH_RESET = 1 generate 
  begin
    INT_ERROR_PROCESS_S2MM : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0' or soft_rst_s2mm = '1')then
                    s2mm_ftch_interr_set_i  <= '0';
                -- Channel active and datamover int error or fetch done and descriptor stale
                --elsif((s2mm_active = '1' and ftch_interr = '1') -- and any_channel = '1')
                --   or ((ftch_done = '1' or ftch_error = '1') and s2mm_stale_descriptor = '1'))then
                --    s2mm_ftch_interr_set_i  <= '1';
                elsif (s2mm_active = '1' and (ftch_interr = '1' or ftch_stale_desc = '1')) then
                    s2mm_ftch_interr_set_i  <= '1';
                else 
                    s2mm_ftch_interr_set_i  <= '0';                     
                end if;
            end if;
        end process INT_ERROR_PROCESS_S2MM;


    SLV_ERROR_PROCESS_S2MM : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0' or soft_rst_s2mm = '1')then
                    s2mm_ftch_slverr_set_i  <= '0';
                elsif(s2mm_active = '1' and ftch_slverr = '1')then
                    s2mm_ftch_slverr_set_i  <= '1';
                else 
                    s2mm_ftch_slverr_set_i  <= '0';                    
                end if;
            end if;
        end process SLV_ERROR_PROCESS_S2MM;


    DEC_ERROR_PROCESS_S2MM : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0' or soft_rst_s2mm = '1')then
                    s2mm_ftch_decerr_set_i  <= '0';
                elsif(s2mm_active = '1' and ftch_decerr = '1')then
                    s2mm_ftch_decerr_set_i  <= '1';
                else 
                    s2mm_ftch_decerr_set_i  <= '0';                    
                end if;
            end if;
        end process DEC_ERROR_PROCESS_S2MM;

end generate RST_PER_CH_ENABLE_GEN2;

RST_PER_CH_DISABLE_GEN2: if C_ENABLE_MULTI_CH_RESET = 0 generate 
  begin
    INT_ERROR_PROCESS_S2MM : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    s2mm_ftch_interr_set_i  <= '0';
                -- Channel active and datamover int error or fetch done and descriptor stale
                --elsif((s2mm_active = '1' and ftch_interr = '1') -- and any_channel = '1')
                --   or ((ftch_done = '1' or ftch_error = '1') and s2mm_stale_descriptor = '1'))then
                --    s2mm_ftch_interr_set_i  <= '1';
                elsif (s2mm_active = '1') then
                   if (ftch_interr = '1' or ftch_stale_desc = '1') then
                    s2mm_ftch_interr_set_i  <= '1';
                   end if;
                end if;
            end if;
        end process INT_ERROR_PROCESS_S2MM;


    SLV_ERROR_PROCESS_S2MM : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    s2mm_ftch_slverr_set_i  <= '0';
                elsif(s2mm_active = '1' and ftch_slverr = '1')then
                    s2mm_ftch_slverr_set_i  <= '1';
                end if;
            end if;
        end process SLV_ERROR_PROCESS_S2MM;


    DEC_ERROR_PROCESS_S2MM : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- If reset or stopped then clear idle bit
                if(m_axi_msg_aresetn = '0')then
                    s2mm_ftch_decerr_set_i  <= '0';
                elsif(s2mm_active = '1' and ftch_decerr = '1')then
                    s2mm_ftch_decerr_set_i  <= '1';
                end if;
            end if;
        end process DEC_ERROR_PROCESS_S2MM;

end generate RST_PER_CH_DISABLE_GEN2;

    s2mm_ftch_decerr_set <= s2mm_ftch_decerr_set_i;
    s2mm_ftch_slverr_set <= s2mm_ftch_slverr_set_i;
    s2mm_ftch_interr_set <= s2mm_ftch_interr_set_i;
    
    -- Early detection of SlvErr or DecErr, used to prevent error'ed descriptor
    -- from being used by dma controller
    s2mm_ftch_err_early_i  <= '1' when (ftch_error_early = '1' and s2mm_active = '1')
                            else '0';

    s2mm_ftch_err_early <= s2mm_ftch_err_early_i;

    -- Enable stale descriptor check
    GEN_CH2_STALE_CHECK : if C_SG_CH2_ENBL_STALE_ERROR = 1 generate
    begin
        -----------------------------------------------------------------------
        -- Stale Descriptor Error
        -----------------------------------------------------------------------
CH2_STALE_DESC_MULTI_RST: if C_ENABLE_MULTI_CH_RESET = 1 generate
     begin
      CH2_STALE_DESC : process(m_axi_msg_aclk)
            begin
                if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                    -- If reset then clear flag
                    if(m_axi_msg_aresetn = '0' or soft_rst_s2mm = '1')then
                        s2mm_stale_descriptor <= '0';
                    elsif(ftch_stale_desc = '1' and s2mm_active='1')then
                        s2mm_stale_descriptor <= '1';
                    else 
                        s2mm_stale_descriptor <= '0';                        
                    end if;
                end if;
            end process CH2_STALE_DESC;

end generate CH2_STALE_DESC_MULTI_RST;

CH2_STALE_DESC_SINGLE_RST: if C_ENABLE_MULTI_CH_RESET = 0 generate
     begin
        CH2_STALE_DESC : process(m_axi_msg_aclk)
            begin
                if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                    -- If reset then clear flag
                    if(m_axi_msg_aresetn = '0')then
                        s2mm_stale_descriptor <= '0';
                    elsif(ftch_stale_desc = '1' and s2mm_active='1')then
                        s2mm_stale_descriptor <= '1';
                    end if;
                end if;
            end process CH2_STALE_DESC;
end generate CH2_STALE_DESC_SINGLE_RST;

    end generate GEN_CH2_STALE_CHECK;
    -- Disable stale descriptor check
    GEN_CH2_NO_STALE_CHECK : if C_SG_CH2_ENBL_STALE_ERROR = 0 generate
    begin
        s2mm_stale_descriptor <= '0';
    end generate GEN_CH2_NO_STALE_CHECK;

    -- Early detection of Stale Descriptor (valid only in tailpntr mode) used
    -- to prevent error'ed descriptor from being used.
    s2mm_ftch_stale_desc <= s2mm_stale_descriptor;

               s2mm_fetch_address <= ch_s2mm_fetch_address((func_ret_int(ch_active_i)+1)*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*func_ret_int(ch_active_i));

--process (ch_active_i, ch_s2mm_fetch_address)

--begin

--       case (ch_active_i(7 downto 0)) is

--           when "00000001" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
--           when "00000010" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(2*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*1);
--           when "00000100" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(3*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*2);
--           when "00001000" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(4*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*3);
--           when "00010000" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(5*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*4);
--           when "00100000" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(6*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*5);
--           when "01000000" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(7*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*6);
--           when "10000000" =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(8*C_M_AXI_SG_ADDR_WIDTH-1 downto C_M_AXI_SG_ADDR_WIDTH*7);
--           when others =>
--               s2mm_fetch_address <= ch_s2mm_fetch_address(C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
      
--        end case; 

--end process;

end generate GEN_CH2_FETCH;

-------------------------------------------------------------------------------
-- Channel excluded therefore do not generate fetch logic
-------------------------------------------------------------------------------
GEN_NO_CH2_FETCH : if C_INCLUDE_CH2 = 0 generate
begin
    ch_s2mm_ftch_idle       <= (others => '1');
    s2mm_ftch_interr_set <= '0';
    s2mm_ftch_slverr_set <= '0';
    s2mm_ftch_decerr_set <= '0';
    s2mm_ftch_err_early  <= '0';
    s2mm_ftch_stale_desc <= '0';
    s2mm_ch_token <= (others => '0');
    s2mm_fetch_address <= (others => '0');
    ch_s2mm_ftch_active <= (others => '0');
    ch_s2mm_ftch_active_i <= (others => '0');
    service_any_s2mm <= '0';

s2mm_ftch_active <= '0';
s2mm_channel_ftch  <= (others => '0');
service_ch_s2mm  <= (others => '0');

end generate GEN_NO_CH2_FETCH;

-------------------------------------------------------------------------------
-- Build DataMover command
-------------------------------------------------------------------------------
-- Assign fetch address 
--fetch_cmd_addr  <= ch1_fetch_address when ch1_active_i = '1'
--             else  ch2_fetch_address;
fetch_cmd_addr  <= mm2s_fetch_address when mm2s_active = '1'
             else  s2mm_fetch_address;






-- Assign bytes to transfer (BTT)
fetch_cmd_btt   <= FETCH_CH1_CMD_BTT when mm2s_active = '1'
             else  FETCH_CH2_CMD_BTT;

fetch_tag <= "0001" when mm2s_active = '1'
              else "0000";

-- When command by sm, drive command to ftch_cmdsts_if
--GEN_DATAMOVER_CMND : process(m_axi_msg_aclk)
--    begin
--        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
--            if(m_axi_msg_aresetn = '0')then
--                ftch_cmnd_wr    <= '0';
--                ftch_cmnd_data  <= (others => '0');

--            -- Fetch SM issued a command write
--            elsif(write_cmnd_cmb = '1')then
--                ftch_cmnd_wr    <= '1';
--                ftch_cmnd_data  <=  FETCH_CMD_RSVD
--                                    & fetch_tag
--                                    & fetch_cmd_addr
--                                    & FETCH_MSB_IGNORED
--                                    & FETCH_CMD_TYPE
--                                    & FETCH_LSB_IGNORED
--                                    & fetch_cmd_btt;
--            else
--                ftch_cmnd_wr    <= '0';

--            end if;
--        end if;
--    end process GEN_DATAMOVER_CMND;


                ftch_cmnd_wr    <= write_cmnd_cmb;
                ftch_cmnd_data  <=  FETCH_CMD_RSVD
                                    & fetch_tag
                                    & fetch_cmd_addr
                                    & FETCH_MSB_IGNORED
                                    & FETCH_CMD_TYPE
                                    & FETCH_LSB_IGNORED
                                    & fetch_cmd_btt;

-------------------------------------------------------------------------------
-- Capture and hold fetch address in case an error occurs
-------------------------------------------------------------------------------
LOG_ERROR_ADDR : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                ftch_error_addr (C_M_AXI_SG_ADDR_WIDTH-1 downto SG_ADDR_LSB)    <= (others => '0');
            elsif(write_cmnd_cmb = '1')then
              ftch_error_addr (C_M_AXI_SG_ADDR_WIDTH-1 downto SG_ADDR_LSB)   <= fetch_cmd_addr (C_M_AXI_SG_ADDR_WIDTH-1 downto SG_ADDR_LSB);
            end if;
        end if;
    end process LOG_ERROR_ADDR;

     ftch_error_addr (5 downto 0) <= "000000";

end implementation;



