library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library unisim;
use unisim.vcomponents.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;

-------------------------------------------------------------------------------
entity  axi_msg_channel_pntr is
    generic (
        C_M_AXI_SG_ADDR_WIDTH       : integer range 32 to 64        := 32   
            -- Master AXI Memory Map Address Width for Scatter Gather R/W Port
    );
    port (
       m_axi_msg_aresetn : in std_logic;
       m_axi_msg_aclk    : in std_logic;
       run_stop         : in std_logic;
       desc_flush       : in std_logic;
       nxtdesc_wren     : in std_logic;
       curdesc          : in std_logic_vector (C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
       nxtdesc          : in std_logic_vector (C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
       taildesc         : in std_logic_vector (C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
       taildesc_wren    : in std_logic;
       tailpntr_enabled : in std_logic;
       fetch_address    : out std_logic_vector (C_M_AXI_SG_ADDR_WIDTH-1 downto 0);
       sg_idle          : out std_logic
    );

end axi_msg_channel_pntr;

-------------------------------------------------------------------------------
-- Architecture
-------------------------------------------------------------------------------
architecture implementation of axi_msg_channel_pntr is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";

signal run_stop_d1 : std_logic;
signal run_stop_re : std_logic;
signal use_crntdesc : std_logic;
signal fetch_address_i : std_logic_vector (C_M_AXI_SG_ADDR_WIDTH-1 downto 0);

begin
    ---------------------------------------------------------------------------
    -- Create clock delay of run_stop in order to generate a rising edge pulse
    ---------------------------------------------------------------------------
    GEN_RUNSTOP_RE : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0')then
                    run_stop_d1 <= '0';
                else
                    run_stop_d1 <= run_stop;
                end if;
            end if;
        end process GEN_RUNSTOP_RE;

    run_stop_re <= run_stop and not run_stop_d1;

    ---------------------------------------------------------------------------
    -- At setting of run/stop need to use current descriptor pointer therefor
    -- flag for use
    ---------------------------------------------------------------------------
    GEN_INIT_PNTR : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0' or nxtdesc_wren = '1')then
                    use_crntdesc <= '0';
                elsif(run_stop_re = '1')then
                    use_crntdesc <= '1';
                end if;
            end if;
        end process GEN_INIT_PNTR;

    ---------------------------------------------------------------------------
    -- Register Current Fetch Address.  During start (run/stop asserts) reg
    -- curdesc pointer from register module.  Once running use nxtdesc pointer.
    ---------------------------------------------------------------------------
    REG_FETCH_ADDRESS : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0')then
                    fetch_address_i <= (others => '0');
                -- On initial tail pointer write use current desc pointer
                elsif((use_crntdesc = '1' and nxtdesc_wren = '0'))then
                    fetch_address_i <= curdesc;
                -- On descirptor fetch capture next pointer
                elsif(nxtdesc_wren = '1')then
                    fetch_address_i <= nxtdesc;
                end if;
            end if;
        end process REG_FETCH_ADDRESS;

    -- Pass address out of module
    -- Addresses are always 16 word 32-bit aligned
    fetch_address <= fetch_address_i (C_M_AXI_SG_ADDR_WIDTH-1 downto 6) & "000000";

    ---------------------------------------------------------------------------
    -- Compair tail descriptor pointer to scatter gather engine current
    -- descriptor pointer.  Set idle if matched.  Only check if DMA engine
    -- is running and current descriptor is in process of being fetched.  This
    -- forces at least 1 descriptor fetch before checking for IDLE condition.
    ---------------------------------------------------------------------------
    COMPARE_ADDRESS : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                -- SG is IDLE on reset and on stop.
                --CR568950 - reset idlag on descriptor flush
                --if(m_axi_msg_aresetn = '0' or run_stop = '0')then
                if(m_axi_msg_aresetn = '0' or run_stop = '0' or desc_flush = '1') then
                    sg_idle <= '1';

                -- taildesc_wren must be in this 'if' to force a minimum
                -- of 1 clock of sg_idle = '0'.
                elsif(taildesc_wren = '1' or tailpntr_enabled = '0')then
                    sg_idle <= '0';

                -- Descriptor at fetch_address is being fetched (wren=1)
                -- therefore safe to check if tail matches the fetch address
                elsif(nxtdesc_wren = '1'
                and taildesc = fetch_address_i)then
                    sg_idle <= '1';
                end if;
            end if;
        end process COMPARE_ADDRESS;


end implementation;


