-------------------------------------------------------------------------------
-- Filename:    axi_msg_ftch_pntr.vhd
-- Description: This entity manages descriptor pointers and determine scatter
--              gather idle mode.
--
-- VHDL-Standard:   VHDL'93
-------------------------------------------------------------------------------
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library unisim;
use unisim.vcomponents.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;

-------------------------------------------------------------------------------
entity  axi_msg_ftch_pntr is
    generic (
        C_M_AXI_SG_ADDR_WIDTH       : integer range 32 to 64        := 32   ;
            -- Master AXI Memory Map Address Width for Scatter Gather R/W Port

        C_INCLUDE_CH1               : integer range 0 to 1          := 1    ;
            -- Include or Exclude channel 1 scatter gather engine
            -- 0 = Exclude Channel 1 SG Engine
            -- 1 = Include Channel 1 SG Engine

        C_INCLUDE_CH2               : integer range 0 to 1          := 1   ;        
            -- Include or Exclude channel 2 scatter gather engine
            -- 0 = Exclude Channel 2 SG Engine
            -- 1 = Include Channel 2 SG Engine
        C_NUM_MM2S_CHANNELS          : integer range 1 to 16;
        C_NUM_S2MM_CHANNELS          : integer range 1 to 16;
        C_MAX_CHANNELS               : integer range 1 to 16 := 8 
    );
    port (
        -----------------------------------------------------------------------
        -- AXI Scatter Gather Interface
        -----------------------------------------------------------------------
        m_axi_msg_aclk               : in  std_logic                         ;                  --
        m_axi_msg_aresetn            : in  std_logic                         ;                  --
                                                                                               --
        nxtdesc                     : in  std_logic_vector                                     --
                                        (C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --

        -------------------------------                                                        --
        -- S2MM CHANNEL 1                                                                           --
        -------------------------------                                                        --
        ch_mm2s_run_stop                : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
        ch_mm2s_desc_flush              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;--CR568950        --
       -- ch1_s2mm_eof_detected            : in  std_logic                         ;                  -- -- not needed
        -- CURDESC update to fetch pointer on run/stop assertion                               --
        ch_mm2s_curdesc                 : in  std_logic_vector                                     --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --
        -- TAILDESC update on CPU write (from axi_dma_reg_module)                              --
        ch_mm2s_tailpntr_enabled        : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
        ch_mm2s_taildesc_wren           : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
        ch_mm2s_taildesc                : in  std_logic_vector                                     --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --
    --    tail_updt                   : in std_logic; -- not needed
    --    tail_updt_latch             : out std_logic;  -- not needed
      --  ch1_s2mm_updt_done               : in std_logic; --not needed
                                                                                               --
        -- NXTDESC update on descriptor fetch (from axi_msg_ftchq_if)                           --
        ch_mm2s_nxtdesc_wren            : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
                                                                                               --
        -- Current address of descriptor to fetch                                              --
        ch_mm2s_fetch_address           : out std_logic_vector                                     --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --
        ch_mm2s_sg_idle                 : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
                                                                                               --
                                                                                               --
        -------------------------------                                                        --
        -- S2MM CHANNEL 1                                                                           --
        -------------------------------                                                        --
        ch_s2mm_run_stop                : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
        ch_s2mm_desc_flush              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;--CR568950        --
       -- ch1_s2mm_eof_detected            : in  std_logic                         ;                  -- -- not needed
        -- CURDESC update to fetch pointer on run/stop assertion                               --
        ch_s2mm_curdesc                 : in  std_logic_vector                                     --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --
        -- TAILDESC update on CPU write (from axi_dma_reg_module)                              --
        ch_s2mm_tailpntr_enabled        : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
        ch_s2mm_taildesc_wren           : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
        ch_s2mm_taildesc                : in  std_logic_vector                                     --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --
    --    tail_updt                   : in std_logic; -- not needed
    --    tail_updt_latch             : out std_logic;  -- not needed
      --  ch1_s2mm_updt_done               : in std_logic; --not needed
                                                                                               --
        -- NXTDESC update on descriptor fetch (from axi_msg_ftchq_if)                           --
        ch_s2mm_nxtdesc_wren            : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                  --
                                                                                               --
        -- Current address of descriptor to fetch                                              --
        ch_s2mm_fetch_address           : out std_logic_vector                                     --
                                        (C_MAX_CHANNELS*C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                  --
        ch_s2mm_sg_idle                 : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                                            --
      --  bd_eq                       : out std_logic;  -- not needed

        


    );

end axi_msg_ftch_pntr;

-------------------------------------------------------------------------------
-- Architecture
-------------------------------------------------------------------------------
architecture implementation of axi_msg_ftch_pntr is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";



-------------------------------------------------------------------------------
-- Functions
-------------------------------------------------------------------------------

-- No Functions Declared

-------------------------------------------------------------------------------
-- Constants Declarations
-------------------------------------------------------------------------------

-- No Constants Declared

-------------------------------------------------------------------------------
-- Signal / Type Declarations
-------------------------------------------------------------------------------
signal first : std_logic;
signal eof_latch : std_logic;

signal ch1_s2mm_sg_idle_int : std_logic;

-------------------------------------------------------------------------------
-- Begin architecture logic
-------------------------------------------------------------------------------
begin

-- Channel 1 is included therefore generate pointer logic
GEN_PNTR_FOR_CH1 : if C_INCLUDE_CH1 = 1 generate
begin


GEN_PNTR_FOR_CHANNEL : for I in 0 to C_NUM_MM2S_CHANNELS-1 generate
begin

    MM2S_CH_PNTR : entity axi_mcdma_v1_2_2.axi_msg_channel_pntr
        generic map(
            C_M_AXI_SG_ADDR_WIDTH      => C_M_AXI_SG_ADDR_WIDTH
        )
        port map(
            m_axi_msg_aresetn => m_axi_msg_aresetn,
            m_axi_msg_aclk    => m_axi_msg_aclk,
            run_stop         => ch_mm2s_run_stop(I),
            desc_flush       => ch_mm2s_desc_flush(I),
            nxtdesc_wren     => ch_mm2s_nxtdesc_wren(I),
            curdesc          => ch_mm2s_curdesc((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I),
            nxtdesc          => nxtdesc,
            taildesc         => ch_mm2s_taildesc((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I),
            taildesc_wren    => ch_mm2s_taildesc_wren(I),
            tailpntr_enabled => ch_mm2s_tailpntr_enabled(I),
            fetch_address    => ch_mm2s_fetch_address((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I),
            sg_idle          => ch_mm2s_sg_idle(I)

        );

end generate GEN_PNTR_FOR_CHANNEL;

UNUSED_CHANNELS : if C_MAX_CHANNELS > C_NUM_MM2S_CHANNELS generate
begin


GEN_PNTR_FOR_CHANNEL : for I in C_NUM_MM2S_CHANNELS to C_MAX_CHANNELS-1 generate
begin

ch_mm2s_fetch_address((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I) <= (others => '0');
ch_mm2s_sg_idle(I) <= '1';

end generate GEN_PNTR_FOR_CHANNEL;
end generate UNUSED_CHANNELS;


end generate GEN_PNTR_FOR_CH1;


-- Channel 1 is NOT included therefore tie off pointer logic
GEN_NO_PNTR_FOR_CH1 : if C_INCLUDE_CH1 = 0 generate
begin
    ch_mm2s_fetch_address   <= (others =>'0');
    ch_mm2s_sg_idle         <= (others => '0');
end generate GEN_NO_PNTR_FOR_CH1;

-- Channel 2 is included therefore generate pointer logic
GEN_PNTR_FOR_CH2 : if C_INCLUDE_CH2 = 1 generate
begin


GEN_PNTR_FOR_CHANNEL : for I in 0 to C_NUM_S2MM_CHANNELS-1 generate
begin

    S2MM_CH_PNTR : entity axi_mcdma_v1_2_2.axi_msg_channel_pntr
        generic map(
            C_M_AXI_SG_ADDR_WIDTH      => C_M_AXI_SG_ADDR_WIDTH
        )
        port map(
            m_axi_msg_aresetn => m_axi_msg_aresetn,
            m_axi_msg_aclk    => m_axi_msg_aclk,
            run_stop         => ch_s2mm_run_stop(I),
            desc_flush       => ch_s2mm_desc_flush(I),
            nxtdesc_wren     => ch_s2mm_nxtdesc_wren(I),
            curdesc          => ch_s2mm_curdesc((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I),
            nxtdesc          => nxtdesc,
            taildesc         => ch_s2mm_taildesc((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I),
            taildesc_wren    => ch_s2mm_taildesc_wren(I),
            tailpntr_enabled => ch_s2mm_tailpntr_enabled(I),
            fetch_address    => ch_s2mm_fetch_address((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I),
            sg_idle          => ch_s2mm_sg_idle(I)

        );

end generate GEN_PNTR_FOR_CHANNEL;

UNUSED_CHANNELS : if C_MAX_CHANNELS > C_NUM_S2MM_CHANNELS generate
begin


GEN_PNTR_FOR_CHANNEL : for I in C_NUM_S2MM_CHANNELS to C_MAX_CHANNELS-1 generate
begin

ch_s2mm_fetch_address((C_M_AXI_SG_ADDR_WIDTH-1)+(C_M_AXI_SG_ADDR_WIDTH*I) downto C_M_AXI_SG_ADDR_WIDTH*I) <= (others => '0');
ch_s2mm_sg_idle(I) <= '1';

end generate GEN_PNTR_FOR_CHANNEL;
end generate UNUSED_CHANNELS;



end generate GEN_PNTR_FOR_CH2;


-- Channel 2 is NOT included therefore tie off pointer logic
GEN_NO_PNTR_FOR_CH2 : if C_INCLUDE_CH2 = 0 generate
begin
    ch_s2mm_fetch_address   <= (others =>'0');
    ch_s2mm_sg_idle         <= (others => '1');
end generate GEN_NO_PNTR_FOR_CH2;

end implementation;



