library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;
--use axi_mcdma_v1_2_2.axi_msg_afifo_autord.all;

-------------------------------------------------------------------------------
entity  axi_msg_ftch_fifo is
    generic (
       C_FAMILY                : string := "virtex7";
       CH_BASE                 : integer := 0;
       QUEUE_ELEMENTS          : integer := 10;
       C_FIELD                 : integer := 5
    );
      
    port (
       m_axi_msg_aclk : in std_logic;
       sinit         : in std_logic;
       data_in       : in std_logic;
       ch_wren       : out std_logic;
       ch_rden       : in std_logic;
       ch_empty       : out std_logic;
       ch_full       : out std_logic;
       ch_pause       : out std_logic;
       ch_desc_available       : out std_logic;
       ch_rd_valid       : out std_logic;
       ch_wraddr       : out std_logic_vector (8 downto 0);
       ch_rdaddr       : out std_logic_vector (8 downto 0)
 --      dcount         : out std_logic_vector (FETCH_QUEUE_CNT_WIDTH-1 downto 0)
     );
  
end axi_msg_ftch_fifo;

 
architecture implementation of axi_msg_ftch_fifo is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";


begin



-------------
-------------



CH_BMG_CTRL : entity axi_mcdma_v1_2_2.axi_msg_bmg_ctrl
    generic map (
       C_START_ADDR            => CH_BASE, 
       C_DEPTH                 => QUEUE_ELEMENTS,
       C_FIELD                 => C_FIELD
    )

    port map (
       m_axi_msg_aclk => m_axi_msg_aclk,
       sinit          => sinit,
       data_in        => data_in,
       wren           => ch_wren,
       rden           => ch_rden,
       bmg_empty      => ch_empty,
       bmg_full       => ch_full,
       bmg_pause      => ch_pause,
       desc_avail     => ch_desc_available,
       data_valid     => ch_rd_valid,
       wraddr         => ch_wraddr,
       rdaddr         => ch_rdaddr
     );




end implementation;



