-------------------------------------------------------------------------------
-- Filename:          axi_msg_ftch_queue.vhd
-- Description: This entity is the descriptor fetch queue interface
--
-- VHDL-Standard:   VHDL'93
-------------------------------------------------------------------------------
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;
--use axi_mcdma_v1_2_2.axi_msg_afifo_autord.all;

-------------------------------------------------------------------------------
entity  axi_msg_ftch_queue is
    generic (
        C_M_AXI_SG_ADDR_WIDTH       : integer range 32 to 64    := 32;
            -- Master AXI Memory Map Address Width

        C_M_AXIS_SG_TDATA_WIDTH     : integer range 32 to 32    := 32;
            -- Master AXI Stream Data width

        C_AXIS_IS_ASYNC             : integer range 0 to 1      := 0;
        C_WORDS_TO_WRITE            : integer range 1 to 16     := 5;
        C_ASYNC             : integer range 0 to 1      := 0;
            -- Channel 1 is async to sg_aclk
            -- 0 = Synchronous to SG ACLK
            -- 1 = Asynchronous to SG ACLK
        C_NUM_CHANNELS : integer range 1 to 16 := 8;
        C_MAX_CHANNELS : integer range 1 to 16 := 1;
        C_QUEUE_BD     : integer range 1 to 8 := 5;
        C_FAMILY                    : string            := "virtex7";
            -- Device family used for proper BRAM selection
        C_ENABLE_MULTI_CH_RESET  : integer range 0 to 1 := 0
    );
    port (
        -----------------------------------------------------------------------
        -- AXI Scatter Gather Interface
        -----------------------------------------------------------------------
        m_axi_msg_aclk               : in  std_logic                         ;                   --
        m_axi_primary_aclk          : in  std_logic                         ;
        m_axi_msg_aresetn            : in  std_logic                         ;                   --
        p_reset_n                   : in  std_logic                         ;
        soft_rst               : in std_logic_vector (C_NUM_CHANNELS-1 downto 0);
 
        ch2_sg_idle                 : in std_logic                          ;
        sof_ftch_desc               : in std_logic                          ;              
        channel_id_in               : in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
        cmplt_mask                  : in std_logic; 
        write_bd_fields             : in std_logic;

        -- MM2S Channel Control                                                                    --
        ch_desc_flush                  : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_cntrl_strm_stop          : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;
        ftch_active                 : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ftch_queue_empty            : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ftch_queue_full             : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ftch_pause                  : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --

        writing_nxtdesc_in          : in  std_logic                         ;                   --
        writing_curdesc_out         : out std_logic                         ;                   --

        -- DataMover Command                                                                    --^M
        ftch_cmnd_wr                : in  std_logic                         ;                   --^M
        ftch_cmnd_data              : in  std_logic_vector                                      --^M
                                        ((C_M_AXI_SG_ADDR_WIDTH+MSG_CMD_BASE_WIDTH)-1 downto 0);    --^M
                                                                                                --^M
        -- MM2S Stream In from DataMover                                                        --^M
        m_axis_mm2s_tdata           : in  std_logic_vector                                      --^M
                                        (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0) ;                  --^M
        m_axis_mm2s_tlast           : in  std_logic                         ;                   --^M
        m_axis_mm2s_tvalid          : in  std_logic                         ;                   --^M
        m_axis_mm2s_tready          : out std_logic                         ;                   --^M
                                                                                                --^M
                                                                                                --^M
        -- Channel 1 AXI Fetch Stream Out                                                       --^M
        m_axis_ftch_aclk            : in  std_logic                         ;                   --^M
        m_axis_ftch_tdata           : out std_logic_vector                                      --^M
                                        (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0);                   --^M
        m_axis_ftch_tvalid          : out std_logic                         ;                   --^M
        m_axis_ftch_data_valid          : out std_logic                         ;                   --^M
        m_axis_ftch_tready          : in  std_logic                         ;                   --^M
        m_axis_ftch_tlast           : out std_logic                         ;                    --^M
        m_axis_ftch_id              : out std_logic_vector (C_MAX_CHANNELS-1 downto 0);

        m_axis_mm2s_cntrl_tdata     : out std_logic_vector                                 --
                                        (31 downto 0);      --
        m_axis_mm2s_cntrl_tkeep     : out std_logic_vector                                 --
                                        (3 downto 0);  --
        m_axis_mm2s_cntrl_tvalid    : out std_logic                         ;              --
        m_axis_mm2s_cntrl_tready    : in  std_logic                         := '0';              --
        m_axis_mm2s_cntrl_tlast     : out std_logic                                       --

    );

end axi_msg_ftch_queue;

-------------------------------------------------------------------------------
-- Architecture
-------------------------------------------------------------------------------
architecture implementation of axi_msg_ftch_queue is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";


constant TO_WRITE : integer := C_WORDS_TO_WRITE;
constant QUEUE_ELEMENTS : integer := (TO_WRITE*C_QUEUE_BD); -- cant exceed 32
constant BASE : integer := 32;

-- Number of words deep fifo needs to be
-- 6 is subtracted as BD address are always 16 word aligned


-----------------

-------------------------------------------------------------------------------
-- Signal / Type Declarations
-------------------------------------------------------------------------------
-- Internal signals
signal curdesc_tdata            : std_logic_vector
                                    (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0) := (others => '0');
signal curdesc_tvalid           : std_logic := '0';
signal ftch_tvalid              : std_logic := '0';
signal ftch_tvalid_new         : std_logic := '0';
signal ftch_tdata               : std_logic_vector
                                    (31 downto 0) := (others => '0');
signal ftch_tdata_new_bd, reg2_bd_64, reg1_bd_64 : std_logic_vector (31 downto 0) := (others => '0');

