-- Begin architecture logic
-------------------------------------------------------------------------------
begin


channel_id_in_i <= channel_id_in;

intg1 <= func_ret_int(channel_id_in_i);
intg_f1 <= func_ret_int(ftch_active);
-- only one fectch is possbiel at a time
--any_ftch <= ftch8_active & ftch7_active & ftch6_active &
--            ftch5_active & ftch4_active & ftch3_active &
--            ftch2_active & ftch1_active;

SOF_DEL_PROCESS : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                sof_ftch_desc_del <= '0';
                intg <= 16;
                intg_f <= 16;
            else
                sof_ftch_desc_del <= sof_ftch_desc;
                intg <= intg1;
                intg_f <= intg_f1;  
            end if;
        end if;
   end process SOF_DEL_PROCESS;

SOF_DEL1_PROCESS : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0' or (m_axis_mm2s_tlast = '1' and m_axis_mm2s_tvalid = '1'))then
                sof_ftch_desc_del1 <= '0';
            elsif (m_axis_mm2s_tvalid = '1') then
                sof_ftch_desc_del1 <= sof_ftch_desc;
            end if;
        end if;
   end process SOF_DEL1_PROCESS;

sof_ftch_desc_pulse <= sof_ftch_desc and (not sof_ftch_desc_del1);

ftch_active_i <= or_reduce (ftch_active);

--ftch_active_i <= ftch1_active or ftch2_active or ftch3_active or
--               ftch4_active or ftch5_active or ftch6_active or
--               ftch7_active or ftch8_active;

---------------------------------------------------------------------------
-- Write current descriptor to FIFO or out channel port
---------------------------------------------------------------------------
ADDR_64: if C_M_AXI_SG_ADDR_WIDTH = 64 generate
begin
msb_curdesc <= ftch_cmnd_data(32+DATAMOVER_CMD_ADDRMSB_BOFST + DATAMOVER_CMD_ADDRLSB_BIT downto DATAMOVER_CMD_ADDRLSB_BIT+32);

end generate ADDR_64;


ADDR_32: if C_M_AXI_SG_ADDR_WIDTH = 32 generate
begin
msb_curdesc <= (others => '0');

end generate ADDR_32;

WRITE_CURDESC_PROCESS : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0' )then
                curdesc_tdata       <= (others => '0');
                curdesc_tvalid      <= '0';
                writing_lsb         <= '0';
                writing_msb         <= '0';

            -- Write LSB Address on command write
            elsif(ftch_cmnd_wr = '1' and ftch_active_i = '1')then
                curdesc_tdata       <= ftch_cmnd_data(DATAMOVER_CMD_ADDRMSB_BOFST
                                                        + DATAMOVER_CMD_ADDRLSB_BIT
                                                        downto DATAMOVER_CMD_ADDRLSB_BIT);
                curdesc_tvalid      <= '1';
                writing_lsb         <= '1';
                writing_msb         <= '0';

            -- On ready write MSB address
            elsif(writing_lsb = '1' and ftch_tready = '1')then
                curdesc_tdata       <= msb_curdesc;
                curdesc_tvalid      <= '1';
                writing_lsb         <= '0';
                writing_msb         <= '1';

            -- On MSB write and ready then clear all
            elsif(writing_msb = '1' and ftch_tready = '1')then
                curdesc_tdata       <= (others => '0');
                curdesc_tvalid      <= '0';
                writing_lsb         <= '0';
                writing_msb         <= '0';

            end if;
        end if;
    end process WRITE_CURDESC_PROCESS;

---------------------------------------------------------------------------
-- TVALID MUX
-- MUX tvalid out channel port
---------------------------------------------------------------------------
TVALID_TDATA_MUX : process(writing_curdesc,
                                writing_nxtdesc,
                                ftch_active_i,
                                curdesc_tvalid,
                                curdesc_tdata,
                                write_bd_fields, 
                                m_axis_mm2s_tvalid,
                                m_axis_mm2s_tdata,
				cmplt_mask,
                                m_axis_mm2s_tlast)
    begin
        -- Select current descriptor to drive out (Queue or Channel Port)
        if(writing_curdesc = '1')then
            ftch_tvalid  <= curdesc_tvalid;
            ftch_tdata   <= curdesc_tdata;
            ftch_tlast   <= '0';
        -- Deassert tvalid when capturing next descriptor pointer
        elsif(writing_nxtdesc = '1')then
            ftch_tvalid  <= '0';
            ftch_tdata   <= (others => '0');
            ftch_tlast   <= '0';
        -- Otherwise drive data from Datamover out (Queue or Channel Port)
        elsif(ftch_active_i = '1')then
            ftch_tvalid  <= write_bd_fields and m_axis_mm2s_tvalid;
            ftch_tdata (31)   <= m_axis_mm2s_tdata (31) and cmplt_mask; -- mask the complete bit for cyclic
            ftch_tdata (30 downto 0)   <= m_axis_mm2s_tdata (30 downto 0);
            ftch_tlast   <= m_axis_mm2s_tlast;
        else
            ftch_tvalid  <= '0';
            ftch_tdata   <= (others => '0');
            ftch_tlast   <= '0';
        end if;
    end process TVALID_TDATA_MUX;

         queue_full(C_MAX_CHANNELS) <= '0';

         queue_full_tready <= queue_full(intg_f); --func_ret_int(ftch_active));

--process (ftch_active) --any_ftch)
--begin
--         queue_full_tready <= '0';

--   case ftch_active(7 downto 0) is --any_ftch is
--     when "00000001" =>
-- -        queue_full_tready <= queue_full(0);
--     when "00000010" =>
--         queue_full_tready <= queue_full(1);
--     when "00000100" =>
--         queue_full_tready <= queue_full(2);
--     when "00001000" =>
--         queue_full_tready <= queue_full(3);
--     when "00010000" =>
--         queue_full_tready <= queue_full(4);
--     when "00100000" =>
--         queue_full_tready <= queue_full(5);
--     when "01000000" =>
--         queue_full_tready <= queue_full(6);
--     when "10000000" =>
--         queue_full_tready <= queue_full(7);

--     when others =>
--         queue_full_tready <= '0';

--   end case; 

--end process;

-- Drive tready with fifo not full
ftch_tready <= not queue_full_tready;

-- Drive out to datamover
m_axis_mm2s_tready <= ftch_tready;

-- Build FIFO data in, appending tlast bit
queue_din(C_M_AXIS_SG_TDATA_WIDTH)               <= ftch_tlast;
queue_din(C_M_AXIS_SG_TDATA_WIDTH-1 downto 0)    <= ftch_tdata;



-- drive valid if fifo is not empty
          ch_desc_avail (C_MAX_CHANNELS) <= '0';
          ch_rd_valid (C_MAX_CHANNELS) <= '0';

          m_axis_ftch_tvalid  <= ch_desc_avail(intg); --func_ret_int(channel_id_in_i)); --not queue_empty1;
          m_axis_ftch_data_valid <= ch_rd_valid(intg); --func_ret_int(channel_id_in_i));

--process (channel_id_in_i, ch_desc_avail, ch_rd_valid) 
--                        
--                        
--
--begin
--
--          m_axis_ftch_tvalid  <= '0';
--    --      m_axis_ftch_id <= (others => '0');
--          m_axis_ftch_data_valid <= '0';
--
--    case (channel_id_in_i) is
--      when "00000001" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(0); --not queue_empty1;
--          m_axis_ftch_data_valid <= ch_rd_valid(0);
--   --       m_axis_ftch_id <= "00000001";
--      when "00000010" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(1); --not queue_empty2;
--          m_axis_ftch_data_valid <= ch_rd_valid(1);
--   --       m_axis_ftch_id <= "00000010";
--      when "00000100" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(2); --not queue_empty3;
--          m_axis_ftch_data_valid <= ch_rd_valid(2);
--   --       m_axis_ftch_id <= "00000100";
--      when "00001000" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(3); --not queue_empty4;
--          m_axis_ftch_data_valid <= ch_rd_valid(3);
--   --       m_axis_ftch_id <= "00001000";
--      when "00010000" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(4); --not queue_empty5;
--          m_axis_ftch_data_valid <= ch_rd_valid(4);
--   --       m_axis_ftch_id <= "00010000";
--      when "00100000" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(5); --not queue_empty6;
--          m_axis_ftch_data_valid <= ch_rd_valid(5);
--   --       m_axis_ftch_id <= "00100000";
--      when "01000000" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(6); --not queue_empty7;
--          m_axis_ftch_data_valid <= ch_rd_valid(6);
--   --       m_axis_ftch_id <= "01000000";
--      when "10000000" =>
--          m_axis_ftch_tvalid  <= ch_desc_avail(7); --not queue_empty8;
--          m_axis_ftch_data_valid <= ch_rd_valid(7);
--   --       m_axis_ftch_id <= "10000000";
--      when others =>
--          m_axis_ftch_tvalid  <= '0';
--          m_axis_ftch_data_valid <=  '0';
--   --       m_axis_ftch_id <= "00000000";
--    end case;
--end process;


ID_PROCESS : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
               m_axis_ftch_id <= (others => '0');
            else
               m_axis_ftch_id <= channel_id_in_i;
            end if;
        end if;
end process ID_PROCESS;
          


          m_axis_ftch_tlast   <= data_out(C_M_AXIS_SG_TDATA_WIDTH);
          m_axis_ftch_tdata   <= data_out(C_M_AXIS_SG_TDATA_WIDTH-1 downto 0);


process (channel_id_in_i, m_axis_ftch_tready)
begin

         m_axis_ftch_tready_i <= (others => '0');

    case (channel_id_in_i(15 downto 0)) is
      when "0000000000000001" =>
         m_axis_ftch_tready_i(0) <= m_axis_ftch_tready;
      when "0000000000000010" =>
         m_axis_ftch_tready_i(1) <= m_axis_ftch_tready;
      when "0000000000000100" =>
         m_axis_ftch_tready_i(2) <= m_axis_ftch_tready;
      when "0000000000001000" =>
         m_axis_ftch_tready_i(3) <= m_axis_ftch_tready;
      when "0000000000010000" =>
         m_axis_ftch_tready_i(4) <= m_axis_ftch_tready;
      when "0000000000100000" =>
         m_axis_ftch_tready_i(5) <= m_axis_ftch_tready;
      when "0000000001000000" =>
         m_axis_ftch_tready_i(6) <= m_axis_ftch_tready;
      when "0000000010000000" =>
         m_axis_ftch_tready_i(7) <= m_axis_ftch_tready;
      when "0000000100000000" =>
         m_axis_ftch_tready_i(8) <= m_axis_ftch_tready;
      when "0000001000000000" =>
         m_axis_ftch_tready_i(9) <= m_axis_ftch_tready;
      when "0000010000000000" =>
         m_axis_ftch_tready_i(10) <= m_axis_ftch_tready;
      when "0000100000000000" =>
         m_axis_ftch_tready_i(11) <= m_axis_ftch_tready;
      when "0001000000000000" =>
         m_axis_ftch_tready_i(12) <= m_axis_ftch_tready;
      when "0010000000000000" =>
         m_axis_ftch_tready_i(13) <= m_axis_ftch_tready;
      when "0100000000000000" =>
         m_axis_ftch_tready_i(14) <= m_axis_ftch_tready;
      when "1000000000000000" =>
         m_axis_ftch_tready_i(15) <= m_axis_ftch_tready;
      when others =>
         m_axis_ftch_tready_i <= (others => '0');
    end case;
end process;



-- If writing curdesc out then flag for proper mux selection
writing_curdesc     <= curdesc_tvalid;
-- Map intnal signal to port
writing_curdesc_out <= writing_curdesc;
-- Map port to internal signal
writing_nxtdesc     <= writing_nxtdesc_in;



I_FTCH_BRAM : entity axi_mcdma_v1_2_2.axi_msg_bmg
    generic map (
        C_FAMILY                =>  C_FAMILY
    )
    port map (
    clka => m_axi_msg_aclk,
    wea  => wrbram,
    addra => wraddr,
    dina => queue_din,
    clkb => m_axi_msg_aclk,
    enb =>  m_axis_ftch_tready,
    regceb  => '1',
    addrb => rdaddr,
    doutb => data_out
              );

