-- each FIFO stores upto 2 BDs

BMG_CTRL_INST : for I in 0 to C_NUM_CHANNELS-1 generate

begin

    I_CH_FTCH_FIFO : entity axi_mcdma_v1_2_2.axi_msg_ftch_fifo
    generic map (
       C_FAMILY                => C_FAMILY,
       CH_BASE                 => BASE*I,
       QUEUE_ELEMENTS          => QUEUE_ELEMENTS,
       C_FIELD                 => TO_WRITE
    )

    port map (
       m_axi_msg_aclk => m_axi_msg_aclk,
       sinit         => queue_sinit(I), 
       data_in       => queue_wren(I),
       ch_wren       => ch_bmg_wren(I),
       ch_rden       => queue_rden(I),
       ch_empty      => ftch_queue_empty(I),
       ch_full       => queue_full (I), --ftch_queue_full(I),
       ch_pause      => ftch_pause(I),
       ch_desc_available => ch_desc_avail(I),
       ch_rd_valid       => ch_rd_valid(I),
       ch_wraddr       => ch_wraddr(9*I+9-1 downto 9*I),
       ch_rdaddr       => ch_rdaddr(9*I+9-1 downto 9*I)
     );

queue_multi_rst: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
queue_sinit(I) <= ch_desc_flush(I) or not m_axi_msg_aresetn or soft_rst(I);
end generate queue_multi_rst;

queue_single_rst: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
queue_sinit(I) <= ch_desc_flush(I) or not m_axi_msg_aresetn;
end generate queue_single_rst;

-- Write to fifo if it is not full and data is valid
--queue_wren1  <= not queue_full1 and ftch_tvalid and ftch1_active;-- and write_bd_fields;
queue_wren(I)  <= ftch_tvalid and ftch_active(I);-- and write_bd_fields;

--ftch1_queue_empty <= queue_empty1;
--'1' when queue_dcount1 = ZERO_COUNT and queue_wren1 = '0'
--               else '0';
ftch_queue_full(I)     <= queue_full(I);
--ftch1_pause <= '0';
--'1' when queue_dcount1(DCNT_HI_INDEX
--                             downto DCNT_LO_INDEX) >= SG_FTCH_DESC2QUEUE_VECT
--         else '0';
--queue_rden1  <= not queue_empty1
--               and m_axis_ftch_tready_1;
              -- and ftch1_active;
queue_rden(I) <= m_axis_ftch_tready_i(I);



end generate BMG_CTRL_INST;

UNUSED_CHANNELS: if C_MAX_CHANNELS > C_NUM_CHANNELS generate
begin

BMG_CTRL_INST : for I in C_NUM_CHANNELS to C_MAX_CHANNELS-1 generate
begin

ftch_queue_empty(I) <= '0';
ftch_queue_full(I) <= '1';
ftch_pause(I) <= '1';
ch_desc_avail(I) <= '0';
ch_rd_valid(I) <= '0';
ch_wraddr(9*I+9-1 downto 9*I) <= (others => '0');
ch_rdaddr(9*I+9-1 downto 9*I) <= (others => '0');
queue_full(I) <= '0';
ch_bmg_wren(I) <= '0';

end generate BMG_CTRL_INST;
end generate UNUSED_CHANNELS;



end implementation;



