-- Filename:          axi_msg_ftch_queue.vhd
-- Description: This entity is the descriptor fetch queue interface
--
-- VHDL-Standard:   VHDL'93
-------------------------------------------------------------------------------
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;

-------------------------------------------------------------------------------
entity  axi_msg_ftch_q_mngr is
    generic (
        C_M_AXI_SG_ADDR_WIDTH       : integer range 32 to 64    := 32;
            -- Master AXI Memory Map Address Width

        C_M_AXIS_SG_TDATA_WIDTH     : integer range 32 to 32    := 32;
            -- Master AXI Stream Data width

        C_AXIS_IS_ASYNC             : integer range 0 to 1      := 0;
            -- Channel 1 is async to sg_aclk
            -- 0 = Synchronous to SG ACLK
            -- 1 = Asynchronous to SG ACLK

        C_ASYNC             : integer range 0 to 1      := 0;
            -- Channel 1 is async to sg_aclk
            -- 0 = Synchronous to SG ACLK
            -- 1 = Asynchronous to SG ACLK

        C_SG_FTCH_DESC2QUEUE        : integer range 0 to 8         := 0;
            -- Number of descriptors to fetch and queue for each channel.
            -- A value of zero excludes the fetch queues.
        C_ENABLE_MULTI_CHANNEL      : integer range 0 to 1          := 0;

        C_SG_CH1_WORDS_TO_FETCH         : integer range 4 to 16     := 8;
            -- Number of words to fetch for channel 1

        C_SG_CH2_WORDS_TO_FETCH         : integer range 4 to 16     := 8;
            -- Number of words to fetch for channel 1

        C_SG_CH1_ENBL_STALE_ERROR   : integer range 0 to 1          := 1;
            -- Enable or disable stale descriptor check
            -- 0 = Disable stale descriptor error check
            -- 1 = Enable stale descriptor error check

        C_SG_CH2_ENBL_STALE_ERROR   : integer range 0 to 1          := 1;
            -- Enable or disable stale descriptor check
            -- 0 = Disable stale descriptor error check
            -- 1 = Enable stale descriptor error check

        C_INCLUDE_CH1               : integer range 0 to 1          := 1;
            -- Include or Exclude channel 1 scatter gather engine
            -- 0 = Exclude Channel 1 SG Engine
            -- 1 = Include Channel 1 SG Engine


        C_INCLUDE_CH2               : integer range 0 to 1          := 1;
            -- Include or Exclude channel 2 scatter gather engine
            -- 0 = Exclude Channel 2 SG Engine
            -- 1 = Include Channel 2 SG Engine
        C_ENABLE_CDMA               : integer range 0 to 1          := 0;

        C_ACTUAL_ADDR               : integer range 32 to 64        := 32;
        C_NUM_MM2S_CHANNELS         : integer range 1 to 16          := 1;
        C_NUM_S2MM_CHANNELS         : integer range 1 to 16          := 1;
        C_MAX_CHANNELS              : integer range 1 to 16         := 1;
	C_SUPPORT_CYCLIC_BD	   : integer range 0 to 1 := 0;

        C_FAMILY                    : string            := "virtex7";
            -- Device family used for proper BRAM selection
        C_ENABLE_MULTI_CH_RESET     : integer range 0 to 1 := 0
    );
    port (
        -----------------------------------------------------------------------
        -- AXI Scatter Gather Interface
        -----------------------------------------------------------------------
        m_axi_msg_aclk               : in  std_logic                         ;                   --
        m_axi_mm2s_aclk               : in  std_logic                         ;                   --
        m_axi_msg_aresetn            : in  std_logic                         ;                   --
        p_reset_n                   : in  std_logic                         ;
        soft_rst_mm2s               : in std_logic_vector (C_NUM_MM2S_CHANNELS-1 downto 0) ;
        soft_rst_s2mm               : in std_logic_vector (C_NUM_S2MM_CHANNELS-1 downto 0);        
        ch2_sg_idle                 : in std_logic                          ;

        -- MM2S Channel 1 Control                                                                    --
        ch_mm2s_desc_flush              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_cyclic                  : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_cntrl_strm_stop         : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;
        ch_mm2s_ftch_active             : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_nxtdesc_wren            : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_queue_empty        : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_queue_full         : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_mm2s_ftch_pause              : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --


        s2mm_channel_id_ftch             : in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
        mm2s_channel_id_ftch             : in std_logic_vector (C_MAX_CHANNELS-1 downto 0);

        -- S2MM Channel 1 Control                                                                    --
        ch_s2mm_desc_flush              : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_cyclic                  : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_active             : in  std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_nxtdesc_wren            : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_queue_empty        : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_queue_full         : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --
        ch_s2mm_ftch_pause              : out std_logic_vector (C_MAX_CHANNELS-1 downto 0)                         ;                   --

        mm2s_ftch_active                 : in std_logic                          ;
        mm2s_channel_ftch                : in std_logic_vector (C_MAX_CHANNELS-1 downto 0);

        s2mm_ftch_active                 : in std_logic                          ;
        s2mm_channel_ftch                : in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
                                                                                                --
        nxtdesc                     : out std_logic_vector                                      --
                                        (C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                   --
        -- DataMover Command                                                                    --
        ftch_cmnd_wr                : in  std_logic                         ;                   --
        ftch_cmnd_data              : in  std_logic_vector                                      --
                                        ((C_M_AXI_SG_ADDR_WIDTH+MSG_CMD_BASE_WIDTH)-1 downto 0);    --
        ftch_stale_desc             : out std_logic                         ;                   --
                                                                                                --
        -- MM2S Stream In from DataMover                                                        --
        m_axis_mm2s_tdata           : in  std_logic_vector                                      --
                                        (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0) ;                  --
        m_axis_mm2s_tkeep           : in  std_logic_vector                                      --
                                        ((C_M_AXIS_SG_TDATA_WIDTH/8)-1 downto 0);               --
        m_axis_mm2s_tlast           : in  std_logic                         ;                   --
        m_axis_mm2s_tvalid          : in  std_logic                         ;                   --
        m_axis_mm2s_tready          : out std_logic                         ;                   --

                                                                                                --
                                                                                                --
        -- Channel 1 AXI Fetch Stream Out                                                       --
        m_axis_ch1_ftch_aclk        : in  std_logic                         ;
        m_axis_ch1_ftch_tdata       : out std_logic_vector                                      --
                                        (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0);                   --
        m_axis_ch1_ftch_tvalid      : out std_logic                         ;                   --
        m_axis_ch1_ftch_data_valid      : out std_logic                         ;                   --
        m_axis_ch1_ftch_tready      : in  std_logic                         ;                   --
        m_axis_ch1_ftch_tlast       : out std_logic                         ;                   --
        m_axis_ch1_ftch_id          : out std_logic_vector (C_MAX_CHANNELS-1 downto 0);

                                                                                               --
        -- Channel 2 AXI Fetch Stream Out                                                       --
        m_axis_ch2_ftch_aclk        : in  std_logic                         ;                   --
        m_axis_ch2_ftch_tdata       : out std_logic_vector                                      --
                                        (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0) ;                  --
        m_axis_ch2_ftch_tvalid      : out std_logic                         ;                   --
        m_axis_ch2_ftch_data_valid      : out std_logic                         ;                   --
        m_axis_ch2_ftch_tready      : in  std_logic                         ;                   --
        m_axis_ch2_ftch_tlast       : out std_logic                         ;                    --
        m_axis_ch2_ftch_id          : out std_logic_vector (C_MAX_CHANNELS-1 downto 0);

        m_axis_mm2s_cntrl_tdata     : out std_logic_vector                                 --
                                        (31 downto 0);      --
        m_axis_mm2s_cntrl_tkeep     : out std_logic_vector                                 --
                                        (3 downto 0);  --
        m_axis_mm2s_cntrl_tvalid    : out std_logic                         ;              --
        m_axis_mm2s_cntrl_tready    : in  std_logic                         := '0';              --
        m_axis_mm2s_cntrl_tlast     : out std_logic                                       --


    );

end axi_msg_ftch_q_mngr;

-------------------------------------------------------------------------------
-- Architecture
-------------------------------------------------------------------------------
architecture implementation of axi_msg_ftch_q_mngr is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";

-------------------------------------------------------------------------------
-- Functions
-------------------------------------------------------------------------------

  function width_calc (value_in : integer)
                     return integer is
  variable addr_value : integer := 4;

  begin
      if (value_in > 8) then
          addr_value := 2;
      else
          addr_value := 4;
      end if;

      return(addr_value);

end function width_calc;



-- No Functions Declared

-------------------------------------------------------------------------------
-- Constants Declarations
-------------------------------------------------------------------------------
constant MM2S_LAST : integer := (7+C_SG_CH1_WORDS_TO_FETCH-8);
constant S2MM_WORDS_TO_WRITE : integer := (5+((C_M_AXI_SG_ADDR_WIDTH-32)/32));
constant MM2S_WORDS_TO_WRITE : integer := (6+((C_M_AXI_SG_ADDR_WIDTH-32)/32)+C_SG_CH1_WORDS_TO_FETCH-8);
constant S2MM_BD_QUEUE : integer := 5;
constant MM2S_BD_QUEUE : integer := width_calc(C_SG_CH1_WORDS_TO_FETCH);

-- Determine the maximum word count for use in setting the word counter width
-- Set bit width on max num words to fetch

constant FETCH_COUNT            : integer := max2(C_SG_CH1_WORDS_TO_FETCH
                                                 ,C_SG_CH2_WORDS_TO_FETCH);
-- LOG2 to get width of counter
constant WORDS2FETCH_BITWIDTH   : integer := clog2(FETCH_COUNT);
-- Zero value for counter
constant WORD_ZERO              : std_logic_vector(WORDS2FETCH_BITWIDTH-1 downto 0)
                                    := (others => '0');
-- One value for counter
constant WORD_ONE               : std_logic_vector(WORDS2FETCH_BITWIDTH-1 downto 0)
                                    := std_logic_vector(to_unsigned(1,WORDS2FETCH_BITWIDTH));
-- Seven value for counter
constant WORD_SEVEN             : std_logic_vector(WORDS2FETCH_BITWIDTH-1 downto 0)
                                    := std_logic_vector(to_unsigned(7,WORDS2FETCH_BITWIDTH));

-- Seven value for counter
constant WORD_SIX             : std_logic_vector(WORDS2FETCH_BITWIDTH-1 downto 0)
                                    := std_logic_vector(to_unsigned(6,WORDS2FETCH_BITWIDTH));


constant USE_LOGIC_FIFOS        : integer   := 0; -- Use Logic FIFOs
constant USE_BRAM_FIFOS         : integer   := 1; -- Use BRAM FIFOs


-------------------------------------------------------------------------------
-- Signal / Type Declarations
-------------------------------------------------------------------------------
signal m_axis_mm2s_tready_i     : std_logic := '0';
signal ch1_ftch_tready          : std_logic := '0';
signal ch2_ftch_tready          : std_logic := '0';

-- Misc Signals
signal writing_curdesc          : std_logic := '0';
signal fetch_word_count         : std_logic_vector
                                    (WORDS2FETCH_BITWIDTH-1 downto 0) := (others => '0');
signal fetch_word_shift         : std_logic_vector (FETCH_COUNT-1 downto 0);
signal msb_curdesc              : std_logic_vector(31 downto 0) := (others => '0');

signal lsbnxtdesc_tready        : std_logic := '0';
signal msbnxtdesc_tready        : std_logic := '0';
signal nxtdesc_tready           : std_logic := '0';

signal ch1_writing_curdesc      : std_logic := '0';
signal ch2_writing_curdesc      : std_logic := '0';
signal m_axis_ch2_ftch_tvalid_1 : std_logic := '0';

-- KAPIL
signal ch_desc_flush : std_logic := '0';
signal m_axis_ch_ftch_tready : std_logic := '0';
signal ch_ftch_queue_empty : std_logic := '0';
signal ch_ftch_queue_full : std_logic := '0';
signal ch_ftch_pause : std_logic := '0';
signal ch_writing_curdesc : std_logic := '0';
signal ch_ftch_tready : std_logic := '0';
signal m_axis_ch_ftch_tdata : std_logic_vector (C_M_AXIS_SG_TDATA_WIDTH-1 downto 0) := (others => '0');
signal m_axis_ch_ftch_tvalid : std_logic := '0';
signal m_axis_ch_ftch_tlast : std_logic := '0';

signal next_bd : std_logic_vector (31 downto 0) := (others => '0');
 
signal sof_ftch_desc : std_logic;   

signal nxtdesc_int                     : std_logic_vector                                      --
                                        (C_M_AXI_SG_ADDR_WIDTH-1 downto 0)  ;                   --


signal ch_s2mm_flush_active : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal ch_mm2s_flush_active : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal ch_s2mm_flush_active_i  : std_logic;
signal ch_mm2s_flush_active_i  : std_logic;


signal write_fields_s2mm : std_logic;
signal mask_s2mm_cmplt   : std_logic;
signal mask_mm2s_cmplt   : std_logic;
signal write_fields_mm2s : std_logic;
signal mcdma_tlast : std_logic;
signal mcdma_tlast_mm2s : std_logic;
signal s2mm_nxtdesc_wren :std_logic;
signal mm2s_nxtdesc_wren :std_logic;

signal ch_s2mm_ftch_active_i : std_logic_vector (C_MAX_CHANNELS-1 downto 0);
signal ch_mm2s_ftch_active_i : std_logic_vector (C_MAX_CHANNELS-1 downto 0);

signal nxtdesc_i : std_logic_vector (31 downto 0);
signal mm2s_cyclic : std_logic;
signal s2mm_cyclic : std_logic;

function or_reduce(slv : std_logic_vector) return std_logic is
    variable r : std_logic := '0';
begin
    for i in slv'range loop
        r := r or slv(i);
    end loop;
    return r;
end or_reduce;

  
-------------------------------------------------------------------------------
-- Begin architecture logic
-------------------------------------------------------------------------------
begin

FTCH_ACTIVE: for I in 0 to C_MAX_CHANNELS-1 generate
begin

ch_s2mm_ftch_active_i(I) <= ch_s2mm_ftch_active(I);--s2mm_channel_ftch(I);
ch_s2mm_nxtdesc_wren(I) <= s2mm_nxtdesc_wren and ch_s2mm_ftch_active(I);--s2mm_channel_ftch (I); --ch1_s2mm_ftch_active;
ch_s2mm_flush_active(I) <= ch_s2mm_desc_flush(I) and ch_s2mm_ftch_active(I);


ch_mm2s_ftch_active_i(I) <= ch_mm2s_ftch_active(I);--s2mm_channel_ftch(I);
ch_mm2s_nxtdesc_wren(I) <= mm2s_nxtdesc_wren and ch_mm2s_ftch_active(I);--s2mm_channel_ftch (I); --ch1_s2mm_ftch_active;
ch_mm2s_flush_active(I) <= ch_mm2s_desc_flush(I) and ch_mm2s_ftch_active(I);

end generate FTCH_ACTIVE;


---------------------------------------------------------------------------
-- For 32-bit SG addresses then drive zero on msb
---------------------------------------------------------------------------
GEN_CURDESC_32 : if C_M_AXI_SG_ADDR_WIDTH = 32 generate
begin
    msb_curdesc <= (others => '0');
end generate  GEN_CURDESC_32;

---------------------------------------------------------------------------
-- For 64-bit SG addresses then capture upper order adder to msb
---------------------------------------------------------------------------
GEN_CURDESC_64 : if C_M_AXI_SG_ADDR_WIDTH = 64 generate
begin
    CAPTURE_CURADDR : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0')then
                    msb_curdesc <= (others => '0');
                elsif(ftch_cmnd_wr = '1')then
                    msb_curdesc <= ftch_cmnd_data(DATAMOVER_CMD_ADDRMSB_BOFST
                                                    + C_M_AXI_SG_ADDR_WIDTH
                                                    downto DATAMOVER_CMD_ADDRMSB_BOFST
                                                    + DATAMOVER_CMD_ADDRLSB_BIT + 1);
                end if;
            end if;
        end process CAPTURE_CURADDR;
end generate  GEN_CURDESC_64;

-------------------------------------------------------------------------------
-- Fetch Stream Word Counter
-- The process is used to determine when to strip off NextDesc pointer from
-- stream and when to look at control word for complete bit set.
-------------------------------------------------------------------------------
REG_WORD_COUNTER : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            -- Clear on reset and on datamover command write
            if(m_axi_msg_aresetn = '0' or ftch_cmnd_wr = '1'
            or (m_axis_mm2s_tlast = '1' and m_axis_mm2s_tvalid = '1' and m_axis_mm2s_tready_i = '1'))then
                fetch_word_count  <= (others => '0');
                fetch_word_shift (0) <= '1';
                fetch_word_shift (FETCH_COUNT-1 downto 1) <= (others => '0');
            -- If both tvalid=1 and tready = 1 then count
            elsif(m_axis_mm2s_tvalid = '1' and m_axis_mm2s_tready_i = '1')then
                fetch_word_count <= std_logic_vector(unsigned(fetch_word_count
                                        (WORDS2FETCH_BITWIDTH-1 downto 0)) + 1);
                fetch_word_shift (0) <= '0';
                fetch_word_shift (FETCH_COUNT-1 downto 1) <= fetch_word_shift (FETCH_COUNT-2 downto 0);
            end if;
        end if;
    end process REG_WORD_COUNTER;

mcdma_tlast <= (m_axis_mm2s_tvalid and m_axis_mm2s_tready_i and fetch_word_shift (6));
mcdma_tlast_mm2s <= (m_axis_mm2s_tvalid and m_axis_mm2s_tready_i and fetch_word_shift (MM2S_LAST));

   SOF_CHECK : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0' )then
                    sof_ftch_desc <= '0';
                -- On valid and word count at 0 and channel active capture LSB next pointer
                elsif(m_axis_mm2s_tvalid = '1' and fetch_word_count = WORD_SIX
                and m_axis_mm2s_tready_i = '1'
                and m_axis_mm2s_tdata(27) = '1')then
                    sof_ftch_desc <= '1';
                else
                    sof_ftch_desc <= '0';
                end if;
            end if;
        end process SOF_CHECK;

---------------------------------------------------------------------------
-- Write lower order Next Descriptor Pointer out to pntr_mngr
---------------------------------------------------------------------------
REG_LSB_NXTPNTR : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0' )then
                nxtdesc(31 downto 0)    <= (others => '0');

            -- On valid and word count at 0 and channel active capture LSB next pointer
            elsif(m_axis_mm2s_tvalid = '1' and fetch_word_count = WORD_ZERO)then
                nxtdesc(31 downto 0)    <= m_axis_mm2s_tdata;

            end if;
        end if;
    end process REG_LSB_NXTPNTR;

lsbnxtdesc_tready <= '1' when m_axis_mm2s_tvalid = '1'
                          and fetch_word_count = WORD_ZERO
                    else '0';

---------------------------------------------------------------------------
-- 64 Bit Scatter Gather addresses enabled
---------------------------------------------------------------------------
GEN_UPPER_MSB_NXTDESC : if C_M_AXI_SG_ADDR_WIDTH = 64 generate
begin
  
    write_fields_s2mm <= fetch_word_shift (2) or fetch_word_shift (3) or fetch_word_shift (5) or fetch_word_shift (6);

MM2S_NO_CTRL: if C_SG_CH1_WORDS_TO_FETCH = 8 generate
begin
    write_fields_mm2s <= fetch_word_shift (2) or fetch_word_shift (3) or fetch_word_shift (5) or fetch_word_shift (6) or fetch_word_shift (MM2S_LAST);

end generate MM2S_NO_CTRL;


MM2S_CTRL: if C_SG_CH1_WORDS_TO_FETCH = 13 generate
begin
    write_fields_mm2s <= fetch_word_shift (2) or fetch_word_shift (3) or fetch_word_shift (5) or fetch_word_shift (6) or
                         fetch_word_shift (7) or fetch_word_shift (8) or fetch_word_shift (9) or fetch_word_shift (10) or
                         fetch_word_shift (11) or fetch_word_shift (MM2S_LAST);

end generate MM2S_CTRL;

    ---------------------------------------------------------------------------
    -- Write upper order Next Descriptor Pointer out to pntr_mngr
    ---------------------------------------------------------------------------
    REG_MSB_NXTPNTR : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0' )then
                    nxtdesc_i(C_ACTUAL_ADDR-32-1 downto 0)   <= (others => '0');
                    s2mm_nxtdesc_wren <= '0';
                    mm2s_nxtdesc_wren <= '0';

                -- Capture upper pointer, drive ready to progress DataMover
                -- and also write nxtdesc out
                elsif(m_axis_mm2s_tvalid = '1' and fetch_word_count = WORD_ONE)then
                    nxtdesc_i(C_ACTUAL_ADDR-32-1 downto 0)   <= m_axis_mm2s_tdata(C_ACTUAL_ADDR-32-1 downto 0);
                    
                    s2mm_nxtdesc_wren <= s2mm_ftch_active;
                    mm2s_nxtdesc_wren <= mm2s_ftch_active;
                -- Assert tready/wren for only 1 clock
                else
                s2mm_nxtdesc_wren <= '0';
                mm2s_nxtdesc_wren <= '0';
                end if;
            end if;
        end process REG_MSB_NXTPNTR;

    msbnxtdesc_tready <= '1' when m_axis_mm2s_tvalid = '1'
                              and fetch_word_count = WORD_ONE
                        else '0';

nxtdesc(C_ACTUAL_ADDR-1 downto 32) <= nxtdesc_i (C_ACTUAL_ADDR-32-1 downto 0); 

UNUSED_MSB: if C_ACTUAL_ADDR /= C_M_AXI_SG_ADDR_WIDTH generate
begin

nxtdesc(63 downto C_ACTUAL_ADDR) <= (others => '0');

end generate UNUSED_MSB;




end generate GEN_UPPER_MSB_NXTDESC;

---------------------------------------------------------------------------
-- 32 Bit Scatter Gather addresses enabled
---------------------------------------------------------------------------
GEN_NO_UPR_MSB_NXTDESC : if C_M_AXI_SG_ADDR_WIDTH = 32 generate
begin


    write_fields_s2mm <= fetch_word_shift (2) or fetch_word_shift (5) or fetch_word_shift (6);

MM2S_NO_CTRL: if C_SG_CH1_WORDS_TO_FETCH = 8 generate
begin
    write_fields_mm2s <= fetch_word_shift (2) or fetch_word_shift (5) or fetch_word_shift (6) or fetch_word_shift (MM2S_LAST);

end generate MM2S_NO_CTRL;


MM2S_CTRL: if C_SG_CH1_WORDS_TO_FETCH = 13 generate
begin
    write_fields_mm2s <= fetch_word_shift (2) or fetch_word_shift (5) or fetch_word_shift (6) or 
                         fetch_word_shift (7) or fetch_word_shift (8) or fetch_word_shift (9) or fetch_word_shift (10) or
                         fetch_word_shift (11) or fetch_word_shift (MM2S_LAST);

end generate MM2S_CTRL;

    -----------------------------------------------------------------------
    -- No upper order therefore dump fetched word and write pntr lower next
    -- pointer to pntr mngr
    -----------------------------------------------------------------------
    REG_MSB_NXTPNTR : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0' )then
                s2mm_nxtdesc_wren <= '0';
                mm2s_nxtdesc_wren <= '0';
                -- Throw away second word but drive ready to progress DataMover
                -- and also write nxtdesc out
                elsif(m_axis_mm2s_tvalid = '1' and fetch_word_count = WORD_ONE)then
                
                s2mm_nxtdesc_wren <= s2mm_ftch_active;
                mm2s_nxtdesc_wren <= mm2s_ftch_active;
                -- Assert for only 1 clock
                else
                s2mm_nxtdesc_wren <= '0';
                mm2s_nxtdesc_wren <= '0';
                end if;
            end if;
        end process REG_MSB_NXTPNTR;

    msbnxtdesc_tready <= '1' when m_axis_mm2s_tvalid = '1'
                              and fetch_word_count = WORD_ONE
                    else '0';



end generate GEN_NO_UPR_MSB_NXTDESC;

-- Drive ready to DataMover for ether lsb or msb capture
nxtdesc_tready  <= msbnxtdesc_tready or lsbnxtdesc_tready;

GEN_CYCLIC_BD : if C_SUPPORT_CYCLIC_BD = 1 generate
process (ch_mm2s_ftch_active, ch_mm2s_cyclic)
begin
         mm2s_cyclic <= '0';

    case (ch_mm2s_ftch_active(15 downto 0)) is
      when "0000000000000001" =>
         mm2s_cyclic <= ch_mm2s_cyclic(0); 
      when "0000000000000010" =>
         mm2s_cyclic <= ch_mm2s_cyclic(1); 
      when "0000000000000100" =>
         mm2s_cyclic <= ch_mm2s_cyclic(2); 
      when "0000000000001000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(3); 
      when "0000000000010000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(4); 
      when "0000000000100000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(5); 
      when "0000000001000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(6); 
      when "0000000010000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(7); 
      when "0000000100000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(8); 
      when "0000001000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(9); 
      when "0000010000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(10); 
      when "0000100000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(11); 
      when "0001000000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(12); 
      when "0010000000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(13); 
      when "0100000000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(14); 
      when "1000000000000000" =>
         mm2s_cyclic <= ch_mm2s_cyclic(15); 
      when others =>
         mm2s_cyclic <= '0';
    end case;
end process;

process (ch_mm2s_ftch_active, ch_s2mm_cyclic)
begin
         s2mm_cyclic <= '0';

    case (ch_mm2s_ftch_active(15 downto 0)) is
      when "0000000000000001" =>
         s2mm_cyclic <= ch_s2mm_cyclic(0); 
      when "0000000000000010" =>
         s2mm_cyclic <= ch_s2mm_cyclic(1); 
      when "0000000000000100" =>
         s2mm_cyclic <= ch_s2mm_cyclic(2); 
      when "0000000000001000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(3); 
      when "0000000000010000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(4); 
      when "0000000000100000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(5); 
      when "0000000001000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(6); 
      when "0000000010000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(7); 
      when "0000000100000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(8); 
      when "0000001000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(9); 
      when "0000010000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(10); 
      when "0000100000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(11); 
      when "0001000000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(12); 
      when "0010000000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(13); 
      when "0100000000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(14); 
      when "1000000000000000" =>
         s2mm_cyclic <= ch_s2mm_cyclic(15); 
      when others =>
         s2mm_cyclic <= '0';
    end case;
end process;

end generate GEN_CYCLIC_BD;

GEN_NO_CYCLIC_BD : if C_SUPPORT_CYCLIC_BD = 0 generate
	s2mm_cyclic <= '0';
	mm2s_cyclic <= '0';

end generate GEN_NO_CYCLIC_BD;

-- Generate logic for checking stale descriptor
GEN_STALE_DESC_CHECK : if C_SG_CH1_ENBL_STALE_ERROR = 1 or C_SG_CH2_ENBL_STALE_ERROR = 1 generate
begin

    mask_mm2s_cmplt <= '0' when ((fetch_word_count = WORD_SEVEN) and (mm2s_cyclic = '1') and (mm2s_ftch_active = '1')) else '1';
    mask_s2mm_cmplt <= '0' when ((fetch_word_count = WORD_SIX) and (s2mm_cyclic = '1') and (s2mm_ftch_active = '1')) else '1';

    ---------------------------------------------------------------------------
    -- Examine Completed BIT to determine if stale descriptor fetched
    ---------------------------------------------------------------------------
    CMPLTD_CHECK : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0' )then
                    ftch_stale_desc <= '0';
                -- On valid and word count at 0 and channel active capture LSB next pointer
                elsif(m_axis_mm2s_tvalid = '1' and fetch_word_count = WORD_SIX
                and m_axis_mm2s_tready_i = '1'
                and m_axis_mm2s_tdata(DESC_STS_CMPLTD_BIT) = '1' and s2mm_ftch_active = '1' and s2mm_cyclic = '0' )then
                    ftch_stale_desc <= '1';
                elsif(m_axis_mm2s_tvalid = '1' and fetch_word_count = WORD_SEVEN
                and m_axis_mm2s_tready_i = '1'
                and m_axis_mm2s_tdata(DESC_STS_CMPLTD_BIT) = '1' and mm2s_ftch_active = '1' and mm2s_cyclic = '0' )then
                    ftch_stale_desc <= '1';
                else
                    ftch_stale_desc <= '0';
                end if;
            end if;
        end process CMPLTD_CHECK;

end generate GEN_STALE_DESC_CHECK;

-- No needed logic for checking stale descriptor
GEN_NO_STALE_CHECK : if C_SG_CH1_ENBL_STALE_ERROR = 0 and C_SG_CH2_ENBL_STALE_ERROR = 0 generate
begin
    ftch_stale_desc <= '0';
end generate GEN_NO_STALE_CHECK;

    ---------------------------------------------------------------------------
    -- SG Queueing therefore pass stream signals to
    -- FIFO
    ---------------------------------------------------------------------------
        -- Instantiate the queue version
GEN_MM2S_FTCH_Q_IF : if C_INCLUDE_CH1 = 1 generate
begin

        FTCH_QUEUE_I : entity axi_mcdma_v1_2_2.axi_msg_ftch_queue
            generic map(
                C_M_AXI_SG_ADDR_WIDTH       => C_M_AXI_SG_ADDR_WIDTH        ,
                C_M_AXIS_SG_TDATA_WIDTH     => C_M_AXIS_SG_TDATA_WIDTH      ,
                C_AXIS_IS_ASYNC             => C_AXIS_IS_ASYNC              ,
                C_ASYNC                     => C_ASYNC                      ,
                C_FAMILY                    => C_FAMILY                     , 
                C_WORDS_TO_WRITE            => MM2S_WORDS_TO_WRITE          ,
                C_QUEUE_BD                  => MM2S_BD_QUEUE                ,
                C_NUM_CHANNELS              => C_NUM_MM2S_CHANNELS          ,
                C_MAX_CHANNELS              => C_MAX_CHANNELS               ,
                C_ENABLE_MULTI_CH_RESET     => C_ENABLE_MULTI_CH_RESET
            )
            port map(
                -----------------------------------------------------------------------
                -- AXI Scatter Gather Interface
                -----------------------------------------------------------------------
                m_axi_msg_aclk               => m_axi_msg_aclk                ,
                m_axi_primary_aclk          => m_axi_mm2s_aclk              ,
                m_axi_msg_aresetn            => m_axi_msg_aresetn             ,
                p_reset_n                   => p_reset_n                    ,
                soft_rst               => soft_rst_mm2s                ,
                ch2_sg_idle                 => '0'                          ,
                sof_ftch_desc               => sof_ftch_desc                ,
                channel_id_in               => mm2s_channel_id_ftch         , 
                cmplt_mask                  => mask_mm2s_cmplt, 
                write_bd_fields             => write_fields_mm2s, 

                -- MM2S Channel Control
                ch_desc_flush               => ch_mm2s_desc_flush               ,
                ch_mm2s_cntrl_strm_stop     => (others => '0'), --ch_mm2s_cntrl_strm_stop          ,
                ftch_active                 => ch_mm2s_ftch_active              ,
                ftch_queue_empty            => ch_mm2s_ftch_queue_empty         ,
                ftch_queue_full             => ch_mm2s_ftch_queue_full          ,
                ftch_pause                  => ch_mm2s_ftch_pause               ,

                writing_nxtdesc_in          => nxtdesc_tready               ,
                writing_curdesc_out         => ch1_writing_curdesc          ,

                -- DataMover Command
                ftch_cmnd_wr                => ftch_cmnd_wr                 ,
                ftch_cmnd_data              => ftch_cmnd_data               ,
               -- MM2S Stream In from DataMover^M
                m_axis_mm2s_tdata           => m_axis_mm2s_tdata            ,
                m_axis_mm2s_tlast           => mcdma_tlast_mm2s, --m_axis_mm2s_tlast            ,
                m_axis_mm2s_tvalid          => m_axis_mm2s_tvalid           ,
                m_axis_mm2s_tready          => ch1_ftch_tready              ,

                -- Channel 1 AXI Fetch Stream Out^M
                m_axis_ftch_aclk            => m_axis_ch1_ftch_aclk         ,
                m_axis_ftch_tdata           => m_axis_ch1_ftch_tdata        ,
                m_axis_ftch_tvalid          => m_axis_ch1_ftch_tvalid       ,
                m_axis_ftch_data_valid          => m_axis_ch1_ftch_data_valid       ,
                m_axis_ftch_tready          => m_axis_ch1_ftch_tready       ,
                m_axis_ftch_tlast           => m_axis_ch1_ftch_tlast        ,
                m_axis_ftch_id              => m_axis_ch1_ftch_id           ,

                m_axis_mm2s_cntrl_tdata     => m_axis_mm2s_cntrl_tdata      ,
                m_axis_mm2s_cntrl_tkeep     => m_axis_mm2s_cntrl_tkeep      ,
                m_axis_mm2s_cntrl_tvalid    => m_axis_mm2s_cntrl_tvalid     ,
                m_axis_mm2s_cntrl_tready    => m_axis_mm2s_cntrl_tready     ,
                m_axis_mm2s_cntrl_tlast     => m_axis_mm2s_cntrl_tlast  

            );

end generate GEN_MM2S_FTCH_Q_IF;



GEN_NO_S2MM_FTCH_Q_IF : if C_INCLUDE_CH2 = 0 generate
begin
ch2_writing_curdesc <= '0';
end generate GEN_NO_S2MM_FTCH_Q_IF;

GEN_S2MM_FTCH_Q_IF : if C_INCLUDE_CH2 = 1 generate
begin

        FTCH_QUEUE_I : entity axi_mcdma_v1_2_2.axi_msg_ftch_queue
            generic map(
             C_M_AXI_SG_ADDR_WIDTH       => C_M_AXI_SG_ADDR_WIDTH        ,
             C_M_AXIS_SG_TDATA_WIDTH     => C_M_AXIS_SG_TDATA_WIDTH      ,
             C_AXIS_IS_ASYNC             => C_AXIS_IS_ASYNC              ,
             C_ASYNC                     => C_ASYNC                      ,
             C_FAMILY                    => C_FAMILY                     , 
             C_NUM_CHANNELS              => C_NUM_S2MM_CHANNELS          ,
             C_WORDS_TO_WRITE            => S2MM_WORDS_TO_WRITE          ,
             C_QUEUE_BD                  => S2MM_BD_QUEUE                ,
             C_MAX_CHANNELS              => C_MAX_CHANNELS               ,
             C_ENABLE_MULTI_CH_RESET     => C_ENABLE_MULTI_CH_RESET
            )
            port map(
                -----------------------------------------------------------------------
                -- AXI Scatter Gather Interface
                -----------------------------------------------------------------------
                m_axi_msg_aclk               => m_axi_msg_aclk                ,
                m_axi_primary_aclk          => m_axi_mm2s_aclk              ,
                m_axi_msg_aresetn            => m_axi_msg_aresetn             ,
                p_reset_n                   => p_reset_n                    , 
                soft_rst                    => soft_rst_s2mm                ,
                ch2_sg_idle                 => '0'                          ,
                sof_ftch_desc               => '0'                          ,
                channel_id_in               => s2mm_channel_id_ftch         , 
                cmplt_mask                  => mask_s2mm_cmplt, 
                write_bd_fields             => write_fields_s2mm            ,

                -- S2MM Channel Control
                ch_desc_flush               => ch_s2mm_desc_flush               ,
                ch_mm2s_cntrl_strm_stop     => (others => '0')                               ,
                ftch_active                 => ch_s2mm_ftch_active_i              ,
                ftch_queue_empty            => ch_s2mm_ftch_queue_empty         ,
                ftch_queue_full             => ch_s2mm_ftch_queue_full          ,
                ftch_pause                  => ch_s2mm_ftch_pause               ,


                writing_nxtdesc_in          => nxtdesc_tready               ,
                writing_curdesc_out         => ch2_writing_curdesc          ,

                -- DataMover Command
                ftch_cmnd_wr                => ftch_cmnd_wr                 ,
                ftch_cmnd_data              => ftch_cmnd_data               ,
               -- MM2S Stream In from DataMover^M
                m_axis_mm2s_tdata           => m_axis_mm2s_tdata            ,
                m_axis_mm2s_tlast           => mcdma_tlast, --m_axis_mm2s_tlast            ,
                m_axis_mm2s_tvalid          => m_axis_mm2s_tvalid           ,
                m_axis_mm2s_tready          => ch2_ftch_tready              ,

                -- Channel 1 AXI Fetch Stream Out^M
                m_axis_ftch_aclk            => m_axis_ch2_ftch_aclk         ,
                m_axis_ftch_tdata           => m_axis_ch2_ftch_tdata        ,
                m_axis_ftch_tvalid          => m_axis_ch2_ftch_tvalid       ,
                m_axis_ftch_data_valid          => m_axis_ch2_ftch_data_valid       ,
                m_axis_ftch_tready          => m_axis_ch2_ftch_tready       ,
                m_axis_ftch_tlast           => m_axis_ch2_ftch_tlast        ,
                m_axis_ftch_id              => m_axis_ch2_ftch_id           ,

                m_axis_mm2s_cntrl_tdata     => open  ,
                m_axis_mm2s_cntrl_tkeep     => open  ,
                m_axis_mm2s_cntrl_tvalid    => open  , 
                m_axis_mm2s_cntrl_tready    => '0'   ,
                m_axis_mm2s_cntrl_tlast     => open  

            );

end generate GEN_S2MM_FTCH_Q_IF;


-------------------------------------------------------------------------------
-- DataMover TREADY MUX
-------------------------------------------------------------------------------
writing_curdesc <= ch1_writing_curdesc or ch2_writing_curdesc or ftch_cmnd_wr;


                        
ch_s2mm_flush_active_i <= or_reduce (ch_s2mm_flush_active);
ch_mm2s_flush_active_i <= or_reduce (ch_mm2s_flush_active);


TREADY_MUX : process(writing_curdesc,
                     fetch_word_count,
                     nxtdesc_tready,

                     -- channel 1 signals
                     ch_mm2s_flush_active_i,
                     ch_s2mm_flush_active_i,
                     mm2s_ftch_active,
                     ch1_ftch_tready,

                     -- channel 2 signals
                     s2mm_ftch_active,
                     ch2_ftch_tready)
    begin
        -- If commmanded to flush descriptor then assert ready
        -- to datamover until active de-asserts.  this allows
        -- any commanded fetches to complete.
        if( (ch_mm2s_flush_active_i = '1')
          or(ch_s2mm_flush_active_i = '1'))then
            m_axis_mm2s_tready_i <= '1';

        -- NOT ready if cmnd being written because
        -- curdesc gets written to queue
        elsif(writing_curdesc = '1')then
            m_axis_mm2s_tready_i <= '0';

        -- First two words drive ready from internal logic
        elsif(fetch_word_count = WORD_ZERO or fetch_word_count = WORD_ONE)then
            m_axis_mm2s_tready_i <= nxtdesc_tready;

        -- Remainder stream words drive ready from channel input
        else
--            m_axis_mm2s_tready_i <= (mm2s_ftch_active and ch1_ftch_tready)
--                                 or (s2mm_ftch_active and ch2_ftch_tready);
-- the fetch will not happen if the BMG is full, so safe to drive '1'
            m_axis_mm2s_tready_i <= '1';
        end if;
    end process TREADY_MUX;

m_axis_mm2s_tready    <= m_axis_mm2s_tready_i;





end implementation;



