-------------------------------------------------------------------------------
-- Filename:          axi_msg_intrpt.vhd
-- Description: This entity handles interrupt coalescing
--
-- VHDL-Standard:   VHDL'93
-------------------------------------------------------------------------------
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library unisim;
use unisim.vcomponents.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;

-------------------------------------------------------------------------------
entity  axi_msg_intrpt is
    generic(

        C_INCLUDE_DLYTMR            : integer range 0 to 1          := 1    ;
            -- Include/Exclude interrupt delay timer
            -- 0 = Exclude Delay timer
            -- 1 = Include Delay timer

        C_DLYTMR_RESOLUTION         : integer range 1 to 100000      := 125
            -- Interrupt Delay Timer resolution in usec

    );
    port (

        -- Secondary Clock and Reset
        m_axi_msg_aclk               : in  std_logic                         ;              --
        m_axi_msg_aresetn            : in  std_logic                         ;              --
                                                                                           --
        ch_irqthresh_decr          : in  std_logic                         ;-- CR567661   --
        ch_irqthresh_rstdsbl       : in  std_logic                         ;-- CR572013   --
        ch_dlyirq_dsble            : in  std_logic                         ;              --
        ch_irqdelay_wren           : in  std_logic                         ;              --
        ch_irqdelay                : in  std_logic_vector(7 downto 0)      ;              --
        ch_irqthresh_wren          : in  std_logic                         ;              --
        ch_irqthresh               : in  std_logic_vector(7 downto 0)      ;              --
        ch_packet_sof              : in  std_logic                         ;              --
        ch_packet_eof              : in  std_logic                         ;              --
        ch_ioc_irq_set             : out std_logic                         ;              --
        ch_dly_irq_set             : out std_logic                         ;              --
        ch_irqdelay_status         : out std_logic_vector(7 downto 0)      ;              --
        ch_irqthresh_status        : out std_logic_vector(7 downto 0)      ;              --
        ch_pkt_count               : out std_logic_vector (15 downto 0)
                                                                                           --

    );

end axi_msg_intrpt;

-------------------------------------------------------------------------------
-- Architecture
-------------------------------------------------------------------------------
architecture implementation of axi_msg_intrpt is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";


-------------------------------------------------------------------------------
-- Functions
-------------------------------------------------------------------------------

-- No Functions Declared

-------------------------------------------------------------------------------
-- Constants Declarations
-------------------------------------------------------------------------------
-- Delay interrupt fast counter width
constant FAST_COUNT_WIDTH   : integer := clog2(C_DLYTMR_RESOLUTION+1);
-- Delay interrupt fast counter terminal count
constant FAST_COUNT_TC      : std_logic_vector(FAST_COUNT_WIDTH-1 downto 0)
                                := std_logic_vector(to_unsigned(
                                (C_DLYTMR_RESOLUTION-1),FAST_COUNT_WIDTH));




-- Delay interrupt fast counter zero value
constant ZERO_FAST_COUNT    : std_logic_vector(FAST_COUNT_WIDTH-1 downto 0)
                                := (others => '0');

constant ZERO_VALUE         : std_logic_vector(7 downto 0) := (others => '0');

-------------------------------------------------------------------------------
-- Signal / Type Declarations
-------------------------------------------------------------------------------
signal ch_thresh_count    : std_logic_vector(7 downto 0) := ONE_THRESHOLD;
signal ch_dly_irq_set_i   : std_logic := '0';
signal ch_ioc_irq_set_i   : std_logic := '0';

signal ch_delay_count     : std_logic_vector(7 downto 0) := (others => '0');
signal ch_delay_cnt_en    : std_logic := '0';
signal ch_dly_fast_cnt    : std_logic_vector(FAST_COUNT_WIDTH-1 downto 0) := (others => '0');
signal ch_dly_fast_incr   : std_logic := '0';
signal ch_delay_zero      : std_logic := '0';
signal ch_delay_tc        : std_logic := '0';
signal ch_disable_delay   : std_logic := '0';
signal packet_count       : std_logic_vector (15 downto 0);


-------------------------------------------------------------------------------
-- Begin architecture logic
-------------------------------------------------------------------------------
begin


    REG_PKT_COUNT : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0')then
                     packet_count <= (others => '0');
                elsif (ch_irqthresh_decr = '1') then
                     packet_count   <= std_logic_vector(unsigned(packet_count(15 downto 0)) + 1);
                end if;
            end if;
        end process REG_PKT_COUNT;

    ch_pkt_count <= packet_count;

-- Transmit channel included therefore generate transmit interrupt logic
    REG_THRESH_COUNT : process(m_axi_msg_aclk)
        begin
            if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                if(m_axi_msg_aresetn = '0')then
                    ch_thresh_count   <= ONE_THRESHOLD;
                    ch_ioc_irq_set_i  <= '0';

                -- New Threshold set by CPU OR delay interrupt event occured.
-- CR572013 - added ability to disable threshold count reset on delay timeout
--                elsif(ch_irqthresh_wren = '1' or ch_dly_irq_set_i = '1') then
                elsif( (ch_irqthresh_wren = '1')
                    or (ch_dly_irq_set_i = '1' and ch_irqthresh_rstdsbl = '0')) then
                    ch_thresh_count   <= ch_irqthresh;
                    ch_ioc_irq_set_i  <= '0';

                -- IOC event then...
                elsif(ch_irqthresh_decr = '1')then --CR567661
                    -- Threshold at zero, reload threshold and drive ioc
                    -- interrupt.
                    if(ch_thresh_count = ONE_THRESHOLD)then
                        ch_thresh_count    <= ch_irqthresh;
                        ch_ioc_irq_set_i  <= '1';
                    else
                        ch_thresh_count   <= std_logic_vector(unsigned(ch_thresh_count(7 downto 0)) - 1);
                        ch_ioc_irq_set_i  <= '0';
                    end if;
                else
                    ch_thresh_count   <= ch_thresh_count;
                    ch_ioc_irq_set_i  <= '0';
                end if;
            end if;
        end process REG_THRESH_COUNT;

    -- Pass current threshold count out to DMASR
    ch_irqthresh_status <= ch_thresh_count;
    ch_ioc_irq_set      <= ch_ioc_irq_set_i;

    ---------------------------------------------------------------------------
    -- Generate Delay Interrupt Timers
    ---------------------------------------------------------------------------
    GEN_CH1_DELAY_INTERRUPT : if C_INCLUDE_DLYTMR = 1 generate
    begin
        GEN_CH1_FAST_COUNTER : if C_DLYTMR_RESOLUTION /= 1 generate
        begin
            ---------------------------------------------------------------------------
            -- Delay interrupt high resolution timer
            ---------------------------------------------------------------------------
            REG_DLY_FAST_CNT : process(m_axi_msg_aclk)
                begin
                    if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
-- CR565366 - need to reset on sof due to chanes for CR
--                        if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1')then
-- CR570398 - need to reset delay timer each time a new delay value is written.
--                        if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1' or ch_packet_sof = '1')then
                        if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1'
                        or ch_packet_sof = '1' or ch_irqdelay_wren = '1')then
                            ch_dly_fast_cnt   <= FAST_COUNT_TC;
                            ch_dly_fast_incr  <= '0';
                        elsif(ch_dly_fast_cnt = ZERO_FAST_COUNT)then
                            ch_dly_fast_cnt   <= FAST_COUNT_TC;
                            ch_dly_fast_incr  <= '1';
                        else
                            ch_dly_fast_cnt   <= std_logic_vector(unsigned(ch_dly_fast_cnt(FAST_COUNT_WIDTH-1 downto 0)) - 1);
                            ch_dly_fast_incr  <= '0';
                        end if;
                    end if;
                end process REG_DLY_FAST_CNT;
        end generate GEN_CH1_FAST_COUNTER;

        GEN_CH1_NO_FAST_COUNTER :  if C_DLYTMR_RESOLUTION = 1 generate
            REG_DLY_FAST_CNT : process(m_axi_msg_aclk)
                begin
                    if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
-- CR565366 - need to reset on sof due to chanes for CR
--                        if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1')then
-- CR570398 - need to reset delay timer each time a new delay value is written.
--                        if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1' or ch_packet_sof = '1')then
                        if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1'
                        or ch_packet_sof = '1' or ch_irqdelay_wren = '1')then
                            ch_dly_fast_incr <= '0';
                        else
                            ch_dly_fast_incr <= '1';
                        end if;
                    end if;
                end process REG_DLY_FAST_CNT;
        end generate GEN_CH1_NO_FAST_COUNTER;

        -- DMACR Delay value set to zero - disable delay interrupt
        ch_delay_zero <= '1' when ch_irqdelay = ZERO_DELAY
                      else '0';

        -- Delay Terminal Count reached (i.e. Delay count = DMACR delay value)
        ch_delay_tc <= '1' when ch_delay_count = ch_irqdelay
                             and ch_delay_zero = '0'
                             and ch_packet_sof = '0'
                    else '0';

        -- 1 clock earlier delay counter disable to prevent count
        -- increment on TC hit.
        ch_disable_delay <= '1' when ch_delay_zero = '1'
                                   or ch_dlyirq_dsble = '1'
                                   or ch_dly_irq_set_i = '1'
                        else '0';

        ---------------------------------------------------------------------------
        -- Delay interrupt low resolution timer
        ---------------------------------------------------------------------------
        REG_DELAY_COUNT : process(m_axi_msg_aclk)
            begin
                if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
-- CR565366 need to reset on SOF now due to CR change
--                    if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1')then
-- CR570398 - need to reset delay timer each time a new delay value is written.
--                    if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1' or ch_packet_sof = '1')then
                    if(m_axi_msg_aresetn = '0' or ch_delay_cnt_en = '0' or ch_disable_delay = '1'
                    or ch_packet_sof = '1' or ch_irqdelay_wren = '1')then
                        ch_delay_count    <= (others => '0');
                        ch_dly_irq_set_i  <= '0';
                    elsif(ch_dly_fast_incr = '1' and ch_delay_tc = '1')then
                        ch_delay_count    <= (others => '0');
                        ch_dly_irq_set_i  <= '1';
                    elsif(ch_dly_fast_incr = '1')then
                        ch_delay_count    <= std_logic_vector(unsigned(ch_delay_count(7 downto 0)) + 1);
                        ch_dly_irq_set_i  <= '0';
                    else
                        ch_delay_count    <= ch_delay_count;
                        ch_dly_irq_set_i  <= '0';
                    end if;
                end if;
            end process REG_DELAY_COUNT;

        -- Pass current delay count to DMASR
        ch_irqdelay_status    <= ch_delay_count;
        ch_dly_irq_set        <= ch_dly_irq_set_i;

        -- Enable control for delay counter
        REG_DELAY_CNT_ENABLE : process(m_axi_msg_aclk)
            begin
                if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
                    if(m_axi_msg_aresetn = '0' or ch_disable_delay = '1')then
                        ch_delay_cnt_en   <= '0';

-- CR565366 simulatenous sof/eof which occurs for small packets causes delay timer
-- to not enable
--                    elsif(ch_packet_sof = '1')then
                    -- stop counting if already counting and receive an sof and
                    -- not end of another packet
                    elsif(ch_delay_cnt_en = '1' and ch_packet_sof = '1'
                    and ch_packet_eof = '0')then
                        ch_delay_cnt_en   <= '0';
                    elsif(ch_packet_eof = '1')then
                        ch_delay_cnt_en   <= '1';
                    end if;
                end if;
            end process REG_DELAY_CNT_ENABLE;
    end generate GEN_CH1_DELAY_INTERRUPT;

    ---------------------------------------------------------------------------
    -- Delay interrupt NOT included
    ---------------------------------------------------------------------------
    GEN_NO_CH1_DELAY_INTR : if C_INCLUDE_DLYTMR = 0  generate
    begin
        ch_dly_irq_set     <= '0';
        ch_dly_irq_set_i   <= '0';
        ch_irqdelay_status <= (others => '0');
    end generate GEN_NO_CH1_DELAY_INTR;

end implementation;


