signal soft_rst_i_s2mm : std_logic := '0';
signal dm_rst_done : std_logic := '0';
signal dm_rst_done_updt : std_logic := '0';
signal soft_rst_i_mm2s_ext : std_logic := '0';
signal soft_rst_i_s2mm_ext : std_logic := '0';
signal dm_rstn_int : std_logic := '0';
signal dm_rstn_int_ftch : std_logic := '1';
signal dm_rst_done_i : std_logic_vector (3 downto 0) := (others => '0');
signal dm_rst_done_i_updt : std_logic_vector (3 downto 0) := (others => '0');
signal soft_int_rst : std_logic := '0';
signal soft_int_rst_s2mm : std_logic := '0';
signal soft_rst_channel : std_logic_vector (C_NUM_MM2S_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_channel_s2mm : std_logic_vector (C_NUM_S2MM_CHANNELS-1 downto 0) := (others => '0');  
signal soft_rst_updt_channel : std_logic_vector (C_NUM_MM2S_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_updt_channel_s2mm : std_logic_vector (C_NUM_S2MM_CHANNELS-1 downto 0) := (others => '0');  
signal dm_rstn_updt_int : std_logic := '1';
signal dm_rstn_int_updt : std_logic := '1';
type RST_STATE_TYPE   is (BUSY, DONE, HOLD);
signal active_cs        : RST_STATE_TYPE;
signal active_ns        : RST_STATE_TYPE;
signal wait_status      : std_logic := '0';
signal wait_status_up      : std_logic := '0';
signal active_up_cs        : RST_STATE_TYPE;
signal active_up_ns        : RST_STATE_TYPE;
signal mm2s_addr_req_posted : std_logic := '0';
signal s2mm_addr_req_posted : std_logic := '0';
signal m_axi_msg_resetn_gen : std_logic_vector (C_NUM_MM2S_CHANNELS-1 downto 0) := (others => '1');
signal m_axi_msg_resetn_s2mm_gen : std_logic_vector (C_NUM_S2MM_CHANNELS-1 downto 0) := (others => '1');
signal soft_rstn_mm2s_ext : std_logic_vector (C_NUM_MM2S_CHANNELS-1 downto 0) := (others => '1');
signal soft_rstn_s2mm_ext : std_logic_vector (C_NUM_S2MM_CHANNELS-1 downto 0) := (others => '1');
signal soft_rst_mm2s_r1	: std_logic_vector (C_MAX_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_mm2s_r2	: std_logic_vector (C_MAX_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_mm2s_r3	: std_logic_vector (C_MAX_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_s2mm_r1	: std_logic_vector (C_MAX_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_s2mm_r2	: std_logic_vector (C_MAX_CHANNELS-1 downto 0) := (others => '0');
signal soft_rst_s2mm_r3	: std_logic_vector (C_MAX_CHANNELS-1 downto 0) := (others => '0');
signal ch_mm2s_run_stop_gen_i : std_logic_vector (C_MAX_CHANNELS - 1 downto 0) := (others => '0');
signal ch_s2mm_run_stop_gen_i : std_logic_vector (C_MAX_CHANNELS - 1 downto 0) := (others => '0');
signal dm_rstn_ftch_i: std_logic := '1';
signal mm2s_addr_req_posted_i : std_logic;
signal s2mm_addr_req_posted_i : std_logic;
signal dm_rstn_updt_i: std_logic := '1'; 
--signal ch1_updt_ioc_irq_set_i : std_logic;
-------------------------------------------------------------------------------
-- Begin architecture logic
-------------------------------------------------------------------------------
begin


s2mm_ftch_idle <= and_reduce (ch_s2mm_ftch_idle_i);
ch_s2mm_ftch_idle <= ch_s2mm_ftch_idle_i;

mm2s_ftch_idle <= and_reduce (ch_mm2s_ftch_idle_i);
ch_mm2s_ftch_idle <= ch_mm2s_ftch_idle_i;

s2mm_updt_done <= ch2_updt_done;
s2mm_updt_idle <= ch2_updt_idle;
mm2s_updt_idle <= ch1_updt_idle;
s2mm_updt_channel <= s2mm_channel;
--ch_mm2s_ftch_current <= ch_mm2s_ftch_active;
--ch_s2mm_ftch_current <= ch_s2mm_ftch_active;
ch_mm2s_ftch_current <= mm2s_channel_ftch;
ch_s2mm_ftch_current <= s2mm_channel_ftch;

updt_error <= updt_error_i;
ftch_error <= ftch_error_i;
mm2s_ftch_err <= ftch_error_capture_mm2s;
s2mm_ftch_err <= ftch_error_capture_s2mm;
--mm2s_halt_cmplt_i <= mm2s_halt_cmplt;
--rst_done <= dm_rst_done;


RST_PER_CH_ENABLE_GEN: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin


  dm_rstn_int_ftch <= dm_resetn and dm_rstn_int; -- and (not (soft_rst_i_mm2s_ext  and (not wait_status)));
  dm_rstn_int_updt <= dm_resetn and dm_rstn_updt_int; -- and (not (soft_rst_i_mm2s_ext  and (not wait_status)));
  soft_rstn_mm2s_ext <= not soft_rst_mm2s(C_NUM_MM2S_CHANNELS-1 downto 0);
  soft_rstn_s2mm_ext <= not soft_rst_s2mm(C_NUM_S2MM_CHANNELS-1 downto 0);
  
  soft_rst_s2mm_i_gen: process (soft_rst_s2mm)
  begin
    if (unsigned(soft_rst_s2mm(C_NUM_S2MM_CHANNELS-1 downto 0)) = 0) then  --create a single bit version of soft_rst_s2mm to be used for reseting fetch error detection mechanism along with aresetn
        soft_rst_i_s2mm <= '0';
    else  soft_rst_i_s2mm <= '1';
    end if;
   end process soft_rst_s2mm_i_gen;

  rst_gen_proc: process (m_axi_msg_aclk)
  begin
    if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
      if (m_axi_msg_aresetn = '0') then
         rst_done <= (others => '0');
	 soft_rst_mm2s_r1 <= (others => '0');
	 soft_rst_mm2s_r2 <= (others => '0');
	 soft_rst_mm2s_r3 <= (others => '0');

       else 
		soft_rst_mm2s_r1 <= soft_rst_mm2s and (not mm2s_channel_ftch);
		soft_rst_mm2s_r2 <= soft_rst_mm2s_r1;
		soft_rst_mm2s_r3 <= soft_rst_mm2s_r2;
                --rst_done <=  soft_rst_s2mm_r3 or soft_rst_mm2s_r3;
                rst_done <=  soft_rst_mm2s_r3;
 
      end if;
    end if;
   end process rst_gen_proc;
  rst_gen_s2mm_proc: process (m_axi_msg_aclk)
  begin
    if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
      if (m_axi_msg_aresetn = '0') then
         rst_done_s2mm <= (others => '0');
         soft_rst_s2mm_r1 <= (others => '0');
	 soft_rst_s2mm_r2 <= (others => '0');
	 soft_rst_s2mm_r3 <= (others => '0');

       else 
                soft_rst_s2mm_r1 <= soft_rst_s2mm and (not s2mm_channel_ftch);
		soft_rst_s2mm_r2 <= soft_rst_s2mm_r1;
		soft_rst_s2mm_r3 <= soft_rst_s2mm_r2;
                --rst_done <=  soft_rst_s2mm_r3 or soft_rst_mm2s_r3;
                rst_done_s2mm <=  soft_rst_s2mm_r3;
 
      end if;
    end if;
   end process rst_gen_s2mm_proc;

  soft_rst_mm2s_in_gen: process (soft_rst_mm2s)
  begin
   if (unsigned(soft_rst_mm2s(C_NUM_MM2S_CHANNELS-1 downto 0)) = 0) then  
        soft_rst_i_mm2s_ext <= '0';
    else  soft_rst_i_mm2s_ext <= '1';
  end if;
end process soft_rst_mm2s_in_gen;

  soft_rst_s2mm_in_gen: process (soft_rst_s2mm)
   begin
    if (unsigned(soft_rst_s2mm(C_NUM_S2MM_CHANNELS-1 downto 0)) = 0) then  
        soft_rst_i_s2mm_ext <= '0';
    else  soft_rst_i_s2mm_ext <= '1';
   end if;
  end process soft_rst_s2mm_in_gen;


     process (m_axi_msg_aclk)
   begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (m_axi_msg_aresetn = '0' or dm_rst_done = '1' ) then
           dm_rstn_int <= '1';
        elsif ((m_axis_ftch_sts_tvalid = '1') and (m_axis_ftch_sts_tready = '1') and (m_axis_ftch_sts_tdata = "01000000" or m_axis_ftch_sts_tdata = "00100000" or m_axis_ftch_sts_tdata = "00010000")) then
           dm_rstn_int <= '0';
        end if;
      end if;
  end process;

soft_int_rst <= not dm_rstn_int and (soft_rst_i_mm2s_ext and (not wait_status));
soft_int_rst_s2mm <= not dm_rstn_int and (soft_rst_i_s2mm_ext and (not wait_status));

process (m_axi_msg_aclk)
   begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then  
        if (m_axi_msg_aresetn = '0') then
            dm_rst_done <= '0';
            dm_rst_done_i <= (others => '0');      
        else dm_rst_done_i(0) <= dm_rstn_int_ftch;          -- DM reset done signal after 3 clock cycles
             dm_rst_done_i(1) <= dm_rst_done_i(0);
             dm_rst_done_i(2) <= dm_rst_done_i(1);
             dm_rst_done <= not dm_rst_done_i(2);
        end if;
     end if;
end process;

soft_rst_channel_gen: for I in 0 to C_NUM_MM2S_CHANNELS-1 generate 
  begin
  soft_rst_channel(I)<= ch_mm2s_ftch_interr_set_i(I) or ch_mm2s_ftch_slverr_set_i(I) or ch_mm2s_ftch_decerr_set_i(I) 
		or      ch_mm2s_updt_interr_set_i(I) or ch_mm2s_updt_slverr_set_i(I) or ch_mm2s_updt_decerr_set_i(I)
		or soft_rst_mm2s(I);   -- reset the corresponding error channel
 end generate soft_rst_channel_gen;


 soft_rst_channel_s2mm_gen: for I in 0 to C_NUM_S2MM_CHANNELS-1 generate 
  begin
  soft_rst_channel_s2mm(I)<= ch_s2mm_ftch_interr_set_i(I) or ch_s2mm_ftch_slverr_set_i(I) or ch_s2mm_ftch_decerr_set_i(I) 
		or      ch_s2mm_updt_interr_set_i(I) or ch_s2mm_updt_slverr_set_i(I) or ch_s2mm_updt_decerr_set_i(I)
		or soft_rst_s2mm(I);   -- reset the corresponding error channel
 end generate soft_rst_channel_s2mm_gen;



 process (m_axi_msg_aclk)
   begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then    -- create a reset signal to data mover incase of updt error
        if (m_axi_msg_aresetn = '0' or dm_rst_done_updt = '1') then
           dm_rstn_updt_int <= '1';
        --elsif (ch1_updt_interr_set_i = '1') then
        elsif ((m_axis_updt_sts_tvalid = '1') and (m_axis_updt_sts_tdata = "01000000" or m_axis_updt_sts_tdata = "00100000" or m_axis_updt_sts_tdata = "00010000") and (m_axis_updt_sts_tready = '1')) then
           dm_rstn_updt_int <= '0';
        end if;
      end if;
  end process;
process (m_axi_msg_aclk)
   begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then  
        if (m_axi_msg_aresetn = '0') then
            dm_rst_done_updt <= '0';
            dm_rst_done_i_updt <= (others => '0');      
        else dm_rst_done_i_updt(0) <= dm_rstn_int_updt;          -- DM reset done signal after 3 clock cycles
             dm_rst_done_i_updt(1) <= dm_rst_done_i_updt(0);
             dm_rst_done_i_updt(2) <= dm_rst_done_i_updt(1);
             dm_rst_done_updt  <= not dm_rst_done_i_updt(2);
        end if;
     end if;
end process;


soft_rst_updt_channel_gen: for I in 0 to C_NUM_MM2S_CHANNELS-1 generate
  begin
  soft_rst_updt_channel(I)<= ch_mm2s_updt_interr_set_i(I) or ch_mm2s_updt_slverr_set_i(I) or ch_mm2s_updt_decerr_set_i(I) or (soft_rst_mm2s(I) and ( not wait_status_up ));   -- reset the corresponding error channel
 end generate soft_rst_updt_channel_gen;  

soft_rst_updt_channel_s2mm_gen: for I in 0 to C_NUM_S2MM_CHANNELS-1 generate
  begin
  soft_rst_updt_channel_s2mm(I)<= ch_s2mm_updt_interr_set_i(I) or ch_s2mm_updt_slverr_set_i(I) or ch_s2mm_updt_decerr_set_i(I) or (soft_rst_s2mm(I) and ( not wait_status_up ));   -- reset the corresponding error channel
 end generate soft_rst_updt_channel_s2mm_gen;  



RST_WHAT_STATE : process(m_axi_msg_aclk)
    begin
        if(m_axi_msg_aclk'EVENT and m_axi_msg_aclk = '1')then
            if(m_axi_msg_aresetn = '0')then
                active_cs     <= HOLD;
		active_up_cs  <= HOLD;
            else
                active_cs     <= active_ns;
                active_up_cs     <= active_up_ns;
            end if;
        end if;
    end process RST_WHAT_STATE;


active : process (mm2s_addr_req_posted, m_axis_ftch_sts_tvalid, m_axis_ftch_sts_tready, s2mm_addr_req_posted)       -- check if data mover is busy
       begin
              active_ns <= active_cs;
  case active_cs is 
     when BUSY =>
               wait_status <= '1';
               active_ns <= BUSY;
             if (m_axis_ftch_sts_tvalid = '1' and m_axis_ftch_sts_tready = '1') then
              active_ns <= DONE;
              else   active_ns <= HOLD; 
             end if;

    when HOLD =>
             wait_status <= '0';
             if (mm2s_addr_req_posted = '1') then
              active_ns <= BUSY;
              else   active_ns <= HOLD; 
             end if;
             if (s2mm_addr_req_posted = '1') then
               active_ns <= BUSY;
             else active_ns <= HOLD; 
             end if;

    when DONE =>
               wait_status <= '0';
             if (mm2s_addr_req_posted = '1') then
              active_ns <= BUSY;
              else   active_ns <= HOLD; 
             end if;
             if (s2mm_addr_req_posted = '1') then
              active_ns <= BUSY;
              else   active_ns <= HOLD; 
             end if;

             --  active_ns <= HOLD;         

end case;                
end process active;

update_active : process (s_axis_updt_cmd_tvalid,s_axis_updt_cmd_tready, m_axis_updt_sts_tvalid, m_axis_updt_sts_tready)       -- check if data mover is busy
       begin
              active_up_ns <= active_up_cs;
  case active_up_cs is 
     when BUSY =>
               wait_status_up <= '1';
               active_up_ns <= BUSY;
             if (m_axis_updt_sts_tvalid = '1' and m_axis_updt_sts_tready = '1') then
              active_up_ns <= DONE;
              else   active_up_ns <= HOLD; 
             end if;

    when HOLD =>
             wait_status_up <= '0';
             if (s_axis_updt_cmd_tvalid = '1' and s_axis_updt_cmd_tready = '1') then
              active_up_ns <= BUSY;
              else   active_up_ns <= HOLD; 
             end if;
           

    when DONE =>
               wait_status_up <= '0';
             if (s_axis_updt_cmd_tvalid = '1' and s_axis_updt_cmd_tready = '1') then
              active_up_ns <= BUSY;
              else   active_up_ns <= HOLD; 
             end if;
             --  active_ns <= HOLD;         

end case;                
end process update_active;

-- Drive interrupt on complete set out

ch_mm2s_run_stop_gen(C_NUM_MM2S_CHANNELS-1 downto 0) <= ch_mm2s_run_stop(C_NUM_MM2S_CHANNELS-1 downto 0) and (not soft_rst_channel);
ch_s2mm_run_stop_gen(C_NUM_S2MM_CHANNELS-1 downto 0) <= ch_s2mm_run_stop(C_NUM_S2MM_CHANNELS-1 downto 0) and (not soft_rst_channel_s2mm);

