           --     ch_mm2s_updt_ioc_irq_set(I)      <= ch1_updt_ioc_irq_set_i or ch_mm2s_updt_ioc_irq_set(I);

                ch_mm2s_dma_interr_set_i(I)     <= ch1_dma_interr_set_i  or ch_mm2s_dma_interr_set_i(I);
                ch_mm2s_dma_slverr_set_i(I)     <= ch1_dma_slverr_set_i  or ch_mm2s_dma_slverr_set_i(I);
                ch_mm2s_dma_decerr_set_i(I)     <= ch1_dma_decerr_set_i  or ch_mm2s_dma_decerr_set_i(I);
            end if;
        end if;
    end process REG_CH_UPDT_ERR;

end generate RST_PER_CH_ENABLE_GEN1;


RST_PER_CH_DISABLE_GEN1: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
  ch_mm2s_ftch_interr_set_i(I) <= mm2s_ftch_interr_set_i and mm2s_ftch_active and mm2s_channel_ftch (I); --ch1_s2mm_ftch_interr_set_i;
  ch_mm2s_ftch_slverr_set_i(I) <= mm2s_ftch_slverr_set_i and mm2s_ftch_active and mm2s_channel_ftch (I); --ch1_s2mm_ftch_slverr_set_i;
  ch_mm2s_ftch_decerr_set_i(I) <= mm2s_ftch_decerr_set_i and mm2s_ftch_active and mm2s_channel_ftch (I); --ch1_s2mm_ftch_decerr_set_i;
  ch_mm2s_ftch_err_early(I)  <= mm2s_ftch_err_early_i  and mm2s_ftch_active and mm2s_channel_ftch (I);
  ch_mm2s_ftch_stale_desc(I) <= mm2s_ftch_stale_desc_i and mm2s_ftch_active and mm2s_channel_ftch (I);

  ch_mm2s_dma_interr_set(I) <= ch1_dma_interr_set_i and mm2s_channel(I);
  ch_mm2s_dma_slverr_set(I) <= ch1_dma_slverr_set_i and mm2s_channel(I);
  ch_mm2s_dma_decerr_set(I) <= ch1_dma_decerr_set_i and mm2s_channel(I);
  ch_mm2s_updt_interr_set(I) <= ch1_updt_interr_set_i and mm2s_channel(I); 
  ch_mm2s_updt_slverr_set(I) <= ch1_updt_slverr_set_i and mm2s_channel(I); 
  ch_mm2s_updt_decerr_set(I) <= ch1_updt_decerr_set_i and mm2s_channel(I);

end generate RST_PER_CH_DISABLE_GEN1;

--ch_mm2s_ftch_interr_set_i(I) <= mm2s_ftch_interr_set_i and mm2s_ftch_active and mm2s_channel_ftch (I); --ch1_s2mm_ftch_interr_set_i;
--ch_mm2s_ftch_slverr_set_i(I) <= mm2s_ftch_slverr_set_i and mm2s_ftch_active and mm2s_channel_ftch (I); --ch1_s2mm_ftch_slverr_set_i;
--ch_mm2s_ftch_decerr_set_i(I) <= mm2s_ftch_decerr_set_i and mm2s_ftch_active and mm2s_channel_ftch (I); --ch1_s2mm_ftch_decerr_set_i;
--ch_mm2s_ftch_err_early(I)  <= mm2s_ftch_err_early_i  and mm2s_ftch_active and mm2s_channel_ftch (I);
--ch_mm2s_ftch_stale_desc(I) <= mm2s_ftch_stale_desc_i and mm2s_ftch_active and mm2s_channel_ftch (I);

--ch_mm2s_dma_interr_set(I) <= ch1_dma_interr_set_i and mm2s_channel(I);
--ch_mm2s_dma_slverr_set(I) <= ch1_dma_slverr_set_i and mm2s_channel(I);
--ch_mm2s_dma_decerr_set(I) <= ch1_dma_decerr_set_i and mm2s_channel(I);
--ch_mm2s_updt_interr_set_i(I) <= ch1_updt_interr_set_i and mm2s_channel(I); 
--ch_mm2s_updt_slverr_set_i(I) <= ch1_updt_slverr_set_i and mm2s_channel(I); 
--ch_mm2s_updt_decerr_set_i(I) <= ch1_updt_decerr_set_i and mm2s_channel(I);    
ch_mm2s_updt_ioc_irq_set(I) <= ch1_updt_ioc_irq_set_i and mm2s_channel(I);    

mm2s_ch_serviced(I) <= ch1_updt_ioc_irq_set_i and mm2s_channel(I);    

end generate GEN_MM2S_CH_OUTPUT; 



UNUSED_FOR_CHANNELS1 : if (C_NUM_MM2S_CHANNELS < C_MAX_CHANNELS) generate

GEN_MM2S_CH_OUTPUT : for I in C_NUM_MM2S_CHANNELS to C_MAX_CHANNELS-1 generate

ch_mm2s_ftch_interr_set_i(I) <= '0';
ch_mm2s_ftch_slverr_set_i(I) <= '0';
ch_mm2s_ftch_decerr_set_i(I) <= '0';

CH_ERR_SET_GEN_MULTI: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
ch_mm2s_ftch_err_early_i(I)  <= '0';
ch_mm2s_ftch_stale_desc_i(I) <= '0';
ch_mm2s_dma_interr_set_i(I) <= '0';
ch_mm2s_dma_slverr_set_i(I) <= '0';
ch_mm2s_dma_decerr_set_i(I) <= '0';
ch_mm2s_updt_interr_set_i(I) <= '0';
ch_mm2s_updt_slverr_set_i(I) <= '0';
ch_mm2s_updt_decerr_set_i(I) <= '0';
end generate CH_ERR_SET_GEN_MULTI;

CH_ERR_SET_GEN_SINGLE: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
ch_mm2s_ftch_err_early(I)  <= '0';
ch_mm2s_ftch_stale_desc(I) <= '0';
ch_mm2s_dma_interr_set(I) <= '0';
ch_mm2s_dma_slverr_set(I) <= '0';
ch_mm2s_dma_decerr_set(I) <= '0';
ch_mm2s_updt_interr_set(I) <= '0';
ch_mm2s_updt_slverr_set(I) <= '0';
ch_mm2s_updt_decerr_set(I) <= '0';
end generate CH_ERR_SET_GEN_SINGLE;

ch_mm2s_updt_ioc_irq_set(I) <= '0';
mm2s_ch_serviced(I) <= '0';

end generate GEN_MM2S_CH_OUTPUT; 


end generate UNUSED_FOR_CHANNELS1;

UPDT_INTR_SET_GEN: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin

  ch_mm2s_updt_interr_set <= ch_mm2s_updt_interr_set_i;
  ch_mm2s_updt_slverr_set <= ch_mm2s_updt_slverr_set_i;
  ch_mm2s_updt_decerr_set <= ch_mm2s_updt_decerr_set_i;
end generate UPDT_INTR_SET_GEN;

process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (m_axi_msg_aresetn = '0') then
              ch_mm2s_ftch_channel_id  <= (others => '0');
              mm2s_ftch_err_cap <= '0';
        elsif (ftch_error_capture_mm2s = '1' and mm2s_ftch_err_cap = '0') then -- or updt_error_i = '1') then
             -- this can be used to identify the channel that caused ftch error
              ch_mm2s_ftch_channel_id  <= mm2s_channel_ftch; --ch_ftch_active_error;
              mm2s_ftch_err_cap <= '1';
        end if;
     end if;
end process; 


updt_error_capture_mm2s <= ch1_updt_interr_set_i or
                           ch1_updt_slverr_set_i or
                           ch1_updt_decerr_set_i or
                           ch1_dma_interr_set_i or
                           ch1_dma_slverr_set_i or
                           ch1_dma_decerr_set_i;

process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (m_axi_msg_aresetn = '0') then
              ch_mm2s_updt_channel_id  <= (others => '0');
              mm2s_updt_err_cap <= '0';
        elsif (updt_error_capture_mm2s = '1' and mm2s_updt_err_cap = '0') then -- or updt_error_i = '1') then
             -- this can be used to identify the channel that caused ftch error
              ch_mm2s_updt_channel_id  <= mm2s_channel;
              mm2s_updt_err_cap <= '1';
        end if;
     end if;
end process; 


end generate MM2S_ERROR_SIG;

NO_MM2S_ERROR_SIG: if C_INCLUDE_CH1 = 0 generate
begin
ftch_error_capture_mm2s <= '0';
mm2s_ftch_interr_set <= '0';
mm2s_ftch_slverr_set <= '0';
mm2s_ftch_decerr_set <= '0';
mm2s_ftch_err_early  <= '0';
mm2s_ftch_stale_desc <= '0';
ch_mm2s_ftch_interr_set <= (others => '0');
ch_mm2s_ftch_slverr_set <= (others => '0');
ch_mm2s_ftch_decerr_set <= (others => '0');
ch_mm2s_ftch_err_early  <=  (others => '0');
ch_mm2s_ftch_stale_desc <=  (others => '0');
ch_mm2s_dma_interr_set <=  (others => '0');
ch_mm2s_dma_slverr_set <=  (others => '0');
ch_mm2s_dma_decerr_set <=  (others => '0');

UPDT_MM2S_ERROR_MULTI: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
ch_mm2s_updt_interr_set_i <=  (others => '0');
ch_mm2s_updt_slverr_set_i <=  (others => '0');
ch_mm2s_updt_decerr_set_i <=  (others => '0');
end generate UPDT_MM2S_ERROR_MULTI;

UPDT_MM2S_ERROR_SINGLE: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
ch_mm2s_updt_interr_set <=  (others => '0');
ch_mm2s_updt_slverr_set <=  (others => '0');
ch_mm2s_updt_decerr_set <=  (others => '0');
end generate UPDT_MM2S_ERROR_SINGLE;

ch_mm2s_updt_ioc_irq_set <=  (others => '0');


end generate NO_MM2S_ERROR_SIG;


updt_error_capture <= ch1_updt_interr_set_i or
                      ch1_updt_slverr_set_i or
                      ch1_updt_decerr_set_i or
                      ch2_updt_interr_set_i or
                      ch2_updt_slverr_set_i or
                      ch2_updt_decerr_set_i or
                      ch2_dma_interr_set_i or
                      ch2_dma_slverr_set_i or
                      ch2_dma_decerr_set_i or
                      ch1_dma_interr_set_i or
                      ch1_dma_slverr_set_i or
                      ch1_dma_decerr_set_i;



process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (m_axi_msg_aresetn = '0') then
           ftch_error_addr (31 downto 6) <= (others => '0');
        elsif (ftch_error_capture_mm2s = '1' or ftch_error_capture_s2mm = '1') then -- or updt_error_i = '1') then
           ftch_error_addr (31 downto 6)<= ftch_error_addr_1(31 downto 6);
        elsif (updt_error_capture = '1') then
           ftch_error_addr (31 downto 6)<= updt_error_addr_1(31 downto 6);
        end if;
     end if;
end process; 

ADDR_64 : if (C_M_AXI_SG_ADDR_WIDTH > 32) generate
begin

process (m_axi_msg_aclk)
begin
     if (m_axi_msg_aclk'event and m_axi_msg_aclk = '1') then
        if (m_axi_msg_aresetn = '0') then
           ftch_error_addr (63 downto 32) <= (others => '0');
        elsif (ftch_error_capture_mm2s = '1' or ftch_error_capture_s2mm = '1') then -- or updt_error_i = '1') then
           ftch_error_addr (63 downto 32)<= ftch_error_addr_1(63 downto 32);
        elsif (updt_error_capture = '1') then
           ftch_error_addr (63 downto 32)<= updt_error_addr_1(63 downto 32);
        end if;
     end if;
end process; 

end generate ADDR_64;

 updt_error_addr <= (others => '0');
 ftch_error_addr (5 downto 0) <= (others => '0');

-- Always valid therefore fix to '1'
s_axis_s2mm_tkeep       <= (others => '1');

s_axis_ch2_updtsts_tready <= s_axis_ch2_updtsts_tready_i;

-------------------------------------------------------------------------------
-- Scatter Gather Fetch Manager
-------------------------------------------------------------------------------
I_SG_FETCH_MNGR : entity axi_mcdma_v1_2_2.axi_msg_ftch_mngr
    generic map(
        C_M_AXI_SG_ADDR_WIDTH       => C_M_AXI_SG_ADDR_WIDTH                ,
        C_ENABLE_MULTI_CHANNEL             => C_ENABLE_MULTI_CHANNEL                      ,
        C_INCLUDE_CH1               => C_INCLUDE_CH1                        ,
        C_INCLUDE_CH2               => C_INCLUDE_CH2                        ,
        C_SG_CH1_WORDS_TO_FETCH     => C_SG_CH1_WORDS_TO_FETCH              ,
        C_SG_CH2_WORDS_TO_FETCH     => C_SG_CH2_WORDS_TO_FETCH              ,
        C_SG_CH1_ENBL_STALE_ERROR   => C_SG_CH1_ENBL_STALE_ERROR            ,
        C_SG_CH2_ENBL_STALE_ERROR   => C_SG_CH2_ENBL_STALE_ERROR            ,
        C_SG_FTCH_DESC2QUEUE        => SG_FTCH_DESC2QUEUE,
        C_NUM_MM2S_CHANNELS         => C_NUM_MM2S_CHANNELS                  ,
        C_NUM_S2MM_CHANNELS         => C_NUM_S2MM_CHANNELS                  ,
        C_MAX_CHANNELS              => C_MAX_CHANNELS                       ,
        C_ENABLE_MULTI_CH_RESET     => C_ENABLE_MULTI_CH_RESET
    )
    port map(
        -----------------------------------------------------------------------
        -- AXI Scatter Gather Interface
        -----------------------------------------------------------------------
        m_axi_msg_aclk               => m_axi_msg_aclk                        ,
        m_axi_msg_aresetn            => m_axi_msg_aresetn                     ,
        soft_rst_mm2s                => soft_int_rst                  ,
        soft_rst_s2mm                => soft_int_rst_s2mm                         ,
        ch_ftch_active_error             => ch_ftch_active_error                      ,

        -- MM2S Channel 1 Control and Status 
        ch_mm2s_run_stop                => ch_mm2s_run_stop_gen_i                        ,
        ch_mm2s_desc_flush              => ch_mm2s_desc_flush                       ,
        ch_mm2s_updt_done               => ch1_updt_done                        ,
        ch_mm2s_ftch_idle               => ch_mm2s_ftch_idle_i                        ,
        ch_mm2s_ftch_active             => ch_mm2s_ftch_active                      ,
        ch_mm2s_tailpntr_enabled        => ch_mm2s_tailpntr_enabled                 ,
        ch_mm2s_taildesc_wren           => ch_mm2s_taildesc_wren                    ,
        ch_mm2s_taildesc                => ch_mm2s_taildesc                         ,
        ch_mm2s_nxtdesc_wren            => ch_mm2s_nxtdesc_wren                     ,
        ch_mm2s_curdesc                 => ch_mm2s_curdesc                          ,
        ch_mm2s_ftch_queue_empty        => ch_mm2s_ftch_queue_empty                 ,
        ch_mm2s_ftch_queue_full         => ch_mm2s_ftch_queue_full                  ,
        ch_mm2s_ftch_pause              => ch_mm2s_ftch_pause                       ,

        mm2s_ftch_interr_set         => mm2s_ftch_interr_set_i                  ,
        mm2s_ftch_slverr_set         => mm2s_ftch_slverr_set_i                  ,
        mm2s_ftch_decerr_set         => mm2s_ftch_decerr_set_i                  ,
        mm2s_ftch_err_early          => mm2s_ftch_err_early_i                   ,
        mm2s_ftch_stale_desc         => mm2s_ftch_stale_desc_i                  ,
        mm2s_ftch_active             => mm2s_ftch_active                      , 
        mm2s_channel_ftch            => mm2s_channel_ftch                     ,
        mm2s_updt_done               => ch1_updt_done                         , 


        -- S2MM Channel 1 Control and Status
        ch_s2mm_run_stop                => ch_s2mm_run_stop_gen_i,--(0)                         ,
        ch_s2mm_desc_flush              => ch_s2mm_desc_flush,--(0)                       ,
        ch_s2mm_updt_done               => ch2_updt_done                        ,
        ch_s2mm_ftch_idle               => ch_s2mm_ftch_idle_i,--(0)                        ,
        ch_s2mm_ftch_active             => ch_s2mm_ftch_active                      ,
        ch_s2mm_tailpntr_enabled        => ch_s2mm_tailpntr_enabled,--(0)                 ,
        ch_s2mm_taildesc_wren           => ch_s2mm_taildesc_wren,--(0)                    ,
        ch_s2mm_taildesc                => ch_s2mm_taildesc                         ,
        ch_s2mm_nxtdesc_wren            => ch_s2mm_nxtdesc_wren                     ,
        ch_s2mm_curdesc                 => ch_s2mm_curdesc                          ,
        ch_s2mm_ftch_queue_empty        => ch_s2mm_ftch_queue_empty                 ,
        ch_s2mm_ftch_queue_full         => ch_s2mm_ftch_queue_full                  ,
        ch_s2mm_ftch_pause              => ch_s2mm_ftch_pause                       ,


        s2mm_ftch_interr_set         => s2mm_ftch_interr_set_i                  ,
        s2mm_ftch_slverr_set         => s2mm_ftch_slverr_set_i                  ,
        s2mm_ftch_decerr_set         => s2mm_ftch_decerr_set_i                  ,
        s2mm_ftch_err_early          => s2mm_ftch_err_early_i                   ,
        s2mm_ftch_stale_desc         => s2mm_ftch_stale_desc_i                  ,
        s2mm_ftch_active             => s2mm_ftch_active                      , 
        s2mm_channel_ftch            => s2mm_channel_ftch                     ,
        s2mm_updt_done               => ch2_updt_done                         , 

        nxtdesc                     => nxtdesc                              ,

        -- Read response for detecting slverr, decerr early
        m_axi_msg_rresp              => m_axi_msg_rresp                       ,
        m_axi_msg_rvalid             => m_axi_msg_rvalid                      ,

        -- User Command Interface Ports (AXI Stream)
        s_axis_ftch_cmd_tvalid      => s_axis_ftch_cmd_tvalid               ,
        s_axis_ftch_cmd_tready      => s_axis_ftch_cmd_tready               ,
        s_axis_ftch_cmd_tdata       => s_axis_ftch_cmd_tdata ((C_M_AXI_SG_ADDR_WIDTH+MSG_CMD_BASE_WIDTH)-1 downto 0)                ,

        -- User Status Interface Ports (AXI Stream)
        m_axis_ftch_sts_tvalid      => m_axis_ftch_sts_tvalid               ,
        m_axis_ftch_sts_tready      => m_axis_ftch_sts_tready               ,
        m_axis_ftch_sts_tdata       => m_axis_ftch_sts_tdata                ,
        m_axis_ftch_sts_tkeep       => m_axis_ftch_sts_tkeep                ,
        mm2s_err                    => mm2s_err                             ,

        -- DataMover Command
        ftch_cmnd_wr                => ftch_cmnd_wr                         ,
        ftch_cmnd_data              => ftch_cmnd_data                       ,
        ftch_stale_desc             => ftch_stale_desc                      ,
        updt_error                  => updt_error_i                         ,
        ftch_error                  => ftch_error_i                         ,
        ftch_error_addr             => ftch_error_addr_1                    

    );

