        -- S2MM Channel 1 Control
        ch_s2mm_desc_flush              => ch_s2mm_desc_flush                       ,
        ch_s2mm_ftch_active             => ch_s2mm_ftch_active                      ,
        ch_s2mm_nxtdesc_wren            => ch_s2mm_nxtdesc_wren                     ,
        ch_s2mm_cyclic                  => ch_s2mm_cyclic                     ,
        ch_s2mm_ftch_queue_empty        => ch_s2mm_ftch_queue_empty                 ,
        ch_s2mm_ftch_queue_full         => ch_s2mm_ftch_queue_full                  ,
        ch_s2mm_ftch_pause              => ch_s2mm_ftch_pause                       ,


        s2mm_channel_ftch            => s2mm_channel_ftch                     ,
        s2mm_ftch_active             => s2mm_ftch_active                      ,
        mm2s_channel_ftch            => (others => '0') ,--open, --mm2s_channel_ftch                     , 
        mm2s_ftch_active             => mm2s_ftch_active                      ,

        nxtdesc                     => nxtdesc                              ,

        -- DataMover Command
        ftch_cmnd_wr                => ftch_cmnd_wr                         ,
        ftch_cmnd_data              => ftch_cmnd_data                       ,
        ftch_stale_desc             => ftch_stale_desc                      ,

        -- MM2S Stream In from DataMover
        m_axis_mm2s_tdata           => m_axis_mm2s_tdata                    ,
        m_axis_mm2s_tkeep           => m_axis_mm2s_tkeep                    ,
        m_axis_mm2s_tlast           => m_axis_mm2s_tlast                    ,
        m_axis_mm2s_tvalid          => m_axis_mm2s_tvalid                   ,
        m_axis_mm2s_tready          => m_axis_mm2s_tready                   ,


        -- Channel 1 AXI Fetch Stream Out
        m_axis_ch1_ftch_aclk        => m_axis_ch1_ftch_aclk                 ,
        m_axis_ch1_ftch_tdata       => m_axis_ch1_ftch_tdata                ,
        m_axis_ch1_ftch_tvalid      => m_axis_ch1_ftch_tvalid               ,
        m_axis_ch1_ftch_data_valid      => m_axis_ch1_ftch_data_valid               ,
        m_axis_ch1_ftch_tready      => m_axis_ch1_ftch_tready               ,
        m_axis_ch1_ftch_tlast       => m_axis_ch1_ftch_tlast                ,
        m_axis_ch1_ftch_id          => m_axis_ch1_ftch_id                   ,

        -- Channel 2 AXI Fetch Stream Out
        m_axis_ch2_ftch_aclk        => m_axis_ch2_ftch_aclk                 ,
        m_axis_ch2_ftch_tdata       => m_axis_ch2_ftch_tdata                ,
        m_axis_ch2_ftch_tvalid      => m_axis_ch2_ftch_tvalid               ,
        m_axis_ch2_ftch_data_valid      => m_axis_ch2_ftch_data_valid               ,
        m_axis_ch2_ftch_tready      => m_axis_ch2_ftch_tready               ,
        m_axis_ch2_ftch_tlast       => m_axis_ch2_ftch_tlast                ,
        m_axis_ch2_ftch_id          => m_axis_ch2_ftch_id                   ,
                
        m_axis_mm2s_cntrl_tdata  => m_axis_mm2s_cntrl_tdata  ,
        m_axis_mm2s_cntrl_tkeep  => m_axis_mm2s_cntrl_tkeep  ,
        m_axis_mm2s_cntrl_tvalid => m_axis_mm2s_cntrl_tvalid ,
        m_axis_mm2s_cntrl_tready => m_axis_mm2s_cntrl_tready ,
        m_axis_mm2s_cntrl_tlast  => m_axis_mm2s_cntrl_tlast

