MULTI_INTERRUPT : if C_ENABLE_SINGLE_INTR = 0 generate
begin

mm2s_irqdelay_status <= (others => '0');
mm2s_irqthresh_status <= (others => '0');

mm2s_updt_ioc_irq_set <= '0';

GEN_MM2S_CH_INTR : for I in 0 to C_NUM_MM2S_CHANNELS-1 generate
begin

ch_mm2s_updt_ioc_irq_set_i(I) <= ch1_updt_ioc_irq_set_i and mm2s_channel(I);    

I_AXI_SG_INTRPT_CH1_MULTI_RST: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
m_axi_msg_resetn_gen(I) <= m_axi_msg_aresetn and soft_rstn_mm2s_ext(I);

    I_AXI_SG_INTRPT_CH1 : entity axi_mcdma_v1_2_2.axi_msg_intrpt
        generic map(
            C_INCLUDE_DLYTMR           => C_INCLUDE_DLYTMR                  ,
            C_DLYTMR_RESOLUTION        => C_DLYTMR_RESOLUTION
        )
        port map(

            -- Secondary Clock and Reset
            m_axi_msg_aclk               => m_axi_msg_aclk                    ,
            m_axi_msg_aresetn            => m_axi_msg_resetn_gen(I),

            ch_irqthresh_decr          => ch_mm2s_updt_ioc_irq_set_i(I), --'0', -- should be ioc_setch1_s2mm_irqthresh_decr               , -- CR567661
            ch_irqthresh_rstdsbl       => ch_mm2s_irqthresh_rstdsbl(I)            , -- CR572013
            ch_dlyirq_dsble            => ch_mm2s_dlyirq_dsble(I)                 ,
            ch_irqdelay_wren           => ch_mm2s_irqdelay_wren(I)                ,
            ch_irqdelay                => ch_mm2s_irqdelay(7+8*I downto 8*I)                     ,
            ch_irqthresh_wren          => ch_mm2s_irqthresh_wren(I)               ,
            ch_irqthresh               => ch_mm2s_irqthresh(7+8*I downto 8*I)                    ,
            ch_packet_sof              => ch_mm2s_packet_sof(I)                   ,
            ch_packet_eof              => ch_mm2s_packet_eof(I)                   ,
            ch_ioc_irq_set             => ch_mm2s_ioc_irq_set(I)                  ,
            ch_dly_irq_set             => ch_mm2s_dly_irq_set(I)                  ,
            ch_irqdelay_status         => ch_mm2s_irqdelay_status (7+8*I downto 8*I)             ,
            ch_irqthresh_status        => ch_mm2s_irqthresh_status (7+8*I downto 8*I)            ,
            ch_pkt_count               => ch_mm2s_pktcount (15+16*I downto 16*I) 

        );
end generate I_AXI_SG_INTRPT_CH1_MULTI_RST;

I_AXI_SG_INTRPT_CH1_SINGLE_RST: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
      I_AXI_SG_INTRPT_CH1 : entity axi_mcdma_v1_2_2.axi_msg_intrpt
        generic map(
            C_INCLUDE_DLYTMR           => C_INCLUDE_DLYTMR                  ,
            C_DLYTMR_RESOLUTION        => C_DLYTMR_RESOLUTION
        )
        port map(

            -- Secondary Clock and Reset
            m_axi_msg_aclk               => m_axi_msg_aclk                    ,
            m_axi_msg_aresetn            => m_axi_msg_aresetn                 ,

            ch_irqthresh_decr          => ch_mm2s_updt_ioc_irq_set_i(I), --'0', -- should be ioc_setch1_s2mm_irqthresh_decr               , -- CR567661
            ch_irqthresh_rstdsbl       => ch_mm2s_irqthresh_rstdsbl(I)            , -- CR572013
            ch_dlyirq_dsble            => ch_mm2s_dlyirq_dsble(I)                 ,
            ch_irqdelay_wren           => ch_mm2s_irqdelay_wren(I)                ,
            ch_irqdelay                => ch_mm2s_irqdelay(7+8*I downto 8*I)                     ,
            ch_irqthresh_wren          => ch_mm2s_irqthresh_wren(I)               ,
            ch_irqthresh               => ch_mm2s_irqthresh(7+8*I downto 8*I)                    ,
            ch_packet_sof              => ch_mm2s_packet_sof(I)                   ,
            ch_packet_eof              => ch_mm2s_packet_eof(I)                   ,
            ch_ioc_irq_set             => ch_mm2s_ioc_irq_set(I)                  ,
            ch_dly_irq_set             => ch_mm2s_dly_irq_set(I)                  ,
            ch_irqdelay_status         => ch_mm2s_irqdelay_status (7+8*I downto 8*I)             ,
            ch_irqthresh_status        => ch_mm2s_irqthresh_status (7+8*I downto 8*I)            ,
            ch_pkt_count               => ch_mm2s_pktcount (15+16*I downto 16*I) 

        );
end generate I_AXI_SG_INTRPT_CH1_SINGLE_RST;

end generate GEN_MM2S_CH_INTR;

