ch_mm2s_irqthresh_status (7+8*I downto 8*I) <= (others => '0');
ch_mm2s_pktcount (15+16*I downto 16*I) <= (others => '0');

end generate GEN_MM2S_CH_INTR;
end generate UNUSED_CH_INTR;

end generate MULTI_INTERRUPT;


