--ch_s2mm_irqthresh_status <= (others => '0');
--
--end generate SINGLE_INTERRUPT;


MULTI_INTERRUPT : if C_ENABLE_SINGLE_INTR = 0 generate
begin

s2mm_irqdelay_status <= (others => '0');
s2mm_irqthresh_status <= (others => '0');

s2mm_updt_ioc_irq_set <= '0';

GEN_S2MM_CH_INTR : for I in 0 to C_NUM_S2MM_CHANNELS-1 generate
begin

ch_s2mm_updt_ioc_irq_set_i(I) <= ch2_updt_ioc_irq_set_i and s2mm_channel(I);    

I_AXI_SG_INTRPT_CH2_SINGLE_RST: if C_ENABLE_MULTI_CH_RESET = 0 generate 
begin
    I_AXI_SG_INTRPT_CH2 : entity axi_mcdma_v1_2_2.axi_msg_intrpt
        generic map(
            C_INCLUDE_DLYTMR           => C_INCLUDE_DLYTMR                  ,
            C_DLYTMR_RESOLUTION        => C_DLYTMR_RESOLUTION
        )
        port map(

            -- Secondary Clock and Reset
            m_axi_msg_aclk               => m_axi_msg_aclk                    ,
            m_axi_msg_aresetn            => m_axi_msg_aresetn                 ,

            ch_irqthresh_decr          => ch_s2mm_updt_ioc_irq_set_i(I), --'0', -- should be ioc_setch1_s2mm_irqthresh_decr               , -- CR567661
            ch_irqthresh_rstdsbl       => ch_s2mm_irqthresh_rstdsbl(I)            , -- CR572013
            ch_dlyirq_dsble            => ch_s2mm_dlyirq_dsble(I)                 ,
            ch_irqdelay_wren           => ch_s2mm_irqdelay_wren(I)                ,
            ch_irqdelay                => ch_s2mm_irqdelay(7+8*I downto 8*I)                     ,
            ch_irqthresh_wren          => ch_s2mm_irqthresh_wren(I)               ,
            ch_irqthresh               => ch_s2mm_irqthresh(7+8*I downto 8*I)                    ,
            ch_packet_sof              => ch_s2mm_packet_sof(I)                   ,
            ch_packet_eof              => ch_s2mm_packet_eof(I)                   ,
            ch_ioc_irq_set             => ch_s2mm_ioc_irq_set(I)                  ,
            ch_dly_irq_set             => ch_s2mm_dly_irq_set(I)                  ,
            ch_irqdelay_status         => ch_s2mm_irqdelay_status (7+8*I downto 8*I)             ,
            ch_irqthresh_status        => ch_s2mm_irqthresh_status (7+8*I downto 8*I)            ,
            ch_pkt_count               => ch_s2mm_pktcount (15+16*I downto 16*I) 

        );
end generate I_AXI_SG_INTRPT_CH2_SINGLE_RST;

I_AXI_SG_INTRPT_CH2_MULTI_RST: if C_ENABLE_MULTI_CH_RESET = 1 generate 
begin
  
m_axi_msg_resetn_s2mm_gen(I) <= m_axi_msg_aresetn and soft_rstn_s2mm_ext(I);

    I_AXI_SG_INTRPT_CH2 : entity axi_mcdma_v1_2_2.axi_msg_intrpt
        generic map(
            C_INCLUDE_DLYTMR           => C_INCLUDE_DLYTMR                  ,
            C_DLYTMR_RESOLUTION        => C_DLYTMR_RESOLUTION
        )
        port map(

            -- Secondary Clock and Reset
            m_axi_msg_aclk               => m_axi_msg_aclk                    ,
            m_axi_msg_aresetn            => m_axi_msg_resetn_s2mm_gen(I)      ,

            ch_irqthresh_decr          => ch_s2mm_updt_ioc_irq_set_i(I), --'0', -- should be ioc_setch1_s2mm_irqthresh_decr               , -- CR567661
            ch_irqthresh_rstdsbl       => ch_s2mm_irqthresh_rstdsbl(I)            , -- CR572013
            ch_dlyirq_dsble            => ch_s2mm_dlyirq_dsble(I)                 ,
            ch_irqdelay_wren           => ch_s2mm_irqdelay_wren(I)                ,
            ch_irqdelay                => ch_s2mm_irqdelay(7+8*I downto 8*I)                     ,
            ch_irqthresh_wren          => ch_s2mm_irqthresh_wren(I)               ,
            ch_irqthresh               => ch_s2mm_irqthresh(7+8*I downto 8*I)                    ,
            ch_packet_sof              => ch_s2mm_packet_sof(I)                   ,
            ch_packet_eof              => ch_s2mm_packet_eof(I)                   ,
            ch_ioc_irq_set             => ch_s2mm_ioc_irq_set(I)                  ,
            ch_dly_irq_set             => ch_s2mm_dly_irq_set(I)                  ,
            ch_irqdelay_status         => ch_s2mm_irqdelay_status (7+8*I downto 8*I)             ,
            ch_irqthresh_status        => ch_s2mm_irqthresh_status (7+8*I downto 8*I)            ,
            ch_pkt_count               => ch_s2mm_pktcount (15+16*I downto 16*I) 

        );
end generate I_AXI_SG_INTRPT_CH2_MULTI_RST;

end generate GEN_S2MM_CH_INTR;

UNUSED_CH_INTR : if C_NUM_S2MM_CHANNELS < C_MAX_CHANNELS generate
begin

GEN_S2MM_CH_INTR : for I in C_NUM_S2MM_CHANNELS to C_MAX_CHANNELS-1 generate
begin

ch_s2mm_ioc_irq_set(I)                  <= '0';
ch_s2mm_dly_irq_set(I)                  <= '0';
ch_s2mm_irqdelay_status (7+8*I downto 8*I)  <= (others => '0');
ch_s2mm_irqthresh_status (7+8*I downto 8*I) <= (others => '0');
ch_s2mm_pktcount (15+16*I downto 16*I) <= (others => '0');
end generate GEN_S2MM_CH_INTR;
end generate UNUSED_CH_INTR;

end generate MULTI_INTERRUPT;

end generate S2MM_INCLUDED;

end generate GEN_INTERRUPT_LOGIC;



-------------------------------------------------------------------------------
-- Scatter Gather DataMover Lite
-------------------------------------------------------------------------------

I_SG_AXI_DATAMOVER : entity axi_mcdma_v1_2_2.axi_msg_datamover
    generic map(
        C_INCLUDE_MM2S              => 2, --INCLUDE_DESC_FETCH,          -- Lite
        C_M_AXI_MM2S_ADDR_WIDTH     => C_M_AXI_SG_ADDR_WIDTH,       -- 32 or 64
        C_M_AXI_MM2S_DATA_WIDTH     => C_M_AXI_SG_DATA_WIDTH,       -- Fixed at 32
        C_M_AXIS_MM2S_TDATA_WIDTH   => C_M_AXI_SG_DATA_WIDTH,       -- Fixed at 32
        C_INCLUDE_MM2S_STSFIFO      => 0,                           -- Exclude
        C_MM2S_STSCMD_FIFO_DEPTH    => 1,                           -- Set to Min
        C_MM2S_STSCMD_IS_ASYNC      => 0,                           -- Synchronous
        C_INCLUDE_MM2S_DRE          => 0,                           -- No DRE
        C_MM2S_BURST_SIZE           => 16,                          -- Set to Min
        C_MM2S_ADDR_PIPE_DEPTH      => 1,                           -- Only 1 outstanding request
        C_MM2S_INCLUDE_SF           => 0,                           -- Exclude Store-and-Forward
    
        C_ENABLE_MULTI_CHANNEL             => C_ENABLE_MULTI_CHANNEL,                           --  
        C_ENABLE_EXTRA_FIELD        => C_ENABLE_EXTRA_FIELD,

        C_INCLUDE_S2MM              => 2, --INCLUDE_DESC_UPDATE,         -- Lite
        C_M_AXI_S2MM_ADDR_WIDTH     => C_M_AXI_SG_ADDR_WIDTH,       -- 32 or 64
        C_M_AXI_S2MM_DATA_WIDTH     => C_M_AXI_SG_DATA_WIDTH,       -- Fixed at 32
        C_S_AXIS_S2MM_TDATA_WIDTH   => C_M_AXI_SG_DATA_WIDTH,       -- Fixed at 32
        C_INCLUDE_S2MM_STSFIFO      => 0,                           -- Exclude
        C_S2MM_STSCMD_FIFO_DEPTH    => 1,                           -- Set to Min
        C_S2MM_STSCMD_IS_ASYNC      => 0,                           -- Synchronous
        C_INCLUDE_S2MM_DRE          => 0,                           -- No DRE
        C_S2MM_BURST_SIZE           => 16,                          -- Set to Min;
        C_S2MM_ADDR_PIPE_DEPTH      => 1,                           -- Only 1 outstanding request
        C_S2MM_INCLUDE_SF           => 0,                           -- Exclude Store-and-Forward
        C_FAMILY                    => C_FAMILY
    )
    port map(
        -- MM2S Primary Clock / Reset input
        m_axi_mm2s_aclk             => m_axi_msg_aclk                        ,
        m_axi_mm2s_aresetn          => dm_rstn_ftch_i              ,
        mm2s_halt                   => NEVER_HALT                  ,
        mm2s_halt_cmplt             => open                        ,
        mm2s_err                    => mm2s_err                             ,
        mm2s_allow_addr_req         => ALWAYS_ALLOW                         ,
        mm2s_addr_req_posted        => mm2s_addr_req_posted_i                 ,
        mm2s_rd_xfer_cmplt          => open                                 ,

        sg_ctl                      => sg_ctl                               ,

        -- Memory Map to Stream Command FIFO and Status FIFO I/O --------------
        m_axis_mm2s_cmdsts_aclk     => m_axi_msg_aclk                        ,
        m_axis_mm2s_cmdsts_aresetn  => dm_rstn_ftch_i                      ,

        -- User Command Interface Ports (AXI Stream)
        s_axis_mm2s_cmd_tvalid      => s_axis_ftch_cmd_tvalid               ,
        s_axis_mm2s_cmd_tready      => s_axis_ftch_cmd_tready               ,
        s_axis_mm2s_cmd_tdata       => s_axis_ftch_cmd_tdata                ,

        -- User Status Interface Ports (AXI Stream)
        m_axis_mm2s_sts_tvalid      => m_axis_ftch_sts_tvalid               ,
        m_axis_mm2s_sts_tready      => m_axis_ftch_sts_tready               ,
        m_axis_mm2s_sts_tdata       => m_axis_ftch_sts_tdata                ,
        m_axis_mm2s_sts_tkeep       => m_axis_ftch_sts_tkeep                ,


        -- MM2S AXI Address Channel I/O  --------------------------------------
        m_axi_mm2s_arid             => open                                 ,
        m_axi_mm2s_araddr           => m_axi_msg_araddr                      ,
        m_axi_mm2s_arlen            => m_axi_msg_arlen                       ,
        m_axi_mm2s_arsize           => m_axi_msg_arsize                      ,
        m_axi_mm2s_arburst          => m_axi_msg_arburst                     ,
        m_axi_mm2s_arprot           => m_axi_msg_arprot                      ,
        m_axi_mm2s_arcache          => m_axi_msg_arcache                     ,
        m_axi_mm2s_aruser           => m_axi_msg_aruser                     ,
        m_axi_mm2s_arvalid          => m_axi_msg_arvalid                     ,
        m_axi_mm2s_arready          => m_axi_msg_arready                     ,

        -- MM2S AXI MMap Read Data Channel I/O  -------------------------------
        m_axi_mm2s_rdata            => m_axi_msg_rdata                       ,
        m_axi_mm2s_rresp            => m_axi_msg_rresp                       ,
        m_axi_mm2s_rlast            => m_axi_msg_rlast                       ,
        m_axi_mm2s_rvalid           => m_axi_msg_rvalid                      ,
        m_axi_mm2s_rready           => m_axi_msg_rready                      ,

        -- MM2S AXI Master Stream Channel I/O  --------------------------------
        m_axis_mm2s_tdata           => m_axis_mm2s_tdata                    ,
        m_axis_mm2s_tkeep           => m_axis_mm2s_tkeep                    ,
        m_axis_mm2s_tlast           => m_axis_mm2s_tlast                    ,
        m_axis_mm2s_tvalid          => m_axis_mm2s_tvalid                   ,
        m_axis_mm2s_tready          => m_axis_mm2s_tready                   ,


        -- Testing Support I/O
        mm2s_dbg_sel                => (others => '0')                      ,
        mm2s_dbg_data               => open                                 ,

        -- S2MM Primary Clock/Reset input
        m_axi_s2mm_aclk             => m_axi_msg_aclk                        ,
        m_axi_s2mm_aresetn          => dm_rstn_updt_i                      ,
        s2mm_halt                   => NEVER_HALT                           ,
        s2mm_halt_cmplt             => open                                 ,
        s2mm_err                    => s2mm_err                             ,
        s2mm_allow_addr_req         => ALWAYS_ALLOW                         ,
        s2mm_addr_req_posted        => s2mm_addr_req_posted_i                                 ,
        s2mm_wr_xfer_cmplt          => open                                 ,
        s2mm_ld_nxt_len             => open                                 ,
        s2mm_wr_len                 => open                                 ,

        -- Stream to Memory Map Command FIFO and Status FIFO I/O --------------
        m_axis_s2mm_cmdsts_awclk    => m_axi_msg_aclk                        ,
        m_axis_s2mm_cmdsts_aresetn  => dm_rstn_updt_i                            ,

        -- User Command Interface Ports (AXI Stream)
        s_axis_s2mm_cmd_tvalid      => s_axis_updt_cmd_tvalid               ,
        s_axis_s2mm_cmd_tready      => s_axis_updt_cmd_tready               ,
        s_axis_s2mm_cmd_tdata       => s_axis_updt_cmd_tdata                ,

        -- User Status Interface Ports (AXI Stream)
        m_axis_s2mm_sts_tvalid      => m_axis_updt_sts_tvalid               ,
        m_axis_s2mm_sts_tready      => m_axis_updt_sts_tready               ,
        m_axis_s2mm_sts_tdata       => m_axis_updt_sts_tdata                ,
        m_axis_s2mm_sts_tkeep       => m_axis_updt_sts_tkeep                ,

        -- S2MM AXI Address Channel I/O  --------------------------------------
        m_axi_s2mm_awid             => open                                 ,
        m_axi_s2mm_awaddr           => m_axi_msg_awaddr_int                      ,
        m_axi_s2mm_awlen            => m_axi_msg_awlen_int                      ,
        m_axi_s2mm_awsize           => m_axi_msg_awsize_int                      ,
        m_axi_s2mm_awburst          => m_axi_msg_awburst_int                     ,
        m_axi_s2mm_awprot           => m_axi_msg_awprot_int                     ,
        m_axi_s2mm_awcache          => m_axi_msg_awcache_int                     ,
        m_axi_s2mm_awuser           => m_axi_msg_awuser_int                       ,
        m_axi_s2mm_awvalid          => m_axi_msg_awvalid_int                    ,
        m_axi_s2mm_awready          => m_axi_msg_awready_int                     ,

        -- S2MM AXI MMap Write Data Channel I/O  ------------------------------
        m_axi_s2mm_wdata            => m_axi_msg_wdata                       ,
        m_axi_s2mm_wstrb            => m_axi_msg_wstrb                       ,
        m_axi_s2mm_wlast            => m_axi_msg_wlast                       ,
        m_axi_s2mm_wvalid           => m_axi_msg_wvalid_int                      ,
        m_axi_s2mm_wready           => m_axi_msg_wready_int                      ,

        -- S2MM AXI MMap Write response Channel I/O  --------------------------
        m_axi_s2mm_bresp            => m_axi_msg_bresp_int                       ,
        m_axi_s2mm_bvalid           => m_axi_msg_bvalid_int                      ,
        m_axi_s2mm_bready           => m_axi_msg_bready_int                      ,

        -- S2MM AXI Slave Stream Channel I/O  ---------------------------------
        s_axis_s2mm_tdata           => s_axis_s2mm_tdata                    ,
        s_axis_s2mm_tkeep           => s_axis_s2mm_tkeep                    ,
        s_axis_s2mm_tlast           => s_axis_s2mm_tlast                    ,
        s_axis_s2mm_tvalid          => s_axis_s2mm_tvalid                   ,
        s_axis_s2mm_tready          => s_axis_s2mm_tready                   ,

        -- Testing Support I/O
        s2mm_dbg_sel                  => (others => '0')                    ,
        s2mm_dbg_data                 => open
    );


 m_axi_msg_awaddr <= m_axi_msg_awaddr_int ;
 m_axi_msg_awlen <= m_axi_msg_awlen_int  ;
 m_axi_msg_awsize <= m_axi_msg_awsize_int ;
 m_axi_msg_awburst <= m_axi_msg_awburst_int;
 m_axi_msg_awprot <= m_axi_msg_awprot_int ;
 m_axi_msg_awcache <= m_axi_msg_awcache_int;
 m_axi_msg_awuser <= m_axi_msg_awuser_int ;
 m_axi_msg_awvalid <= m_axi_msg_awvalid_int;
 m_axi_msg_awready_int <= m_axi_msg_awready;

 m_axi_msg_wvalid <= m_axi_msg_wvalid_int;
 m_axi_msg_wready_int <= m_axi_msg_wready;

 m_axi_msg_bresp_int <= m_axi_msg_bresp;
 m_axi_msg_bvalid_int <= m_axi_msg_bvalid;
 m_axi_msg_bready <= m_axi_msg_bready_int; 





end implementation;



