---------------------------------------------------------------------------
-- DMA Status Register
---------------------------------------------------------------------------
dmasr_i    <=  irqdelay_status         -- Bits 31 downto 24
             & irqthresh_status        -- Bits 23 downto 16
             & pktirqthresh_status     -- Bit  15 downto 8
             & err_irq          -- Bit  7
             & dly_irq          -- Bit  6
             & ioc_irq          -- Bit  5
             & pktdrp_irq              -- Bit  4
             & '0'        -- Bit  3
             & '0'        -- Bit  2
             & idle              -- Bit  1
             & halted;    -- Bit 0  


dmaerr_i <= "0000000000000000000000000"
            &   sg_decerr
            &   sg_slverr
            &   sg_interr
            &   '0'
            &   dma_decerr
            &   dma_slverr
            &   dma_interr;

end implementation;



