---------------------------------------------------------------------------
-- DMA Status Register
---------------------------------------------------------------------------
dmasr_i    <=  irqdelay_status         -- Bits 31 downto 24
             & irqthresh_status        -- Bits 23 downto 16
             & pktirqthresh_status     -- Bit  15 downto 8
             & err_irq          -- Bit  7
             & dly_irq          -- Bit  6
             & ioc_irq          -- Bit  5
             & '0'              -- Bit  4
             & '0'        -- Bit  3
             & '0'        -- Bit  2
             & idle              -- Bit  1
             & halted;    -- Bit 0  

--sg_decerr <= '0' when  (unsigned(sg_decerr_ch ) = 0) else '1';
--sg_slverr <= '0' when  (unsigned(sg_slverr_ch ) = 0) else '1';
--sg_interr <= '0' when  (unsigned(sg_interr_ch ) = 0) else '1';
--dma_decerr <= '0' when (unsigned(dma_decerr_ch) = 0) else '1';
--dma_slverr <= '0' when (unsigned(dma_slverr_ch) = 0) else '1';
--dma_interr <= '0' when (unsigned(dma_interr_ch) = 0) else '1';


dmaerr_i <= "0000000000000000000000000"
            &   sg_decerr
            &   sg_slverr
            &   sg_interr
            &   '0'
            &   dma_decerr
            &   dma_slverr
            &   dma_interr;

end implementation;



