signal mm2s_run_stop_common : std_logic; 
signal mm2s_halted_common : std_logic; 
--signal mm2s_timeout       : std_logic_vector(13 downto 0);
begin


    I_MM2S_COMMON_REGISTER : entity axi_mcdma_v1_2_2.axi_mcdma_mm2s_common_register
    generic map (
