        ch_service                  => '0',
        channel_service_run         => '0'          ,
        dma_run_stop                => mm2s_run_stop_common     ,
        dma_halted                  => mm2s_halted_common       ,
        halted_clr                  => mm2s_ch_halted_clr(I)          ,
        halted_set                  => mm2s_ch_halted_set(I)          ,
        idle_set                    => mm2s_ch_idle_set(I)            ,
        idle_clr                    => mm2s_ch_idle_clr(I)            ,
