                when S2MM_CMN_INTR_OFFSET =>
                    ip2axi_rddata_s2mm_cmn <= s2mm_ch_intr_status;
          -- coverage off
                when others =>
                    ip2axi_rddata_s2mm_cmn <= (others => '0');
