                when "011" =>
                    ip2axi_rddata_s2mm_ch2 <= ip2axi_rddata_s2mm_ch (255 downto 224);
          -- coverage off
                when others =>
                    ip2axi_rddata_s2mm_ch2 <= (others => '0');
          -- coverage on
            end case;
        end process AXI_LITE_READ_MUX_CH1;

end generate CHANNELS_2;


