                    ip2axi_rddata_s2mm_ch3 <= ip2axi_rddata_s2mm_ch (319 downto 288);
                when "110" =>
                    ip2axi_rddata_s2mm_ch3 <= ip2axi_rddata_s2mm_ch (351 downto 320);
                when "111" =>
                    ip2axi_rddata_s2mm_ch3 <= ip2axi_rddata_s2mm_ch (383 downto 352);
          -- coverage off
