                when "001"  =>
                    ip2axi_rddata_s2mm_ch4 <= ip2axi_rddata_s2mm_ch (447 downto 416);
                when "010" =>
                    ip2axi_rddata_s2mm_ch4 <= ip2axi_rddata_s2mm_ch (479 downto 448);
                when "011" =>
                    ip2axi_rddata_s2mm_ch4 <= ip2axi_rddata_s2mm_ch (511 downto 480);
          -- coverage off
