    AXI_LITE_READ_MUX_CH1 : process(read_addr(8 downto 6)            ,
                                ip2axi_rddata_s2mm_ch(543 downto 512)             ,
                                ip2axi_rddata_s2mm_obs_ch 
)
        begin
