   if (m_axi_sg_aclk'event and m_axi_sg_aclk = '1') then

         case (axi2ip_rdaddr(11 downto 8)) is
             when "0000" =>
                ip2axi_rddata <= ip2axi_rddata_mm2s_ch1; 

