SG_CHANNEL_ID_CDC : xpm_cdc_array_single
generic map (
  DEST_SYNC_FF   => 2,
  SRC_INPUT_REG  => 1,
  WIDTH          => C_MAX_CHANNELS,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => m_axi_s2mm_aclk,
  src_in   => channel_id_i,
  dest_clk => m_axi_sg_aclk,
  dest_out => channel_id_i2
  );

process (m_axi_sg_aclk)
begin
   if (m_axi_sg_aclk'event and m_axi_sg_aclk = '1') then
      if (m_axi_sg_aresetn_gen = '0') then
         sg_channel_id_int <= (others => '0');
         window <= '0';
      elsif (to_be_serviced_trig = '1') then
         sg_channel_id_int <= channel_id_i2;
         window <= '1';
      elsif (eof_detected = '1' and hold = '0') then 
         sg_channel_id_int <= (others => '0');
         window <= '0';
      elsif (eof_detected = '1' and hold = '1') then
         sg_channel_id_int <= channel_id_i2;
         window <= '1';
      end if;
   end if;
end process; 


process (m_axi_sg_aclk)
begin
   if (m_axi_sg_aclk'event and m_axi_sg_aclk = '1') then
      if (m_axi_sg_aresetn_gen = '0') then
          hold <= '0';
      elsif (window = '1' and to_be_serviced_trig = '1' and eof_detected = '0') then
          hold <= '1';
      elsif (eof_detected = '1') then
          hold <= '0';
      end if;
   end if;
end process;



