  dest_clk => m_axi_s2mm_aclk,
  dest_out => ch_s2mm_pktirqthresh_s2mm (8+8*I-1 downto 8*I)
  );


PKTDRP_THRESH_WREN_CDC : xpm_cdc_pulse
generic map (
