  dest_rst   => m_axi_s2mm_areset,
  dest_pulse => ch_s2mm_pktirqthresh_wren_s2mm(I)
  );

PKTDRP_RST_CDC : xpm_cdc_pulse
generic map (
  DEST_SYNC_FF   => 4,
  RST_USED       => 1,
  REG_OUTPUT     => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk    => m_axi_sg_aclk,
  src_rst    => m_axi_sg_areset,
  src_pulse  => ch_s2mm_pktdrp_reset(I),
  dest_clk   => m_axi_s2mm_aclk,
  dest_rst   => m_axi_s2mm_areset,
  dest_pulse => ch_s2mm_pktdrp_reset_s2mm(I)
  );

    CH_STAT : entity axi_mcdma_v1_2_2.axi_mcdma_pkt_drop
     generic map (
             C_CHANNEL_ID      => I,
             C_COMMON          => 1,
             C_ENABLE_DROP_CNT => C_ENABLE_DROP_CNT,
             C_ENABLE_SINGLE_INTR => C_ENABLE_SINGLE_INTR
             )
     port map (
           m_axi_sg_aclk           => m_axi_s2mm_aclk,
           m_axi_sg_aresetn        => m_axi_s2mm_aresetn, 
           packet_dropped          => packet_dropped,
           dropped_ch_id           => dropped_id_s2mm,

           packet_thresh           => ch_s2mm_pktirqthresh_s2mm(8+8*I-1 downto 8*I),  
           packet_thresh_wren      => ch_s2mm_pktirqthresh_wren_s2mm(I),
           packet_thresh_sts       => ch_s2mm_pktirqthresh_status_s2mm(8+8*I-1 downto 8*I),
           packet_irq              => ch_s2mm_pktdrp_irq_set_s2mm(I),

           reset_pkt_drp_count     => ch_s2mm_pktdrp_reset_s2mm(I), 
           channel_packet_drop_cnt => ch_s2mm_pktdrp_count_s2mm(16+16*I-1 downto 16*I),
           total_packet_drop_cnt   => open
          );



PKTDRP_COUNT_CDC : xpm_cdc_array_single
generic map (
  DEST_SYNC_FF   => 3,
  SRC_INPUT_REG  => 0,
  WIDTH          => 16,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => ch_s2mm_pktdrp_count_s2mm (16+16*I-1 downto 16*I),
  dest_clk => m_axi_sg_aclk,
  dest_out => ch_s2mm_pktdrp_count (16+16*I-1 downto 16*I)
  );


PKTDRP_THRESH_STS_CDC : xpm_cdc_array_single
generic map (
  DEST_SYNC_FF   => 3,
  SRC_INPUT_REG  => 0,
  WIDTH          => 8,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => ch_s2mm_pktirqthresh_status_s2mm (8+8*I-1 downto 8*I),
  dest_clk => m_axi_sg_aclk,
  dest_out => ch_s2mm_pktirqthresh_status (8+8*I-1 downto 8*I)
  );

process (m_axi_s2mm_aclk)
begin
   if (m_axi_s2mm_aclk'event and m_axi_s2mm_aclk = '1') then
      if (m_axi_s2mm_aresetn = '0') then
         ch_s2mm_pktdrp_irq_set_s2mm_del(I) <= '0';
      else
         ch_s2mm_pktdrp_irq_set_s2mm_del(I) <= ch_s2mm_pktdrp_irq_set_s2mm(I);
      end if;
   end if;
end process;

ch_s2mm_pktdrp_irq_set_s2mm_pulse (I) <= ch_s2mm_pktdrp_irq_set_s2mm (I) and (not ch_s2mm_pktdrp_irq_set_s2mm_del (I));


PKTDRP_IRQ_SET_CDC : xpm_cdc_pulse
generic map (
  DEST_SYNC_FF   => 4,
  RST_USED       => 1,
  REG_OUTPUT     => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk    => m_axi_s2mm_aclk,
  src_rst    => m_axi_s2mm_areset,
  src_pulse  => ch_s2mm_pktdrp_irq_set_s2mm_pulse (I),
  dest_clk   => m_axi_sg_aclk,
  dest_rst   => m_axi_sg_areset,
  dest_pulse => ch_s2mm_pktdrp_irq_set (I)
  );

end generate CHANNEL_STAT;

UNUSED_CHANNELS: if C_MAX_CHANNELS > C_NUM_S2MM_CHANNELS generate
begin


CHANNEL_STAT : for I in C_NUM_S2MM_CHANNELS to C_MAX_CHANNELS-1 generate
begin

ch_s2mm_pktirqthresh_status(8+8*I-1 downto 8*I) <= (others => '0');
ch_s2mm_pktdrp_irq_set(I) <= '0';
ch_s2mm_pktdrp_count(16+16*I-1 downto 16*I) <= (others => '0');

end generate CHANNEL_STAT;
end generate UNUSED_CHANNELS;

end generate ASYNC_CLOCKS_INTR;

end implementation;


