library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;
use IEEE.std_logic_arith.all;
use IEEE.std_logic_unsigned.all;


library unisim;
use unisim.vcomponents.all;

library xpm;
use xpm.vcomponents.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;


 
entity axi_mcdma_cmd_split is
     generic (
             C_ADDR_WIDTH  : integer range 32 to 64    := 32;
             C_DM_STATUS_WIDTH               : integer range 8 to 32         := 8;
             C_INCLUDE_S2MM : integer range 0 to 1     := 0 
             );
     port (
           clock : in std_logic;
           sgresetn : in std_logic;
           clock_sec : in std_logic;
           aresetn : in std_logic;

   -- command coming from _MNGR 
           s_axis_cmd_tvalid : in std_logic;
           s_axis_cmd_tready : out std_logic;
           s_axis_cmd_tdata  : in std_logic_vector ((C_ADDR_WIDTH-32+2*32+CMD_BASE_WIDTH+46)-1 downto 0);

   -- split command to DM
           s_axis_cmd_tvalid_s : out std_logic;
           s_axis_cmd_tready_s : in std_logic;
           s_axis_cmd_tdata_s  : out std_logic_vector ((C_ADDR_WIDTH+CMD_BASE_WIDTH+8)-1 downto 0);
   -- Tvalid from Datamover
           tvalid_from_datamover    : in std_logic;
           status_in                : in std_logic_vector (C_DM_STATUS_WIDTH-1 downto 0);
           tvalid_unsplit           : out std_logic;
           status_out               : out std_logic_vector (C_DM_STATUS_WIDTH-1 downto 0);

   -- Tlast of stream data from Datamover
           tlast_stream_data        : in std_logic;
           tready_stream_data        : in std_logic;
           tlast_unsplit            : out std_logic;  
           tlast_unsplit_user       : out std_logic  

          );
end entity axi_mcdma_cmd_split;

architecture implementation of axi_mcdma_cmd_split is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";


type SPLIT_MM2S_STATE_TYPE      is (
                                IDLE,
                                SEND,
                                SPLIT
                                );

signal mm2s_cs                  : SPLIT_MM2S_STATE_TYPE;
signal mm2s_ns                  : SPLIT_MM2S_STATE_TYPE;

signal mm2s_cmd    : std_logic_vector (C_ADDR_WIDTH-32+2*32+CMD_BASE_WIDTH+46-1 downto 0);
signal command_ns    : std_logic_vector (C_ADDR_WIDTH-32+2*32+CMD_BASE_WIDTH-1 downto 0);
signal command    : std_logic_vector (C_ADDR_WIDTH-32+2*32+CMD_BASE_WIDTH-1 downto 0);

signal cache_info  : std_logic_vector (31 downto 0);
signal vsize_data  : std_logic_vector (22 downto 0);
signal vsize_data_int  : std_logic_vector (22 downto 0);
signal vsize       : std_logic_vector (22 downto 0);
signal counter     : std_logic_vector (22 downto 0);
signal counter_tlast     : std_logic_vector (22 downto 0);
signal split_cmd   : std_logic_vector (31+(C_ADDR_WIDTH-32) downto 0);
signal stride_data : std_logic_vector (22 downto 0);
signal vsize_over   : std_logic;

signal cmd_proc_cdc_from    : std_logic;
signal cmd_proc_cdc_to    : std_logic;
signal cmd_proc_cdc    : std_logic;
signal cmd_proc_ns    : std_logic;
  ATTRIBUTE async_reg                      : STRING;
--  ATTRIBUTE async_reg OF cmd_proc_cdc_to  : SIGNAL IS "true";
--  ATTRIBUTE async_reg OF cmd_proc_cdc  : SIGNAL IS "true";


signal cmd_out    : std_logic;
signal cmd_out_ns    : std_logic;

signal split_out    : std_logic;
signal split_out_ns    : std_logic;

signal command_valid : std_logic;
signal command_valid_ns : std_logic;
signal command_ready : std_logic;
signal reset_lock : std_logic;
signal reset_lock_tlast : std_logic;


signal tvalid_unsplit_int : std_logic;
signal tlast_stream_data_int : std_logic;

signal ready_for_next_cmd : std_logic;
signal ready_for_next_cmd_tlast : std_logic;
signal ready_for_next_cmd_tlast_cdc_from : std_logic;
signal ready_for_next_cmd_tlast_cdc_to : std_logic;
signal ready_for_next_cmd_tlast_cdc : std_logic;

--  ATTRIBUTE async_reg OF ready_for_next_cmd_tlast_cdc_to  : SIGNAL IS "true";
--  ATTRIBUTE async_reg OF ready_for_next_cmd_tlast_cdc  : SIGNAL IS "true";

signal tmp1, tmp2, tmp3, tmp4 : std_logic;
signal tlast_int : std_logic;

signal eof_bit : std_logic;
signal eof_bit_cdc_from : std_logic;
signal eof_bit_cdc_to : std_logic;
signal eof_bit_cdc : std_logic;
signal eof_set : std_logic;
signal over_ns, over : std_logic;

signal cmd_in : std_logic;

signal status_out_int : std_logic_vector (C_DM_STATUS_WIDTH-1 downto 0);

begin

s_axis_cmd_tvalid_s <= command_valid;
command_ready <= s_axis_cmd_tready_s;
s_axis_cmd_tdata_s <= command (103+(C_ADDR_WIDTH-32) downto 96+(C_ADDR_WIDTH-32)) & command (71+(C_ADDR_WIDTH-32) downto 0);


REGISTER_STATE_MM2S : process(clock)
    begin
        if(clock'EVENT and clock = '1')then
            if(sgresetn = '0')then
                mm2s_cs     <= IDLE;
                cmd_proc_cdc_from <= '0';
                cmd_out <= '0';
                command <= (others => '0');
                command_valid <= '0';
                split_out <= '0';
                over <= '0';
            else
                mm2s_cs     <= mm2s_ns;
                cmd_proc_cdc_from <= cmd_proc_ns;
                cmd_out <= cmd_out_ns;
                command <= command_ns;
                command_valid <= command_valid_ns;
                split_out <= split_out_ns;
                over <= over_ns;
            end if;
        end if;
    end process REGISTER_STATE_MM2S;


-- grab the MM2S command coming from MM2S_mngr
REGISTER_MM2S_CMD : process(clock)
    begin
        if(clock'EVENT and clock = '1')then
            if(sgresetn = '0')then
                mm2s_cmd <= (others => '0');
                s_axis_cmd_tready <= '0';
                cache_info <= (others => '0');
                vsize_data <= (others => '0');
                vsize_data_int <= (others => '0');
                stride_data <= (others => '0');
                eof_bit_cdc_from <= '0';
                cmd_in <= '0';
            elsif (s_axis_cmd_tvalid = '1' and ready_for_next_cmd = '1' and cmd_proc_cdc_from = '0' and ready_for_next_cmd_tlast_cdc = '1') then  -- when there is no processing being done, means it is ready to accept
                mm2s_cmd     <= s_axis_cmd_tdata;
                s_axis_cmd_tready <= '1';
                cache_info <= s_axis_cmd_tdata (149+(C_ADDR_WIDTH-32) downto 118+(C_ADDR_WIDTH-32));
                vsize_data <= s_axis_cmd_tdata (117+(C_ADDR_WIDTH-32) downto 95+(C_ADDR_WIDTH-32));
                vsize_data_int <= s_axis_cmd_tdata (117+(C_ADDR_WIDTH-32) downto 95+(C_ADDR_WIDTH-32)) - '1';
                stride_data <= s_axis_cmd_tdata (94+(C_ADDR_WIDTH-32) downto 72+(C_ADDR_WIDTH-32));
                eof_bit_cdc_from <= s_axis_cmd_tdata (30);
                cmd_in <= '1';
            else
                mm2s_cmd     <= mm2s_cmd; --split_cmd;
                vsize_data   <= vsize_data;
                vsize_data_int   <= vsize_data_int;
                stride_data   <= stride_data;
                cache_info <= cache_info;
                s_axis_cmd_tready <= '0';
                eof_bit_cdc_from <= eof_bit_cdc_from;
                cmd_in <= '0';
            end if;
        end if;
    end process REGISTER_MM2S_CMD;


REGISTER_DECR_VSIZE : process(clock)
    begin
        if(clock'EVENT and clock = '1')then
            if(sgresetn = '0')then
                vsize <= "00000000000000000000000";
            elsif (command_valid = '1' and command_ready = '1' and (vsize < vsize_data_int)) then  -- sending a cmd out to DM
                vsize <= vsize + '1';
            elsif (cmd_proc_cdc_from = '0') then  -- idle or when all cmd are sent to DM
                vsize <= "00000000000000000000000";
            else 
                vsize <= vsize;    
            end if;
        end if;
    end process REGISTER_DECR_VSIZE;

    vsize_over <= '1' when (vsize = vsize_data_int) else '0';
  --  eof_set <= eof_bit when (vsize = vsize_data_int) else '0';


 REGISTER_SPLIT : process(clock)
     begin
         if(clock'EVENT and clock = '1')then
             if(sgresetn = '0')then
                 split_cmd <= (others => '0');
             elsif (s_axis_cmd_tvalid = '1' and cmd_proc_cdc_from = '0' and ready_for_next_cmd = '1' and ready_for_next_cmd_tlast_cdc = '1') then
                 split_cmd <= s_axis_cmd_tdata (63+(C_ADDR_WIDTH-32) downto 32);          -- capture the ba when a new cmd arrives
             elsif (split_out = '1') then  -- add stride to previous ba
                 split_cmd <= split_cmd + stride_data;
             else 
                 split_cmd <= split_cmd;
             end if;

         end if;
     end process REGISTER_SPLIT;



MM2S_MACHINE : process(mm2s_cs,
                       s_axis_cmd_tvalid,
                       cmd_proc_cdc_from, 
                       vsize_over, command_ready,
                       cache_info, mm2s_cmd,
                       split_cmd, eof_set,
                       cmd_in, command
                       )
    begin
         over_ns <= '0'; 
                       cmd_proc_ns <= '0';      -- ready to receive new command 
                       split_out_ns <= '0';
                       command_valid_ns <= '0';
         mm2s_ns <= mm2s_cs;
         command_ns <= command;  
        -- Default signal assignment
        case mm2s_cs is

            -------------------------------------------------------------------
            when IDLE => 
                       command_ns <=  cache_info & mm2s_cmd (72+(C_ADDR_WIDTH-32) downto 65+(C_ADDR_WIDTH-32)) & split_cmd & mm2s_cmd (31) & eof_set & mm2s_cmd (29 downto 0); -- buf length remains the same
                  --     command_ns <=  cache_info & mm2s_cmd (72 downto 65) & split_cmd & mm2s_cmd (31 downto 0); -- buf length remains the same
                   if (cmd_in = '1' and cmd_proc_cdc_from = '0') then
                       cmd_proc_ns <= '1';      -- new command has come in and i need to start processing
                       mm2s_ns <= SEND;
                       over_ns <= '0'; 
                       split_out_ns <= '1'; 
                       command_valid_ns <= '1';
                   else 
                       mm2s_ns <= IDLE; 
                       over_ns <= '0'; 
                       cmd_proc_ns <= '0';      -- ready to receive new command 
                       split_out_ns <= '0'; 
                       command_valid_ns <= '0';
                   end if;

            -------------------------------------------------------------------
            when SEND =>
                       cmd_out_ns <= '1';
                       command_ns <=  command;

                       if (vsize_over = '1' and command_ready = '1') then
                         mm2s_ns <= IDLE; 
                         cmd_proc_ns <= '1';
                         command_valid_ns <= '0';
                         split_out_ns <= '0'; 
                         over_ns <= '1'; 
                       elsif  (command_ready = '0') then --(command_valid = '1' and command_ready = '0') then
                         mm2s_ns <= SEND;
                         command_valid_ns <= '1';
                         cmd_proc_ns <= '1'; 
                         split_out_ns <= '0'; 
                         over_ns <= '0';
                       else 
                         mm2s_ns <= SPLIT;
                         command_valid_ns <= '0';
                         cmd_proc_ns <= '1';
                         over_ns <= '0'; 
                         split_out_ns <= '0'; 
                       end if;
                  
            -------------------------------------------------------------------
            when SPLIT =>
                         cmd_proc_ns <= '1';
                         mm2s_ns <= SEND; 
                         command_ns <=  cache_info & mm2s_cmd (72+(C_ADDR_WIDTH-32) downto 65+(C_ADDR_WIDTH-32)) & split_cmd & mm2s_cmd (31) & eof_set & mm2s_cmd (29 downto 0); -- buf length remains the same
        --                 command_ns <=  cache_info & mm2s_cmd (72 downto 65) & split_cmd & mm2s_cmd (31 downto 0); -- buf length remains the same
                         cmd_out_ns <= '0';
                         split_out_ns <= '1'; 
                         command_valid_ns <= '1';

            -------------------------------------------------------------------
          -- coverage off
            when others =>
                mm2s_ns <= IDLE;
          -- coverage on

        end case;
    end process MM2S_MACHINE;


SWALLOW_TVALID : process(clock)
    begin
        if(clock'EVENT and clock = '1')then
            if(sgresetn = '0')then
                counter <= (others => '0');
           --     tvalid_unsplit_int <= '0';
                reset_lock <= '1';
                ready_for_next_cmd <= '0';
            elsif (vsize_data_int = "00000000000000000000000") then
           --     tvalid_unsplit_int <= '0';
                ready_for_next_cmd <= '1';
                reset_lock <= '0';
            elsif ((tvalid_from_datamover = '1') and (counter < vsize_data_int)) then
                counter <= counter + '1';
           --     tvalid_unsplit_int <= '0';
                ready_for_next_cmd <= '0';
                reset_lock <= '0';
            elsif ((counter = vsize_data_int) and (reset_lock = '0') and (tvalid_from_datamover = '1')) then
                counter <= (others => '0');
          --      tvalid_unsplit_int <= '1';
                ready_for_next_cmd <= '1';
            else
                counter <= counter;
           --     tvalid_unsplit_int <= '0';
                if (cmd_proc_cdc_from = '1') then
                   ready_for_next_cmd <= '0';
                else
                   ready_for_next_cmd <= ready_for_next_cmd;
                end if;
            end if;
        end if;
    end process SWALLOW_TVALID;

                tvalid_unsplit_int <= tvalid_from_datamover when (counter = vsize_data_int) else '0'; --tvalid_unsplit_int;

SWALLOW_TDATA : process(clock)
    begin
        if(clock'EVENT and clock = '1')then
            if (sgresetn = '0' or cmd_in = '1') then
               tvalid_unsplit <= '0';
               status_out_int <= (others => '0');
            else
               tvalid_unsplit <= tvalid_unsplit_int;
               if (tvalid_from_datamover = '1') then 
                  status_out_int (C_DM_STATUS_WIDTH-2 downto 0) <= status_in (C_DM_STATUS_WIDTH-2 downto 0) or status_out_int (C_DM_STATUS_WIDTH-2 downto 0); 
               else
                  status_out_int <= status_out_int;
               end if;

               if (tvalid_unsplit_int = '1') then
                  status_out_int (C_DM_STATUS_WIDTH-1) <= status_in (C_DM_STATUS_WIDTH-1);
               end if;
            end if;
        end if;
    end process SWALLOW_TDATA;


        status_out <= status_out_int;

SWALLOW_TLAST_GEN : if C_INCLUDE_S2MM = 0 generate
begin


    eof_set <= '1'; --eof_bit when (vsize = vsize_data_int) else '0';

CDC_CMD_PROC1 : xpm_cdc_single
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  SRC_INPUT_REG  => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => cmd_proc_cdc_from,
  dest_clk => clock_sec,
  dest_out => cmd_proc_cdc
  );

CDC_CMD_PROC2 : xpm_cdc_single
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  SRC_INPUT_REG  => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => eof_bit_cdc_from,
  dest_clk => clock_sec,
  dest_out => eof_bit_cdc
  );


CDC_CMD_PROC : process (clock_sec)
   begin
        if (clock_sec'EVENT and clock_sec = '1') then
           if (aresetn = '0') then
--              cmd_proc_cdc_to <= '0';
--              cmd_proc_cdc <= '0';
--              eof_bit_cdc_to <= '0';
--              eof_bit_cdc <= '0';
              ready_for_next_cmd_tlast_cdc_from <= '0';
           else
--              cmd_proc_cdc_to <= cmd_proc_cdc_from;
--              cmd_proc_cdc <= cmd_proc_cdc_to;
--              eof_bit_cdc_to <= eof_bit_cdc_from;
--              eof_bit_cdc <= eof_bit_cdc_to;
              ready_for_next_cmd_tlast_cdc_from <= ready_for_next_cmd_tlast;
           end if;
        end if;
end process CDC_CMD_PROC;

CDC_CMDTLAST_PROC : xpm_cdc_single
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  SRC_INPUT_REG  => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => ready_for_next_cmd_tlast_cdc_from,
  dest_clk => clock,
  dest_out => ready_for_next_cmd_tlast_cdc
  );

--CDC_CMDTLAST_PROC : process (clock)
--   begin
--        if (clock'EVENT and clock = '1') then
--           if (sgresetn = '0') then
--              ready_for_next_cmd_tlast_cdc_to <= '0';
--              ready_for_next_cmd_tlast_cdc <= '0';
--           else
--              ready_for_next_cmd_tlast_cdc_to <= ready_for_next_cmd_tlast_cdc_from;
--              ready_for_next_cmd_tlast_cdc <= ready_for_next_cmd_tlast_cdc_to;
--           end if;
--         end if;  
--end process CDC_CMDTLAST_PROC;

SWALLOW_TLAST : process(clock_sec)
    begin
        if(clock_sec'EVENT and clock_sec = '1')then
            if(aresetn = '0')then
                counter_tlast <= (others => '0');
                tlast_stream_data_int <= '0';
                reset_lock_tlast <= '1';
                ready_for_next_cmd_tlast <= '1';
            elsif ((tlast_stream_data = '1' and tready_stream_data = '1') and vsize_data_int = "00000000000000000000000") then
                tlast_stream_data_int <= '0';
                ready_for_next_cmd_tlast <= '1';
                reset_lock_tlast <= '0';
            elsif ((tlast_stream_data = '1' and tready_stream_data = '1') and (counter_tlast < vsize_data_int)) then
                counter_tlast <= counter_tlast + '1';
                tlast_stream_data_int <= '0';
                ready_for_next_cmd_tlast <= '0';
                reset_lock_tlast <= '0';
            elsif ((counter_tlast = vsize_data_int) and (reset_lock_tlast = '0') and (tlast_stream_data = '1' and tready_stream_data = '1')) then
                counter_tlast <= (others => '0');
                tlast_stream_data_int <= '1';
                ready_for_next_cmd_tlast <= '1';
            else
                counter_tlast <= counter_tlast;
                tlast_stream_data_int <= '0';
                if (cmd_proc_cdc = '1') then
                   ready_for_next_cmd_tlast <= '0';
                else
                   ready_for_next_cmd_tlast <= ready_for_next_cmd_tlast;
                end if;
            end if;
        end if;
    end process SWALLOW_TLAST;
                
          tlast_unsplit <= tlast_stream_data when (counter_tlast = vsize_data_int and eof_bit_cdc = '1') else '0';
          tlast_unsplit_user <= tlast_stream_data when (counter_tlast = vsize_data_int) else '0';
       --   tlast_unsplit <= tlast_stream_data; -- when (counter_tlast = vsize_data_int) else '0';


end generate SWALLOW_TLAST_GEN;

SWALLOW_TLAST_GEN_S2MM : if C_INCLUDE_S2MM = 1 generate
begin

    eof_set <= eof_bit_cdc_from;
ready_for_next_cmd_tlast_cdc <= '1';

end generate SWALLOW_TLAST_GEN_S2MM;


end implementation;



library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;
use ieee.std_logic_misc.all;

library unisim;
use unisim.vcomponents.all;

library axi_mcdma_v1_2_2;
use axi_mcdma_v1_2_2.axi_mcdma_pkg.all;

--------------------------------------------------------------------------------------
entity  axi_mcdma_multi_ch_reset is
    generic (
        C_FAMILY                        : string   := "virtex5";
        C_MAX_CHANNELS                  : integer range 1 to 16     := 1
    );
    port (
        m_axi_sg_aclk               : in  std_logic                         ;           --
        m_axi_sg_aresetn            : in  std_logic                         ;           --
 	soft_reset_in		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	current_channel		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	error_dma		: in	std_logic;
	ch_complete		: in	std_logic;
--	error_in 		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	is_mm2s			: in std_logic;
	mm2s_sideband		: in std_logic_vector(27 downto 0);
	mm2s_sideband_out	: out std_logic_vector(27 downto 0);
	channel_to_sg		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0);

	ftch_error_sg		: in std_logic;
	ftch_error_ch		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	updt_error_sg		: in std_logic;
	updt_error_ch		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	
	
	timeout_count		: in std_logic_vector (13 downto 0);
        --reset_done		: in std_logic ;
	halt_cmplt_dm		: in std_logic ;
	eof_received		: in std_logic ;
	soft_reset_out		: out std_logic_vector (C_MAX_CHANNELS-1 downto 0); --to SG
	soft_reset_dma		: out std_logic;
	channel_disable		: out std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	error_out 		: out std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	halt      		: out std_logic;
	reset_in_progress	: out std_logic_vector (C_MAX_CHANNELS-1 downto 0);
	reset_complete_dma   	: in std_logic;
	reset_done_sg		: in std_logic_vector (C_MAX_CHANNELS-1 downto 0)
    );

end axi_mcdma_multi_ch_reset;

architecture implementation of axi_mcdma_multi_ch_reset is
  attribute DowngradeIPIdentifiedWarnings: string;
  attribute DowngradeIPIdentifiedWarnings of implementation : architecture is "yes";
-------------------------------------------------------------------------------
-- Functions
-------------------------------------------------------------------------------

-- No Functions Declared

-------------------------------------------------------------------------------
-- Constants Declarations
-------------------------------------------------------------------------------

----Signals
signal count_128 : std_logic_vector(6 downto 0);
signal count : std_logic_vector(15 downto 0);
signal error_in : std_logic_vector (C_MAX_CHANNELS-1 downto 0);
signal reset_cur_ch_in_progress	: std_logic_vector(C_MAX_CHANNELS-1 downto 0);

--signal soft_reset_out : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal soft_rst_out_r : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal soft_rst_curr  : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal soft_rst_currsg  : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
--signal error_curr     : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal error_curr     : std_logic;
signal error_per_ch     : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal current_channel_r     : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
--signal channel_disable     : std_logic_vector(C_MAX_CHANNELS-1 downto 0);

type SFT_RST_STATE_TYPE is (
				IDLE,
				TIMER_STATE,
				EOF_STATE,
				HALT_STATE,
				RESET_STATE );


signal state_ns   : SFT_RST_STATE_TYPE;
signal state_cs   : SFT_RST_STATE_TYPE;
signal state_cs_r : SFT_RST_STATE_TYPE;
signal halt_dm : std_logic;
signal rst_out : std_logic;
signal timer_start : std_logic;
signal timer_done : std_logic;
signal rst_in_progress :  std_logic;
signal ftch_error_sg_r : std_logic;
signal updt_error_sg_r : std_logic;
signal error_dma_r : std_logic;
signal error_dma_reset_r : std_logic;

signal ftch_error_per_ch : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal ftch_error_per_ch_r : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal updt_error_per_ch : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal updt_error_per_ch_r : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal dma_error_per_ch : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal dma_error_per_ch_r : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal reset_done : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal error_dma_reset : std_logic;
signal soft_reset_done_cu_channel : std_logic;
signal channel_disable_r : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal channel_disable_reg : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal cur_channel_disable_r : std_logic_vector(C_MAX_CHANNELS-1 downto 0);
signal count_16 : std_logic_vector(3 downto 0);
signal dma_rst_cm : std_logic;
signal reset_dma : std_logic;
signal soft_reset_out_f : std_logic_vector(C_MAX_CHANNELS-1 downto 0);

begin
--cur_channel_disable_r <= current_channel and channel_disable_r;
cur_channel_disable_r <= current_channel and (ftch_error_per_ch or updt_error_per_ch or dma_error_per_ch);
error_out <= channel_disable_reg;
--channel_disable <= channel_disable_r or soft_reset_out_f;
channel_disable <= channel_disable_reg or soft_reset_out_f;
soft_reset_out <= soft_reset_out_f;
--reset_in_progress <= soft_reset_in and (not reset_done);
reset_in_progress <= (soft_reset_in and (not reset_done)) or (soft_reset_in and reset_cur_ch_in_progress);
--reset_cur_ch_in_progress <= rst_in_progress;
reset_cur_ch_in_progress <= current_channel_r when (rst_in_progress = '1') else (others => '0');
reset_done <= reset_done_sg;
--reset_done <= reset_done_sg when (reset_complete_dma = '1') else (others => '0');
--soft_reset_done_cu_channel <= '1' when (unsigned(reset_done and current_channel_r) > 0) else '0';
soft_reset_done_cu_channel <= '1' when (dma_rst_cm = '1' and reset_complete_dma = '1') else '0';
--soft_reset_out <= (soft_rst_out_r) when (rst_out = '1')
--soft_reset_out <= (soft_reset_in) when (reset_dma = '1')
--			else (soft_rst_out_r );
--reset_dma	<= rst_out or halt_dm;
soft_reset_dma <= reset_dma;
soft_rst_out_r <= soft_reset_in and (not current_channel_r);
soft_rst_curr <= soft_reset_in and current_channel;
soft_rst_currsg <= soft_reset_in and channel_to_sg;
error_curr <= (not error_dma_reset_r ) and (error_dma_reset); 
halt <= halt_dm;
timer_done <= '1' when (is_mm2s = '1' and (unsigned(count) = unsigned(timeout_count)))
		else '0';
error_dma_reset <= '1' when (unsigned(cur_channel_disable_r) > 0) else '0';

channel_disable_r <= ftch_error_per_ch or updt_error_per_ch or dma_error_per_ch;
dma_rst_cm <= '1' when (count_16 = "1111") else '0';


RESET_DONE_COUNTER : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			count_16		<= (others => '0');
		else
			--if(rst_out = '1') then
			if(state_cs = RESET_STATE) then
				if(count_16 = "1111") then
					count_16 <= count_16;
				else
					count_16 <= std_logic_vector(unsigned(count_16(3 downto 0)) + 1);
				end if;
			else
				count_16 <= (others => '0');
			end if;

		end if;
	end if;
end process RESET_DONE_COUNTER;


FLOP_ERROR_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			ftch_error_sg_r		<= '0';
			updt_error_sg_r	<= '0';
			error_dma_r		<= '0';
			error_dma_reset_r	<= '0';
		else
			ftch_error_sg_r		<= ftch_error_sg;
			updt_error_sg_r	<= updt_error_sg;
			error_dma_r		<= error_dma;
			error_dma_reset_r	<= error_dma_reset;
		end if;
	end if;
end process FLOP_ERROR_PROC;


FETCH_ERROR_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			ftch_error_per_ch	<= (others => '0');
			ftch_error_per_ch_r	<= (others => '0');
		else
			ftch_error_per_ch_r	<= ftch_error_per_ch;
			if(ftch_error_sg_r = '0' and ftch_error_sg = '1') then
				ftch_error_per_ch <= ftch_error_ch or ftch_error_per_ch;
			elsif(unsigned(soft_reset_in) > 0) then
				ftch_error_per_ch <= ftch_error_per_ch and (not(soft_reset_in));
			end if;	
		end if;
	end if;
end process FETCH_ERROR_PROC;

QUEUE_ERROR_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			updt_error_per_ch	<= (others => '0');
			updt_error_per_ch_r	<= (others => '0');
		else
			updt_error_per_ch_r	<= updt_error_per_ch;
			if(updt_error_sg_r = '0' and updt_error_sg = '1') then
				--updt_error_per_ch <= current_channel or updt_error_per_ch;
				updt_error_per_ch <= updt_error_ch or updt_error_per_ch;
			elsif(unsigned(soft_reset_in) > 0) then
				updt_error_per_ch <= updt_error_per_ch and (not(soft_reset_in));
			end if;	
		end if;
	end if;
end process QUEUE_ERROR_PROC;

DMA_ERROR_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			dma_error_per_ch	<= (others => '0');
			dma_error_per_ch_r	<= (others => '0');
		else
			dma_error_per_ch_r	<= dma_error_per_ch;
			if(error_dma_r = '0' and error_dma = '1') then
				dma_error_per_ch <= current_channel or dma_error_per_ch;
			elsif(unsigned(soft_reset_in) > 0) then
				dma_error_per_ch <= dma_error_per_ch and (not(soft_reset_in));
			end if;	
		end if;
	end if;
end process DMA_ERROR_PROC;

TIMER_MACHINE : process (	state_cs,
				current_channel,
				error_curr,
				soft_rst_curr,
				soft_rst_currsg,
				ch_complete,
				timer_done,
				eof_received,
				halt_cmplt_dm,
				soft_reset_done_cu_channel)
	begin
	state_ns	<= state_cs;
--	current_channel_r	<= current_channel_r;
	case state_cs is
		when IDLE =>
--			current_channel_r	<= current_channel;
			if(error_curr = '1') then
				state_ns	<= HALT_STATE;
			elsif(soft_rst_curr /= ("0000000000000000")) then
				state_ns	<= TIMER_STATE;
			elsif(soft_rst_currsg /= ("0000000000000000")) then
				state_ns	<= EOF_STATE;
			end if;

		when TIMER_STATE =>
			if(timer_done = '1' or eof_received = '1' or error_curr = '1') then 
				state_ns	<= HALT_STATE;
			elsif(soft_rst_curr = ("0000000000000000")) then
				state_ns	<= IDLE;
			end if;

		when EOF_STATE =>
			if(ch_complete = '1' or error_curr = '1') then 
				state_ns	<= HALT_STATE;
			elsif(soft_rst_curr /= ("0000000000000000")) then
				state_ns	<= TIMER_STATE;
			else
				state_ns	<= EOF_STATE;
			end if;

		when HALT_STATE =>
			if(halt_cmplt_dm = '1') then
				state_ns	<= RESET_STATE;
			end if;

		when RESET_STATE =>
			if(soft_reset_done_cu_channel = '1') then
				state_ns	<= IDLE;
			end if;
	end case;
end process TIMER_MACHINE;
			
rst_in_progress <= '0' when (state_cs = IDLE)	else '1';
--halt_dm	<= '1' when (state_cs = HALT_STATE and (state_cs_r = IDLE or state_cs_r = TIMER_STATE)) else '0';
--halt_dm	<= '1' when (state_cs = HALT_STATE) else '0';
timer_start <= '1' when state_cs = TIMER_STATE else '0';
rst_out <= '1' when state_cs = RESET_STATE else '0';

HALT_DM_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			halt_dm		<= '0';
		else
			if(state_ns = HALT_STATE) then
				halt_dm		<= '1';
			else
				halt_dm		<= '0';
			end if;
		end if;
	end if;
end process HALT_DM_PROC;

MM2S_LOGIC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			mm2s_sideband_out		<= (others => '0');
		else
			--if(rst_out = '1') then
			--if((state_ns = HALT_STATE)) then
			if(state_ns = HALT_STATE) then
				if(state_cs /= HALT_STATE) then 
					mm2s_sideband_out <= mm2s_sideband;
			--	else 
			--		mm2s_sideband_out <= mm2s_sideband_out;
				end if;
			else
				mm2s_sideband_out <= (others => '0');
			end if;

		end if;
	end if;
end process MM2S_LOGIC;

CH_DISABLE_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			channel_disable_reg		<= (others => '0');
		else
			channel_disable_reg <= ftch_error_per_ch or updt_error_per_ch or dma_error_per_ch;
		end if;
	end if;
end process CH_DISABLE_PROC;



RST_DMA_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			reset_dma		<= '0';
		else
			if((state_ns = HALT_STATE) or (state_ns = RESET_STATE)) then
			--if((state_ns = RESET_STATE)) then
				reset_dma		<= '1';
			else
				reset_dma		<= '0';
			end if;
		end if;
	end if;
end process RST_DMA_PROC;

SFT_OUT_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			soft_reset_out_f		<= (others => '0');
		else
			if((state_ns = HALT_STATE) or (state_ns = RESET_STATE)) then
				soft_reset_out_f		<= soft_reset_in;
			elsif (state_ns = IDLE) then
				soft_reset_out_f		<= soft_reset_in and (not current_channel);
			else
				soft_reset_out_f		<= soft_rst_out_r;
			end if;
		end if;
	end if;
end process SFT_OUT_PROC;



CURR_CH_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			current_channel_r	<= (others => '0');
		else
			if(state_cs = IDLE) then
				current_channel_r	<= current_channel;
			else
				current_channel_r	<= current_channel_r;
			end if;
		end if;
	end if;
end process CURR_CH_PROC;

TIMER_STATE_PROC : process(m_axi_sg_aclk)
begin
	if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
        	if(m_axi_sg_aresetn = '0')then
			state_cs	<= IDLE;
			state_cs_r	<= IDLE;
		else
			state_cs	<= state_ns;
			state_cs_r	<= state_cs;
		end if;
	end if;
end process TIMER_STATE_PROC;


COUNT_128_TIMER: process(m_axi_sg_aclk)
begin
        if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
            if(m_axi_sg_aresetn = '0')then
		count_128	<= (others => '0');
	    else 
		if(timer_start = '1') then
			count_128 <= std_logic_vector(unsigned(count_128(6 downto 0)) + 1);
		elsif(timer_done = '1') then
			count_128	<= (others => '0');
		else 
			count_128 <= count_128;
		end if;	
	    end if;
	end if;
end process COUNT_128_TIMER;

COUNT_TIMER: process(m_axi_sg_aclk)
begin
        if(m_axi_sg_aclk'EVENT and m_axi_sg_aclk = '1')then
            if(m_axi_sg_aresetn = '0')then
		count	<= (others => '0');
	    else 
		if(timer_start = '1' and (count_128 = "1111111")) then
			count <= std_logic_vector(unsigned(count(15 downto 0)) + 1);
		elsif(timer_done = '1') then
			count	<= (others => '0');
		else 
			count <= count;
		end if;	
	    end if;
	end if;
end process COUNT_TIMER;


end implementation;


