INCLUDE_MM2S_SOF_EOF_GENERATOR : if C_INCLUDE_MM2S = 1 generate
begin

mm2s_tlast <= m_axis_mm2s_tvalid_i and m_axis_mm2s_tlast_i; -- and m_axis_mm2s_tready; 


-------------------------------------------------------------------------------
---MULTI CHANNEL RESET
-------------------------------------------------------------------------------

INCLUDE_SOFT_RESET_PER_CHANNEL : if C_ENABLE_MULTI_CH_RESET = 1 generate
begin 

mm2s_sideband_in <= mm2s_tuser_tid & m_axis_mm2s_tdest_int;
        m_axis_mm2s_tuser  <= mm2s_tuser_tid (15 downto 0) or mm2s_sideband_out(19 downto 4);
        m_axis_mm2s_tid    <= mm2s_tuser_tid (23 downto 16) or mm2s_sideband_out(27 downto 20);
        m_axis_mm2s_tdest  <= m_axis_mm2s_tdest_int or mm2s_sideband_out(3 downto 0);

I_MM2S_MULTI_CHANNEL_RST_MNGR : entity axi_mcdma_v1_2_2.axi_mcdma_multi_ch_reset
  generic map(
	C_FAMILY => C_FAMILY ,
	C_MAX_CHANNELS => C_MAX_CHANNELS
  )
  port map(
        m_axi_sg_aclk               => axi_sg_aclk                          ,
        m_axi_sg_aresetn            => mm2s_scndry_resetn                   ,
	is_mm2s			    => '1',
	mm2s_sideband		    => mm2s_sideband_in,
	mm2s_sideband_out	    => mm2s_sideband_out,
	channel_to_sg		    => mm2s_axis_channel,
	ch_complete			=> ch_complete,
----AXILITE 

	soft_reset_in		    =>  mm2s_ch_soft_reset,
	timeout_count		    =>	mm2s_timeout,

	channel_disable		    => channel_disable_sft_rst,
	error_out		    => error_out_perch,
	reset_in_progress	    => reset_in_progress_perch,
----MM2S
	--current_channel		    => mm2s_axis_channel, 
	current_channel		    => mm2s_curr_channel, 
	error_dma		    => dma_mm2s_error,
	eof_received		    => eof_done_mm2s , --TOCHANGE
	reset_complete_dma	    => '1', --TOCHANGE 

	soft_reset_dma		    => soft_reset_mm2s_dma,
--	reset_cur_ch_in_progress    => rst_dma_in_prog,
-----SG
	ftch_error_sg		    => ftch_error_mm2s,
	ftch_error_ch		    => mm2s_ch_ftch_active,
	updt_error_sg		    => updt_error_mm2s,
	--updt_error_ch		    => ch_mm2s_updt_channel_id,
	updt_error_ch		    => mm2s_curr_channel,
	reset_done_sg	    => reset_done_sg_array,
	
	soft_reset_out		    => soft_reset_sg_mm2s,
---DATAMOVER
	halt			    => halt_dm_sft_rst,
	halt_cmplt_dm		    => mm2s_halt_cmplt_sg

  );


MM2S_CH_EN : process(axi_sg_aclk)
    begin
        if(axi_sg_aclk'EVENT and axi_sg_aclk = '1')then
            if(mm2s_scndry_resetn = '0' )then
                mm2s_channel_en_gen     <= (others => '0');
		mm2s_channel_rs_gen	<= (others => '0');
            else
		mm2s_channel_rs_gen <= mm2s_ch_dmacr_rs and (not channel_disable_sft_rst);         --sgclk
		mm2s_channel_en_gen <= channel_enable_mm2s and (not channel_disable_sft_rst);      --sgclk
	    end if;
        end if;
    end process MM2S_CH_EN;

MM2S_HALT_EN : process(m_axi_mm2s_aclk_i)
    begin
        if(m_axi_mm2s_aclk_i'EVENT and m_axi_mm2s_aclk_i = '1')then
            if(mm2s_prmry_resetn = '0' )then
		mm2s_halt 		<= '0';
            else
		mm2s_halt <= mm2s_halt_r or halt_dm_sft_rst_axi;
	    end if;
        end if;
    end process MM2S_HALT_EN;



--mm2s_halt <= mm2s_halt_r or halt_dm_sft_rst_axi;
--mm2s_channel_rs_gen <= mm2s_ch_dmacr_rs and (not channel_disable_sft_rst);         --sgclk
--mm2s_channel_en_gen <= channel_enable_mm2s and (not channel_disable_sft_rst);      --sgclk
mm2s_prmry_resetn_gen   <= mm2s_prmry_resetn and (not  soft_reset_mm2s_dma_axi                 ) ;
mm2s_scndry_resetn_gen   <= mm2s_scndry_resetn and (not  soft_reset_mm2s_dma                  ) ;   --sgclk
--reset_done_sg_array	<= (others => '1') when (soft_reset_sg_cmplt = '1') else (others => '0');
dm_mm2s_scndry_resetn_gen <= dm_mm2s_scndry_resetn and (not (soft_reset_mm2s_dma and not halt_dm_sft_rst));
m_axi_mm2s_aresetn_gen <= m_axi_mm2s_aresetn and (not (soft_reset_mm2s_dma_axi and not halt_dm_sft_rst_axi));
mm2s_prmry_reset_out_perch_n_i <= (mm2s_prmy_rstn_vect) and (not soft_reset_sg_mm2s_axi);
mm2s_prmy_rstn_vect <= (others => mm2s_prmry_reset_out_n_i);
mm2s_prmry_reset_out_perch_n <= mm2s_prmry_reset_out_perch_n_i(C_NUM_MM2S_CHANNELS-1 downto 0);
mm2s_cntrl_reset_out_n <= mm2s_cntrl_reset_out_n_i and (not soft_reset_mm2s_dma_axi);

GEN_SYNC_RESET : if C_PRMRY_IS_ACLK_ASYNC = 0 generate
begin

mm2s_halt_cmplt_sg <= mm2s_halt_cmplt;
halt_dm_sft_rst_axi <= halt_dm_sft_rst;
soft_reset_mm2s_dma_axi <= soft_reset_mm2s_dma;
soft_reset_sg_mm2s_axi <= soft_reset_sg_mm2s;

end generate GEN_SYNC_RESET;

GEN_ASYNC_RESET : if C_PRMRY_IS_ACLK_ASYNC = 1 generate
begin

SFT_RST_SG_PRIM_CDC_PROC : xpm_cdc_array_single
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  SRC_INPUT_REG  => 0,
  WIDTH          => 16,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => soft_reset_sg_mm2s,
  dest_clk => m_axi_mm2s_aclk_i,
  dest_out => soft_reset_sg_mm2s_axi
  );

SFT_RST_PRIM_CDC_PROC : xpm_cdc_sync_rst
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  INIT           => 1,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_rst  => soft_reset_mm2s_dma,
  dest_clk => m_axi_mm2s_aclk_i,
  dest_rst => soft_reset_mm2s_dma_axi
  );

HALT_CDC_PROC : xpm_cdc_sync_rst
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  INIT           => 1,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_rst  => halt_dm_sft_rst,
  dest_clk => m_axi_mm2s_aclk_i,
  dest_rst => halt_dm_sft_rst_axi
  );
HALT_COMPL_CDC_PROC : xpm_cdc_single
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  SRC_INPUT_REG  => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => mm2s_halt_cmplt,
  dest_clk => m_axi_sg_aclk,
  dest_out => mm2s_halt_cmplt_sg
  );




end generate GEN_ASYNC_RESET;

end generate INCLUDE_SOFT_RESET_PER_CHANNEL;

EXCLUDE_SOFT_RESET_PER_CHANNEL : if C_ENABLE_MULTI_CH_RESET = 0 generate
begin 

        m_axis_mm2s_tuser  <= mm2s_tuser_tid (15 downto 0);
        m_axis_mm2s_tid    <= mm2s_tuser_tid (23 downto 16);
        m_axis_mm2s_tdest  <= m_axis_mm2s_tdest_int;
mm2s_channel_rs_gen <= mm2s_ch_dmacr_rs    ;
mm2s_channel_en_gen <= channel_enable_mm2s ;
mm2s_prmry_resetn_gen   <= mm2s_prmry_resetn   ;
mm2s_scndry_resetn_gen   <= mm2s_scndry_resetn ;
dm_mm2s_scndry_resetn_gen <= dm_mm2s_scndry_resetn;
m_axi_mm2s_aresetn_gen <= m_axi_mm2s_aresetn;

soft_reset_mm2s_dma <= '0';
soft_reset_sg_mm2s <= (others => '0');
mm2s_halt <= mm2s_halt_r;
reset_in_progress_perch <= (others => '0');
mm2s_prmry_reset_out_perch_n <= (others => mm2s_prmry_reset_out_n_i);
mm2s_cntrl_reset_out_n <= mm2s_cntrl_reset_out_n_i;

GEN_SYNC_RESET : if C_PRMRY_IS_ACLK_ASYNC = 0 generate
begin
mm2s_halt_cmplt_sg <= mm2s_halt_cmplt;
end generate GEN_SYNC_RESET;

GEN_ASYNC_RESET : if C_PRMRY_IS_ACLK_ASYNC = 1 generate
begin

HALT_COMPL_CDC_PROC : xpm_cdc_single
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  SRC_INPUT_REG  => 0,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
  src_clk  => '0',
  src_in   => mm2s_halt_cmplt,
  dest_clk => m_axi_sg_aclk,
  dest_out => mm2s_halt_cmplt_sg
  );
end generate GEN_ASYNC_RESET;


end generate EXCLUDE_SOFT_RESET_PER_CHANNEL;

