    mm2s_packet_sof <= '0';
    mm2s_packet_eof <= '0';
end generate EXCLUDE_MM2S_SOF_EOF_GENERATOR;


INCLUDE_S2MM_SOF_EOF_GENERATOR : if C_INCLUDE_S2MM = 1 generate
begin

-------------------------------------------------------------------------------
---S2MM -MULTI CHANNEL RESET
-------------------------------------------------------------------------------

INCLUDE_SOFT_RESET_PER_CHANNEL_S2MM : if C_ENABLE_MULTI_CH_RESET = 1 generate
begin 

I_S2MM_MULTI_CHANNEL_RST_MNGR : entity axi_mcdma_v1_2_2.axi_mcdma_multi_ch_reset
  generic map(
	C_FAMILY => C_FAMILY ,
	C_MAX_CHANNELS => C_MAX_CHANNELS
  )
  port map(
        m_axi_sg_aclk               => axi_sg_aclk                          ,
        m_axi_sg_aresetn            => s2mm_scndry_resetn                   ,
	is_mm2s			    => '0',
	mm2s_sideband		    => (others => '0'),
	mm2s_sideband_out	    => open,
	channel_to_sg		    => cur_channel_s2mm,
	ch_complete			=> '0',

----AXILITE 

	soft_reset_in		    =>  s2mm_ch_soft_reset,
	timeout_count		    =>	s2mm_timeout,

	channel_disable		    => channel_disable_sft_rst_s2mm,
	error_out		    => error_out_perch_s2mm,
	reset_in_progress	    => reset_in_progress_perch_s2mm,
----S2MM
	--current_channel		    => mm2s_axis_channel, 
	current_channel		    => cur_channel_s2mm, 
	error_dma		    => dma_s2mm_error,
	eof_received		    => s2mm_eof_detected , --TOCHANGE
	reset_complete_dma	    => soft_rst_complete_sg,
	--reset_complete_dma	    => '0', --TOCHANGE 

	soft_reset_dma		    => soft_reset_s2mm_dma,
--	reset_cur_ch_in_progress    => rst_dma_in_prog,
-----SG
	ftch_error_sg		    => ftch_error_s2mm,
	ftch_error_ch		    => s2mm_ch_ftch_active,
	updt_error_sg		    => updt_error_s2mm,
	--updt_error_ch		    => cur_channel_s2mm,
	updt_error_ch		    => s2mm_updt_channel,
	reset_done_sg	    => reset_done_sg_array_s2mm,
	
	soft_reset_out		    => soft_reset_sg_s2mm,
---DATAMOVER
	halt			    => halt_dm_sft_rst_s2mm,
	halt_cmplt_dm		    => s2mm_halt_cmplt_sg

  );

GEN_MULTI_RST_BLOCK_S2MM:if C_ENABLE_MULTI_CH_RESET = 1 generate
begin 

S2MM_CH_EN : process(axi_sg_aclk)
    begin
        if(axi_sg_aclk'EVENT and axi_sg_aclk = '1')then
            if(s2mm_scndry_resetn = '0' )then
                s2mm_channel_en_gen     <= (others => '0');
		s2mm_channel_rs_gen	<= (others => '0');
            else
		s2mm_channel_rs_gen <= s2mm_ch_dmacr_rs and (not channel_disable_sft_rst_s2mm);         --sgclk
		s2mm_channel_en_gen <= channel_enable_reg and (not channel_disable_sft_rst_s2mm);      --sgclk
	    end if;
        end if;
    end process S2MM_CH_EN;

S2MM_HALT_EN : process(m_axi_s2mm_aclk_i)
    begin
        if(m_axi_s2mm_aclk_i'EVENT and m_axi_s2mm_aclk_i = '1')then
            if(s2mm_prmry_resetn = '0' )then
		s2mm_halt 		<= '0';
            else
		s2mm_halt <= s2mm_halt_r or halt_dm_sft_rst_axi_s2mm;
	    end if;
        end if;
    end process S2MM_HALT_EN;



--s2mm_halt <= s2mm_halt_r or halt_dm_sft_rst_axi_s2mm;
--s2mm_channel_rs_gen <= s2mm_ch_dmacr_rs and (not channel_disable_sft_rst_s2mm);         --sgclk
--s2mm_channel_en_gen <= channel_enable_reg and (not channel_disable_sft_rst_s2mm);      --sgclk
s2mm_prmry_resetn_gen   <= s2mm_prmry_resetn and (not  soft_reset_s2mm_dma_axi                 ) ;
s2mm_scndry_resetn_gen   <= s2mm_scndry_resetn and (not  soft_reset_s2mm_dma                  ) ;   --sgclk
dm_s2mm_scndry_resetn_gen <= dm_s2mm_scndry_resetn and (not (soft_reset_s2mm_dma and not halt_dm_sft_rst_s2mm));
m_axi_s2mm_aresetn_gen <= m_axi_s2mm_aresetn and (not (soft_reset_s2mm_dma_axi and not halt_dm_sft_rst_axi_s2mm));
s2mm_prmry_reset_out_perch_n_i <= (s2mm_prmy_rstn_vect) and (not soft_reset_sg_s2mm_axi);
s2mm_prmy_rstn_vect <= (others => s2mm_prmry_reset_out_n_i);
s2mm_prmry_reset_out_perch_n <= s2mm_prmry_reset_out_perch_n_i(C_NUM_S2MM_CHANNELS-1 downto 0);
--s2mm_cntrl_reset_out_n <= s2mm_cntrl_reset_out_n_i and (not soft_reset_s2mm_dma_axi);
process (cur_channel_captured_s2mm)
begin
    cur_channel_s2mm <= (others => '0');
    case (cur_channel_captured_s2mm) is
      when "10000" =>
        cur_channel_s2mm <= (others => '0');
      when "00000" =>
        cur_channel_s2mm(0) <= '1';
      when "00001" =>
        cur_channel_s2mm(1) <= '1';
      when "00010" =>
        cur_channel_s2mm(2) <= '1';
      when "00011" =>
        cur_channel_s2mm(3) <= '1';
      when "00100" =>
        cur_channel_s2mm(4) <= '1';
      when "00101" =>
        cur_channel_s2mm(5) <= '1';
      when "00110" =>
        cur_channel_s2mm(6) <= '1';
      when "00111" =>
        cur_channel_s2mm(7) <= '1';
      when "01000" =>
        cur_channel_s2mm(8) <= '1';
      when "01001" =>
        cur_channel_s2mm(9) <= '1';
      when "01010" =>
        cur_channel_s2mm(10) <= '1';
      when "01011" =>
        cur_channel_s2mm(11) <= '1';
      when "01100" =>
        cur_channel_s2mm(12) <= '1';
      when "01101" =>
        cur_channel_s2mm(13) <= '1';
      when "01110" =>
        cur_channel_s2mm(14) <= '1';
      when "01111" =>
        cur_channel_s2mm(15) <= '1';
      when others =>
        cur_channel_s2mm <= (others => '0');
    end case;
end process;

process (ch_captured)
begin
    cur_channel_sg <= (others => '0');
    case (ch_captured) is
      when "10000" =>
        cur_channel_sg <= (others => '0');
      when "00000" =>
        cur_channel_sg(0) <= '1';
      when "00001" =>
        cur_channel_sg(1) <= '1';
      when "00010" =>
        cur_channel_sg(2) <= '1';
      when "00011" =>
        cur_channel_sg(3) <= '1';
      when "00100" =>
        cur_channel_sg(4) <= '1';
      when "00101" =>
        cur_channel_sg(5) <= '1';
      when "00110" =>
        cur_channel_sg(6) <= '1';
      when "00111" =>
        cur_channel_sg(7) <= '1';
      when "01000" =>
        cur_channel_sg(8) <= '1';
      when "01001" =>
        cur_channel_sg(9) <= '1';
      when "01010" =>
        cur_channel_sg(10) <= '1';
      when "01011" =>
        cur_channel_sg(11) <= '1';
      when "01100" =>
        cur_channel_sg(12) <= '1';
      when "01101" =>
        cur_channel_sg(13) <= '1';
      when "01110" =>
        cur_channel_sg(14) <= '1';
      when "01111" =>
        cur_channel_sg(15) <= '1';
      when others =>
        cur_channel_sg <= (others => '0');
    end case;
end process;

-- anuvab

curr_channel_soft_rst <= '1' when ((s2mm_ch_soft_reset_sync /= ("0000000000000000")) and (s2mm_ch_soft_reset_sync = cur_channel_sg)) else '0'; 

S2MM_EOF_GEN : process(m_axi_s2mm_aclk_i)
    begin
        if(m_axi_s2mm_aclk_i'EVENT and m_axi_s2mm_aclk_i = '1')then
            if(s2mm_prmry_resetn_gen = '0' )then
                s2mm_eof_detected_s2mm     <= '0';
		ch_wait_s2mm_i	      <= '0';
            else
            	if(curr_channel_soft_rst = '1' and s_axis_s2mm_tlast_dm = '1' and axis_buffer_valid = '1' and axis_buffer_read = '1') then
			ch_wait_s2mm_i <= '1';
			s2mm_eof_detected_s2mm <= '0';
		elsif(ch_wait_s2mm_i = '1' and update_complete_s2mm = '1' and s2mm_eof = '1') then
			ch_wait_s2mm_i	<= '1';
			s2mm_eof_detected_s2mm <= '1';
		end if;
	    end if;
        end if;
    end process S2MM_EOF_GEN;

S2MM_EOF_UPDATE_GEN : process(m_axi_s2mm_aclk_i)
    begin
        if(m_axi_s2mm_aclk_i'EVENT and m_axi_s2mm_aclk_i = '1')then
            if(s2mm_prmry_resetn_gen = '0' )then
                s2mm_eof     <= '0';
            else
            	if(s2mm_eof_status_s2mm = '1') then
            	--if(m_axis_s2mm_sts_tdata(DATAMOVER_STS_TAGEOF_BIT) = '1' and m_axis_s2mm_sts_tvalid = '1') then
               		s2mm_eof     <= '1';
		elsif(update_complete_s2mm = '1') then
               		s2mm_eof     <= '0';
		end if;
	    end if;
        end if;
    end process S2MM_EOF_UPDATE_GEN;



--
--NO_ERROR_CASE : process(m_axi_s2mm_aclk_i)
--    begin
--        if(m_axi_s2mm_aclk_i'EVENT and m_axi_s2mm_aclk_i = '1')then
--            if(s2mm_prmry_resetn_gen = '0' )then
--                active_cs     <= WAITING_TLAST;
--            else
--                active_cs     <= active_ns;
--            end if;
--        end if;
--    end process NO_ERROR_CASE;
--
--active_s2mm : process (s2mm_ch_soft_reset_sync, cur_channel_s2mm, s_axis_s2mm_tlast_dm) 
--       begin
--              active_ns <= active_cs;
--       case active_cs is
--
--             when WAITING_TLAST =>
--                   if (s2mm_ch_soft_reset_sync /= ("0000000000000000") and s2mm_ch_soft_reset_sync = cur_channel_s2mm) then   -- if soft_reset == current channel
--                      tlast_detected_s2mm <= '0';   -- waiting for tlast
--                      ch_wait_s2mm_i <= '0';
--                      s2mm_eof_detected <= '0';
--                      active_ns <= TLAST_RECV;
--                   else 
--                      active_ns <= WAITING_TLAST;
--                      ch_wait_s2mm_i <= '0';
--                      s2mm_eof_detected <= '0';
--                      tlast_detected_s2mm <= '0'; 
--                   end if;
--
--              when TLAST_RECV =>                              -- tlast detected and created ch_wait_s2mm_i  to block any more data process
--     		   if(s_axis_s2mm_tlast_dm = '1' and axis_buffer_valid = '1' and axis_buffer_read = '1') then
--                       tlast_detected_s2mm <= '1';
--                       s2mm_eof_detected <= '0';
--                       ch_wait_s2mm_i <= '1';
--                       active_ns <= UPDT_CMPT_I;
--                   else
--                      active_ns <= TLAST_RECV;
--                   end if;
--              when UPDT_CMPT_I =>
--                     if (update_complete_s2mm = '1') then   -- waiting for update to complete and send eof received for multi_rst block to reset all blocks
--                       s2mm_eof_detected <= '1';
--                       active_ns <= UPDT_CMPT_I;
--                     end if;
--       
--       end case;
--   end process active_s2mm;
--
--ch_wait_s2mm_i <= '1' when (tlast_detected_s2mm = '1' and s2mm_ch_soft_reset_sync /= ("0000000000000000")) else '0';

--anuvab


process (m_axi_s2mm_aclk_i)
begin
if(m_axi_s2mm_aclk_i'event and m_axi_s2mm_aclk_i = '1') then
     --if (m_axi_s2mm_aresetn = '0') then
     if (s2mm_prmry_resetn_gen = '0') then
	ch_captured <= "10000";
     elsif(ch_wait_s2mm = '1' and update_complete_s2mm = '1' and s2mm_eof = '1') then
	ch_captured <= "10000";
     elsif(axis_buffer_empty = '1' and update_complete_s2mm = '1' and s2mm_eof = '1') then
	ch_captured <= "10000";
     elsif(accept_sts = '1') then
	ch_captured <= '0' & s_axis_s2mm_tdest_dm;
     elsif (reject_sts = '1') then
	ch_captured <= "10000"; 
     end if;
end if;
end process;


tdest_s2mm_in <= s_axis_s2mm_tdest_dm when axis_buffer_empty = '0' else "0000";
ch_equal <= '1' when ((unsigned(ch_captured(3 downto 0)) = (unsigned(tdest_s2mm_in)))) else '0';
ch_wait_s2mm_p <= '1' when (ch_equal = '0') and (ch_captured(4) = '0') else '0';
--finish ongoing transaction in case of soft reset without error
--drop current transaction in case of error

process (m_axi_s2mm_aclk_i)
begin
if(m_axi_s2mm_aclk_i'event and m_axi_s2mm_aclk_i = '1') then
     --if (m_axi_s2mm_aresetn = '0') then
     if (s2mm_prmry_resetn_gen = '0') then
	ch_wait_s2mm <= '0';
     elsif(ch_captured(4) = '1') then
	ch_wait_s2mm <= '0';
     elsif(ch_equal = '0' and ch_wait_s2mm = '0' and axis_buffer_empty = '0') then
	 ch_wait_s2mm <= '1';
     elsif(ch_wait_s2mm = '1' and update_complete_s2mm = '1' and s2mm_eof = '1' and dma_error_s2mm_early_axi = '0') then
	 ch_wait_s2mm <= '0'; 

     end if;

end if;
end process;
process (m_axi_s2mm_aclk_i)
begin
if(m_axi_s2mm_aclk_i'event and m_axi_s2mm_aclk_i = '1') then
     if (m_axi_s2mm_aresetn = '0') then
     --if (s2mm_prmry_resetn_gen = '0') then
	s2mm_pkt_in_prog <= '0';
     elsif(s_axis_s2mm_tlast_dm = '1' and axis_buffer_valid = '1' and axis_buffer_read = '1') then
	 s2mm_pkt_in_prog <= '0'; 
     elsif(accept_sts = '1' or reject_sts = '1') then
	s2mm_pkt_in_prog <= '1';
     end if;
end if;
end process;
process (m_axi_s2mm_aclk_i)
begin
if(m_axi_s2mm_aclk_i'event and m_axi_s2mm_aclk_i = '1') then
     --if (m_axi_s2mm_aresetn = '0') then
     if (s2mm_prmry_resetn_gen = '0') then
	wait_for_update_s2mm <= '0';
     elsif(eof_detected_int = '1') then
	wait_for_update_s2mm <= '1';
     elsif(wait_for_update_s2mm = '1' and update_complete_s2mm = '1') then
	 wait_for_update_s2mm <= '0'; 

     end if;
end if;
end process;

process (m_axi_s2mm_aclk_i)
begin
if(m_axi_s2mm_aclk_i'event and m_axi_s2mm_aclk_i = '1') then
     if (m_axi_s2mm_aresetn = '0' or soft_reset_s2mm_dma_axi = '0') then
    -- if (s2mm_prmry_resetn_gen = '0') then
	count_rst_s2mm <= "0000";
	soft_rst_complete_axi <= '0';
     elsif(soft_reset_s2mm_dma_axi = '1') then
		if(s2mm_pkt_in_prog = '1') then
			count_rst_s2mm <= "0000";
			soft_rst_complete_axi <= '0';
		elsif(count_rst_s2mm = "1111") then
			count_rst_s2mm	<= "1111";
			soft_rst_complete_axi <= '1';
		else
			soft_rst_complete_axi <= '0';
			count_rst_s2mm <= std_logic_vector(unsigned(count_rst_s2mm(3 downto 0)) + 1);
		end if;
     end if;
end if;
end process;

--soft_rst_complete_axi <= '1' when (count_rst_s2mm = "1111") and (s2mm_pkt_in_prog = '0') else '0';
--soft_rst_complete_axi <= '1' when (count_rst_s2mm = "1111") else '0';

end generate GEN_MULTI_RST_BLOCK_S2MM;

GEN_SYNC_RESET_S2MM : if C_PRMRY_IS_ACLK_ASYNC = 0 generate
begin

s2mm_halt_cmplt_sg <= s2mm_halt_cmplt;
halt_dm_sft_rst_axi_s2mm <= halt_dm_sft_rst_s2mm;
soft_reset_s2mm_dma_axi <= soft_reset_s2mm_dma;
soft_reset_sg_s2mm_axi <= soft_reset_sg_s2mm;
soft_rst_complete_sg  <= soft_rst_complete_axi;
s2mm_ch_soft_reset_sync <= s2mm_ch_soft_reset;
update_complete_s2mm <= s2mm_updt_done;
--update_complete_s2mm <= update_complete_sg;
dma_error_s2mm_early_axi <= dma_error_s2mm_early_sg;
cur_channel_captured_s2mm <= ch_captured;
s2mm_eof_detected	<= s2mm_eof_detected_s2mm;
s2mm_eof_status_s2mm <= s2mm_eof_status;

end generate GEN_SYNC_RESET_S2MM;

