  );

SFT_RST_PRIM_CDC_PROC_S2MM : xpm_cdc_sync_rst
generic map (
  DEST_SYNC_FF   => MTBF_STAGES,
  INIT           => 1,
  INIT_SYNC_FF   => 0,
  SIM_ASSERT_CHK => 0
  )
port map (
